    // Helper function for Excel cell styling
    function styleExcelCell(cell, options = {}) {
        if (options.font) cell.font = options.font;
        if (options.fill) cell.fill = options.fill;
        if (options.border) cell.border = options.border;
        if (options.alignment) cell.alignment = options.alignment;
        if (options.numFmt) cell.numFmt = options.numFmt;
    }

    // Helper function to create Excel header row
    function createExcelHeaderRow(worksheet, rowNumber, columns, startCol = 1) {
        const row = worksheet.getRow(rowNumber);
        columns.forEach((col, index) => {
            const cell = row.getCell(startCol + index);
            cell.value = col;
            styleExcelCell(cell, {
                font: { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 },
                fill: { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF4472C4' } },
                alignment: { horizontal: 'center', vertical: 'middle', wrapText: true },
                border: {
                    top: { style: 'thin' },
                    left: { style: 'thin' },
                    bottom: { style: 'thin' },
                    right: { style: 'thin' }
                }
            });
        });
        row.height = 30; // Increased height for better text wrapping
        return row;
    }

    // Helper function to create Excel title row
    function createExcelTitle(worksheet, rowNumber, title, colSpan = 1) {
        const row = worksheet.getRow(rowNumber);
        const cell = row.getCell(1);
        cell.value = title;
        worksheet.mergeCells(rowNumber, 1, rowNumber, colSpan);
        styleExcelCell(cell, {
            font: { bold: true, size: 16, color: { argb: 'FF1F4E78' } },
            alignment: { horizontal: 'left', vertical: 'middle', wrapText: true }
        });
        row.height = 30;
        return row;
    }

    // Helper function to create Excel section header
    function createExcelSectionHeader(worksheet, rowNumber, title, colSpan = 1) {
        const row = worksheet.getRow(rowNumber);
        const cell = row.getCell(1);
        cell.value = title;
        worksheet.mergeCells(rowNumber, 1, rowNumber, colSpan);
        styleExcelCell(cell, {
            font: { bold: true, size: 12, color: { argb: 'FFFFFFFF' } },
            fill: { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF70AD47' } },
            alignment: { horizontal: 'left', vertical: 'middle', wrapText: true },
            border: {
                top: { style: 'thin' },
                left: { style: 'thin' },
                bottom: { style: 'thin' },
                right: { style: 'thin' }
            }
        });
        row.height = 22;
        return row;
    }

    // Helper function to add spacing row
    function addSpacingRow(worksheet, rowNumber) {
        const row = worksheet.getRow(rowNumber);
        row.height = 5;
        return row;
    }

    /** Rows for Excel/CSV sales report summary (matches on-screen metrics). */
    function buildSalesReportSummaryRows(stats) {
        const n = (v) => parseFloat(v || 0);
        const i = (v) => parseInt(v || 0, 10);
        return [
            { label: 'Gross Sales', value: n(stats.grossSales), currency: true },
            { label: 'Net Sales', value: n(stats.netSales), currency: true },
            { label: 'Gross Revenue', value: n(stats.grossRevenue), currency: true },
            { label: 'Net Revenue', value: n(stats.netRevenue), currency: true },
            { label: 'Total Revenue', value: n(stats.totalRevenue), currency: true },
            { label: 'Returns', value: n(stats.salesReturns), currency: true },
            { label: 'Total Discounts', value: n(stats.totalDiscounts), currency: true },
            { label: 'Total Taxes', value: n(stats.totalTaxes), currency: true },
            { label: 'Inventory Loss', value: n(stats.inventoryLoss), currency: true },
            { label: 'Delivery Revenues', value: n(stats.deliveryRevenues), currency: true },
            { label: 'Total Orders', value: i(stats.totalOrders), currency: false },
            { label: 'Total Customers', value: i(stats.totalCustomers), currency: false },
            { label: 'Average Order Value', value: n(stats.averageOrderValue), currency: true },
            { label: 'Refunded Orders', value: i(stats.refundedOrdersCount), currency: false },
            { label: 'Returned Orders', value: i(stats.returnedOrdersCount), currency: false },
            { label: 'Replacement Orders', value: i(stats.replacementOrdersCount), currency: false },
            { label: 'Return Rate', value: n(stats.returnRate), percent: true }
        ];
    }

    // Helper function to sync variation stock from InventoryProductVariations to ProductVariations (for CMS display)
    // This ensures ProductVariations.Quantity reflects InventoryProductVariations.Quantity
    async function syncInventoryVariationToProductsVariation(variationId, transaction = null) {
        // Always create a new request object to avoid parameter conflicts
        const inventoryRequest = transaction ? transaction.request() : pool.request();

        try {
            console.log(`[VARIATION SYNC] Starting sync for VariationID: ${variationId}`);

            // Find linked InventoryProductVariation via VariationID
            // Note: VariationID is shared between InventoryProductVariations and ProductVariations
                const inventoryResult = await inventoryRequest
                .input('variationId', sql.Int, variationId)
                .query(`
                    SELECT TOP 1 
                        VariationID,
                        VariationName,
                        AvailableQuantity as InventoryQuantity,
                        VariationImageURL,
                        ThumbnailURLs,
                        Model3D,
                        SKU
                    FROM InventoryProductVariations
                    WHERE VariationID = @variationId AND IsActive = 1
                `);

            console.log(`[VARIATION SYNC] InventoryProductVariations query result: ${inventoryResult.recordset.length} records found`);

            if (inventoryResult.recordset.length > 0) {
                const inventoryVariation = inventoryResult.recordset[0];
                const inventoryQuantity = inventoryVariation.InventoryQuantity || 0;

                console.log(`[VARIATION SYNC] Found InventoryProductVariation for VariationID ${variationId}, AvailableQuantity: ${inventoryQuantity}`);

                // Get current ProductVariations.Quantity before update - create new request
                const currentRequest = transaction ? transaction.request() : pool.request();
                const currentVariationResult = await currentRequest
                    .input('variationId', sql.Int, variationId)
                    .query(`
                        SELECT Quantity
                        FROM ProductVariations
                        WHERE VariationID = @variationId
                    `);

                const oldVariationQty = currentVariationResult.recordset.length > 0
                    ? (currentVariationResult.recordset[0].Quantity || 0)
                    : 0;

                console.log(`[VARIATION SYNC] Current ProductVariations.Quantity: ${oldVariationQty}, Updating to: ${inventoryQuantity} (from InventoryProductVariations.AvailableQuantity)`);

                // Update ProductVariations.Quantity to match InventoryProductVariations.Quantity - create new request
                const updateRequest = transaction ? transaction.request() : pool.request();
                const invRow = inventoryResult.recordset[0];
                let variationSku = invRow.SKU;
                if (!variationSku || !String(variationSku).trim()) {
                    variationSku = await assignVariationSku(transaction || pool, variationId, invRow.VariationName);
                }
                const updateResult = await updateRequest
                    .input('variationId', sql.Int, variationId)
                    .input('inventoryQuantity', sql.Int, inventoryQuantity)
                    .input('imageUrl', sql.NVarChar, invRow.VariationImageURL || null)
                    .input('thumbJson', sql.NVarChar, invRow.ThumbnailURLs || null)
                    .input('model3d', sql.NVarChar, invRow.Model3D || null)
                    .input('sku', sql.NVarChar, variationSku)
                    .query(`
                        UPDATE ProductVariations 
                        SET Quantity = @inventoryQuantity,
                            SKU = COALESCE(@sku, SKU),
                            VariationImageURL = COALESCE(@imageUrl, VariationImageURL),
                            ThumbnailURLs = COALESCE(@thumbJson, ThumbnailURLs),
                            Model3D = COALESCE(@model3d, Model3D),
                            UpdatedAt = GETDATE()
                        WHERE VariationID = @variationId
                    `);

                console.log(`[VARIATION SYNC] ✅ Updated ProductVariations for VariationID ${variationId} qty ${oldVariationQty} -> ${inventoryQuantity}, rows affected: ${updateResult.rowsAffected[0] || 0}`);

                // Verify the update - create new request
                const verifyRequest = transaction ? transaction.request() : pool.request();
                const verifyResult = await verifyRequest
                    .input('variationId', sql.Int, variationId)
                    .query(`
                        SELECT Quantity
                        FROM ProductVariations
                        WHERE VariationID = @variationId
                    `);

                const newVariationQty = verifyResult.recordset.length > 0
                    ? (verifyResult.recordset[0].Quantity || 0)
                    : 0;

                console.log(`[VARIATION SYNC] ✅ Verified ProductVariations.Quantity for VariationID ${variationId}: ${newVariationQty}`);

                return true;
            } else {
                // No inventory variation found, keep ProductVariations.Quantity as is
                console.log(`[VARIATION SYNC] ⚠️ No InventoryProductVariation found for VariationID ${variationId}, keeping ProductVariations.Quantity unchanged`);
                return false;
            }
        } catch (err) {
            console.error(`[VARIATION SYNC] ❌ Error syncing variation stock for VariationID ${variationId}:`, err);
            console.error(`[VARIATION SYNC] Error message:`, err.message);
            console.error(`[VARIATION SYNC] Error stack:`, err.stack);
            return false;
        }
    }

    /**
     * When an InventoryProducts row is archived from Product Inventory, mirror to CMS:
     * soft-archive all matching InventoryProductVariations, ProductVariations (shared VariationID),
     * and linked Products (via InventoryProducts.ProductID or legacy InventoryProductID = Products.ProductID).
     */
    async function cascadeArchiveCmsFromInventoryProductArchived(inventoryProductId) {
        const invId = parseInt(inventoryProductId, 10);
        if (!invId || Number.isNaN(invId)) return;

        await pool.request().input('inventoryProductId', sql.Int, invId).query(`
            UPDATE ipv SET ipv.IsActive = 0, ipv.UpdatedAt = GETDATE()
            FROM InventoryProductVariations ipv
            WHERE ipv.IsActive = 1
              AND (ipv.InventoryProductID = @inventoryProductId OR ipv.ProductID = @inventoryProductId)
        `);

        await pool.request().input('inventoryProductId', sql.Int, invId).query(`
            UPDATE pv SET pv.IsActive = 0, pv.UpdatedAt = GETDATE()
            FROM ProductVariations pv
            WHERE pv.IsActive = 1
              AND EXISTS (
                SELECT 1 FROM InventoryProductVariations ipv
                WHERE ipv.InventoryProductID = @inventoryProductId OR ipv.ProductID = @inventoryProductId
                  AND ipv.VariationID = pv.VariationID
              )
        `);

        await pool.request().input('inventoryProductId', sql.Int, invId).query(`
            UPDATE p SET p.IsActive = 0, p.UpdatedAt = GETDATE()
            FROM Products p
            WHERE p.IsActive = 1
              AND (
                EXISTS (
                    SELECT 1 FROM InventoryProducts ip
                    WHERE ip.InventoryProductID = @inventoryProductId
                      AND ip.ProductID IS NOT NULL
                      AND ip.ProductID = p.ProductID
                )
                OR EXISTS (
                    SELECT 1 FROM InventoryProducts ip
                    WHERE ip.InventoryProductID = @inventoryProductId
                      AND ip.InventoryProductID = p.ProductID
                )
              )
        `);
    }

    /**
     * Delete rows referencing Products.ProductID (FK order matches delete_all_products.sql).
     * Removes OrderItems/BulkOrderItems for this product so CMS delete can succeed.
     */
    async function deleteCmsProductDependentRows(transaction, productId) {
        const pid = parseInt(productId, 10);
        if (!pid || Number.isNaN(pid)) {
            return { orderItemsRemoved: 0, bulkItemsRemoved: 0 };
        }

        const run = () => transaction.request().input('productId', sql.Int, pid);

        const optionalTables = [
            'CartItems',
            'WishlistItems',
            'ProductDiscounts',
            'ProductReviews',
            'BulkOrderQuoteItems',
        ];
        for (const table of optionalTables) {
            try {
                await run().query(`DELETE FROM [dbo].[${table}] WHERE ProductID = @productId`);
            } catch (e) {
                if (e.number !== 208) {
                    console.log(`Skip ${table} on CMS product delete:`, e.message);
                }
            }
        }

        let bulkItemsRemoved = 0;
        let orderItemsRemoved = 0;
        try {
            const bulkRes = await run().query('DELETE FROM [dbo].[BulkOrderItems] WHERE ProductID = @productId');
            bulkItemsRemoved = bulkRes.rowsAffected?.[0] || 0;
        } catch (e) {
            if (e.number !== 208) throw e;
        }

        try {
            const orderRes = await run().query('DELETE FROM [dbo].[OrderItems] WHERE ProductID = @productId');
            orderItemsRemoved = orderRes.rowsAffected?.[0] || 0;
        } catch (e) {
            if (e.number !== 208) throw e;
        }

        await run().query('DELETE FROM [dbo].[ProductMaterials] WHERE ProductID = @productId');
        await run().query('DELETE FROM [dbo].[ProductVariations] WHERE ProductID = @productId');

        try {
            await run().query('DELETE FROM [dbo].[ProductInventory] WHERE ProductID = @productId');
        } catch (e) {
            if (e.number !== 208) {
                console.log('Skip ProductInventory on CMS product delete:', e.message);
            }
        }

        try {
            await run().query('UPDATE [dbo].[InventoryProducts] SET ProductID = NULL WHERE ProductID = @productId');
        } catch (e) {
            if (e.number !== 208) {
                console.log('Skip InventoryProducts unlink on CMS product delete:', e.message);
            }
        }

        return { orderItemsRemoved, bulkItemsRemoved };
    }

    async function permanentlyDeleteCmsProductRow(transaction, productId) {
        const stats = await deleteCmsProductDependentRows(transaction, productId);
        await transaction.request()
            .input('productId', sql.Int, parseInt(productId, 10))
            .query('DELETE FROM [dbo].[Products] WHERE ProductID = @productId');
        return stats;
    }

    function formatPermanentDeleteProductMessage(stats, entityLabel = 'Product') {
        let message = `${entityLabel} and related items permanently deleted.`;
        const orderN = stats?.orderItemsRemoved || 0;
        const bulkN = stats?.bulkItemsRemoved || 0;
        if (orderN > 0 || bulkN > 0) {
            message += ` Removed ${orderN} order line(s) and ${bulkN} bulk order line(s) that referenced this product.`;
        }
        return message;
    }

    /**
     * When a single InventoryProductVariation is archived, deactivate linked CMS ProductVariation (same VariationID).
     */
    async function cascadeArchiveCmsProductVariationFromInventoryVariationArchived(variationId) {
        const vid = parseInt(variationId, 10);
        if (!vid || Number.isNaN(vid)) return;
        await pool.request().input('variationID', sql.Int, vid).query(`
            UPDATE ProductVariations
            SET IsActive = 0, UpdatedAt = GETDATE()
            WHERE VariationID = @variationID
        `);
    }

    // Helper function to sync stock from InventoryProducts to Products (for CMS display)
    // This ensures Products.StockQuantity reflects InventoryProducts.AvailableQuantity
    async function syncInventoryToProductsStock(productId, transaction = null) {
        // Always create a new request object to avoid parameter conflicts
        const inventoryRequest = transaction ? transaction.request() : pool.request();

        try {
            console.log(`[STOCK SYNC] Starting sync for ProductID: ${productId}`);

            // Find linked InventoryProduct via ProductID
            const inventoryResult = await inventoryRequest
                .input('productId', sql.Int, productId)
                .query(`
                    SELECT TOP 1 
                        InventoryProductID,
                        AvailableQuantity
                    FROM InventoryProducts
                    WHERE ProductID = @productId AND IsActive = 1
                    ORDER BY InventoryProductID DESC
                `);

            console.log(`[STOCK SYNC] InventoryProducts query result: ${inventoryResult.recordset.length} records found`);

            if (inventoryResult.recordset.length > 0) {
                const inventoryProduct = inventoryResult.recordset[0];
                const availableQuantity = inventoryProduct.AvailableQuantity || 0;
                const inventoryProductId = inventoryProduct.InventoryProductID;

                const hasInventoryVariations = await productHasActiveInventoryVariations(inventoryProductId, transaction);
                const { productHasActiveProductVariations } = require('./utils/productVariationPolicy');
                const hasProductVariations = await productHasActiveProductVariations(pool, productId, transaction);
                const hasVariations = hasInventoryVariations || hasProductVariations;
                // Parent CMS stock is not sellable when variations exist (variations hold stock).
                const stockToSync = hasVariations ? 0 : availableQuantity;

                console.log(`[STOCK SYNC] Found InventoryProduct ${inventoryProductId} for ProductID ${productId}, AvailableQuantity: ${availableQuantity}, hasVariations: ${hasVariations}, CMS StockQuantity -> ${stockToSync}`);

                // Get current Products.StockQuantity before update - create new request
                const currentRequest = transaction ? transaction.request() : pool.request();
                const currentProductsResult = await currentRequest
                    .input('productId', sql.Int, productId)
                    .query(`
                        SELECT StockQuantity
                        FROM Products
                        WHERE ProductID = @productId
                    `);

                const oldStockQuantity = currentProductsResult.recordset.length > 0
                    ? (currentProductsResult.recordset[0].StockQuantity || 0)
                    : 0;

                console.log(`[STOCK SYNC] Current Products.StockQuantity: ${oldStockQuantity}, Updating to: ${stockToSync}`);

                // Update Products.StockQuantity - create new request
                const updateRequest = transaction ? transaction.request() : pool.request();
                const updateResult = await updateRequest
                    .input('productId', sql.Int, productId)
                    .input('availableQuantity', sql.Int, stockToSync)
                    .query(`
                        UPDATE Products 
                        SET StockQuantity = @availableQuantity,
                            UpdatedAt = GETDATE()
                        WHERE ProductID = @productId
                    `);

                console.log(`[STOCK SYNC] ✅ Updated Products.StockQuantity for ProductID ${productId} from ${oldStockQuantity} to ${stockToSync}, rows affected: ${updateResult.rowsAffected[0] || 0}`);

                // Verify the update - create new request
                const verifyRequest = transaction ? transaction.request() : pool.request();
                const verifyResult = await verifyRequest
                    .input('productId', sql.Int, productId)
                    .query(`
                        SELECT StockQuantity
                        FROM Products
                        WHERE ProductID = @productId
                    `);

                const newStockQuantity = verifyResult.recordset.length > 0
                    ? (verifyResult.recordset[0].StockQuantity || 0)
                    : 0;

                console.log(`[STOCK SYNC] ✅ Verified Products.StockQuantity for ProductID ${productId}: ${newStockQuantity}`);

                return true;
            } else {
                const { productHasActiveProductVariations } = require('./utils/productVariationPolicy');
                if (await productHasActiveProductVariations(pool, productId, transaction)) {
                    const updateRequest = transaction ? transaction.request() : pool.request();
                    await updateRequest
                        .input('productId', sql.Int, productId)
                        .query(`
                            UPDATE Products
                            SET StockQuantity = 0, UpdatedAt = GETDATE()
                            WHERE ProductID = @productId
                        `);
                    console.log(`[STOCK SYNC] No inventory link; set Products.StockQuantity=0 for ProductID ${productId} (has CMS variations)`);
                    return true;
                }
                console.log(`[STOCK SYNC] ⚠️ No linked InventoryProduct found for ProductID ${productId}, keeping Products.StockQuantity unchanged`);
                return false;
            }
        } catch (err) {
            console.error(`[STOCK SYNC] ❌ Error syncing stock for ProductID ${productId}:`, err);
            console.error(`[STOCK SYNC] Error message:`, err.message);
            console.error(`[STOCK SYNC] Error stack:`, err.stack);
            return false;
        }
    }

    async function productHasActiveInventoryVariations(inventoryProductId, transaction = null) {
        const request = transaction ? transaction.request() : pool.request();
        const result = await request
            .input('inventoryProductId', sql.Int, inventoryProductId)
            .query(`
                SELECT COUNT(*) as Cnt
                FROM InventoryProductVariations
                WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
            `);
        return (result.recordset[0]?.Cnt || 0) > 0;
    }

    /**
     * Roll up active variation status quantities into InventoryProducts
     * (product inventory tab stays in sync with product variations tab).
     */
    async function syncInventoryProductQtyFromVariations(inventoryProductId, transaction = null) {
        const hasVariations = await productHasActiveInventoryVariations(inventoryProductId, transaction);
        if (!hasVariations) {
            return null;
        }

        const sumRequest = transaction ? transaction.request() : pool.request();
        const sumResult = await sumRequest
            .input('inventoryProductId', sql.Int, inventoryProductId)
            .query(`
                SELECT
                    ISNULL(SUM(
                        CASE
                            WHEN AvailableQuantity IS NULL OR AvailableQuantity = 0
                            THEN COALESCE(Quantity, 0)
                            ELSE AvailableQuantity
                        END
                    ), 0) as AvailableQuantity,
                    ISNULL(SUM(COALESCE(DamagedQuantity, 0)), 0) as DamagedQuantity,
                    ISNULL(SUM(COALESCE(ReturnedQuantity, 0)), 0) as ReturnedQuantity,
                    ISNULL(SUM(COALESCE(RepairedQuantity, 0)), 0) as RepairedQuantity,
                    ISNULL(SUM(COALESCE(DisposedQuantity, 0)), 0) as DisposedQuantity
                FROM InventoryProductVariations
                WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
            `);

        const agg = sumResult.recordset[0] || {};
        const available = agg.AvailableQuantity || 0;
        const damaged = agg.DamagedQuantity || 0;
        const returned = agg.ReturnedQuantity || 0;
        const repaired = agg.RepairedQuantity || 0;
        const disposed = agg.DisposedQuantity || 0;

        const primaryStatus = available > 0 ? 'available' :
            repaired > 0 ? 'repaired' :
                damaged > 0 ? 'damaged' :
                    disposed > 0 ? 'disposed' : 'available';

        const updateRequest = transaction ? transaction.request() : pool.request();
        await updateRequest
            .input('inventoryProductId', sql.Int, inventoryProductId)
            .input('available', sql.Int, available)
            .input('damaged', sql.Int, damaged)
            .input('returned', sql.Int, returned)
            .input('repaired', sql.Int, repaired)
            .input('disposed', sql.Int, disposed)
            .input('status', sql.NVarChar, primaryStatus)
            .query(`
                UPDATE InventoryProducts
                SET AvailableQuantity = @available,
                    DamagedQuantity = @damaged,
                    ReturnedQuantity = @returned,
                    RepairedQuantity = @repaired,
                    DisposedQuantity = @disposed,
                    InventoryStatus = @status
                WHERE InventoryProductID = @inventoryProductId
            `);

        const linkRequest = transaction ? transaction.request() : pool.request();
        const linkResult = await linkRequest
            .input('inventoryProductId', sql.Int, inventoryProductId)
            .query(`
                SELECT ProductID FROM InventoryProducts
                WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
            `);

        const linkedProductId = linkResult.recordset[0]?.ProductID;
        if (linkedProductId) {
            await syncInventoryToProductsStock(linkedProductId, transaction);
        }

        return { available, damaged, returned, repaired, disposed, primaryStatus };
    }

    /** Split a non-negative total across slots by prior weights (or evenly if all zero). */
    function distributeQuantityAcrossSlots(total, weights) {
        const n = weights.length;
        if (n === 0) return [];
        const target = Math.max(0, parseInt(total, 10) || 0);
        if (target === 0) return weights.map(() => 0);

        const w = weights.map((x) => Math.max(0, parseInt(x, 10) || 0));
        const weightSum = w.reduce((a, b) => a + b, 0);

        let allocated;
        if (weightSum === 0) {
            const base = Math.floor(target / n);
            const remainder = target % n;
            allocated = w.map((_, i) => base + (i < remainder ? 1 : 0));
        } else {
            allocated = w.map((weight) => Math.floor((target * weight) / weightSum));
            let assigned = allocated.reduce((a, b) => a + b, 0);
            let remainder = target - assigned;
            const order = w
                .map((weight, index) => ({ weight, index }))
                .sort((a, b) => b.weight - a.weight)
                .map((x) => x.index);
            let ptr = 0;
            while (remainder > 0) {
                allocated[order[ptr % n]] += 1;
                remainder -= 1;
                ptr += 1;
            }
        }
        return allocated;
    }

    /**
     * Push InventoryProducts status quantities down to active variations (proportional split).
     */
    async function syncInventoryVariationsFromProduct(inventoryProductId, quantities, transaction = null) {
        const hasVariations = await productHasActiveInventoryVariations(inventoryProductId, transaction);
        if (!hasVariations) {
            return [];
        }

        const varRequest = transaction ? transaction.request() : pool.request();
        const variationsResult = await varRequest
            .input('inventoryProductId', sql.Int, inventoryProductId)
            .query(`
                SELECT
                    VariationID,
                    CASE
                        WHEN AvailableQuantity IS NULL OR AvailableQuantity = 0
                        THEN COALESCE(Quantity, 0)
                        ELSE AvailableQuantity
                    END as AvailableQuantity,
                    COALESCE(DamagedQuantity, 0) as DamagedQuantity,
                    COALESCE(ReturnedQuantity, 0) as ReturnedQuantity,
                    COALESCE(RepairedQuantity, 0) as RepairedQuantity,
                    COALESCE(DisposedQuantity, 0) as DisposedQuantity
                FROM InventoryProductVariations
                WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
                ORDER BY VariationID
            `);

        const variations = variationsResult.recordset || [];
        if (!variations.length) {
            return [];
        }

        const targets = {
            available: quantities.available || 0,
            damaged: quantities.damaged || 0,
            returned: quantities.returned || 0,
            repaired: quantities.repaired || 0,
            disposed: quantities.disposed || 0
        };

        const availableSplit = distributeQuantityAcrossSlots(
            targets.available,
            variations.map((v) => v.AvailableQuantity)
        );
        const damagedSplit = distributeQuantityAcrossSlots(
            targets.damaged,
            variations.map((v) => v.DamagedQuantity)
        );
        const returnedSplit = distributeQuantityAcrossSlots(
            targets.returned,
            variations.map((v) => v.ReturnedQuantity)
        );
        const repairedSplit = distributeQuantityAcrossSlots(
            targets.repaired,
            variations.map((v) => v.RepairedQuantity)
        );
        const disposedSplit = distributeQuantityAcrossSlots(
            targets.disposed,
            variations.map((v) => v.DisposedQuantity)
        );

        const updatedVariationIds = [];

        for (let i = 0; i < variations.length; i++) {
            const variationId = variations[i].VariationID;
            const available = availableSplit[i] || 0;
            const damaged = damagedSplit[i] || 0;
            const returned = returnedSplit[i] || 0;
            const repaired = repairedSplit[i] || 0;
            const disposed = disposedSplit[i] || 0;
            const totalQty = available + damaged;

            const updateReq = transaction ? transaction.request() : pool.request();
            await updateReq
                .input('variationId', sql.Int, variationId)
                .input('available', sql.Int, available)
                .input('damaged', sql.Int, damaged)
                .input('returned', sql.Int, returned)
                .input('repaired', sql.Int, repaired)
                .input('disposed', sql.Int, disposed)
                .input('totalQty', sql.Int, totalQty)
                .query(`
                    UPDATE InventoryProductVariations
                    SET AvailableQuantity = @available,
                        DamagedQuantity = @damaged,
                        ReturnedQuantity = @returned,
                        RepairedQuantity = @repaired,
                        DisposedQuantity = @disposed,
                        Quantity = @totalQty,
                        UpdatedAt = GETDATE()
                    WHERE VariationID = @variationId
                `);

            updatedVariationIds.push(variationId);
        }

        return updatedVariationIds;
    }

    // Helper function to decrement stock from both InventoryProducts and Products
    // This is the main function for ecommerce stock management
    async function decrementStockFromInventory(productId, quantity, variationId = null, transaction = null) {
        const request = transaction ? transaction.request() : pool.request();

        try {
            console.log(`[STOCK DECREMENT] Starting decrement for ProductID: ${productId}, Quantity: ${quantity}, VariationID: ${variationId || 'none'}`);

            // First, decrement from InventoryProducts if linked
            const inventoryResult = await request
                .input('productId', sql.Int, productId)
                .query(`
                    SELECT TOP 1 
                        InventoryProductID,
                        AvailableQuantity,
                        ProductID
                    FROM InventoryProducts
                    WHERE ProductID = @productId AND IsActive = 1
                    ORDER BY InventoryProductID DESC
                `);

            console.log(`[STOCK DECREMENT] InventoryProducts query result: ${inventoryResult.recordset.length} records found`);

            if (inventoryResult.recordset.length > 0) {
                const inventoryProduct = inventoryResult.recordset[0];
                const currentAvailable = inventoryProduct.AvailableQuantity || 0;
                const inventoryProductId = inventoryProduct.InventoryProductID;

                console.log(`[STOCK DECREMENT] Found InventoryProduct ${inventoryProductId} for ProductID ${productId}, Current AvailableQuantity: ${currentAvailable}`);

                if (variationId) {
                    // For variations, check InventoryProductVariations
                    console.log(`[STOCK DECREMENT] Processing variation: VariationID ${variationId}`);

                    // Create a new request for variation query to avoid parameter conflicts
                    // Create a new request for variation query to avoid parameter conflicts
                    const variationQueryRequest = transaction ? transaction.request() : pool.request();
                    const variationResult = await variationQueryRequest
                        .input('inventoryProductId', sql.Int, inventoryProductId)
                        .input('variationId', sql.Int, variationId)
                        .query(`
                            SELECT TOP 1 
                                Quantity,
                                AvailableQuantity
                            FROM InventoryProductVariations
                            WHERE InventoryProductID = @inventoryProductId 
                              AND VariationID = @variationId 
                              AND IsActive = 1
                        `);

                    console.log(`[STOCK DECREMENT] InventoryProductVariations query result: ${variationResult.recordset.length} records found`);

                    if (variationResult.recordset.length > 0) {
                        const variation = variationResult.recordset[0];
                        const currentVariationQty = variation.Quantity || 0;
                        const currentAvailableQty = variation.AvailableQuantity || 0;
                        const newVariationQty = Math.max(0, currentVariationQty - quantity);
                        const newAvailableQty = Math.max(0, currentAvailableQty - quantity);

                        console.log(`[STOCK DECREMENT] Current variation Quantity: ${currentVariationQty}, AvailableQuantity: ${currentAvailableQty}, Decrementing by: ${quantity}`);
                        console.log(`[STOCK DECREMENT] New variation Quantity: ${newVariationQty}, AvailableQuantity: ${newAvailableQty}`);

                        // Create a new request for variation update
                        const variationUpdateRequest = transaction ? transaction.request() : pool.request();
                        const variationUpdateResult = await variationUpdateRequest
                            .input('inventoryProductId', sql.Int, inventoryProductId)
                            .input('variationId', sql.Int, variationId)
                            .input('quantity', sql.Int, quantity)
                            .query(`
                                UPDATE InventoryProductVariations
                                SET Quantity = CASE WHEN Quantity >= @quantity THEN Quantity - @quantity ELSE 0 END,
                                    AvailableQuantity = CASE WHEN AvailableQuantity >= @quantity THEN AvailableQuantity - @quantity ELSE 0 END,
                                    UpdatedAt = GETDATE()
                                WHERE InventoryProductID = @inventoryProductId 
                                  AND VariationID = @variationId
                            `);

                        console.log(`[STOCK DECREMENT] ✅ Decremented ${quantity} from InventoryProductVariations (VariationID: ${variationId}), rows affected: ${variationUpdateResult.rowsAffected[0] || 0}`);

                        // Verify variation update - create new request
                        const verifyVariationRequest = transaction ? transaction.request() : pool.request();
                        const verifyVariationResult = await verifyVariationRequest
                            .input('inventoryProductId', sql.Int, inventoryProductId)
                            .input('variationId', sql.Int, variationId)
                            .query(`
                                SELECT Quantity, AvailableQuantity
                                FROM InventoryProductVariations
                                WHERE InventoryProductID = @inventoryProductId 
                                  AND VariationID = @variationId
                            `);

                        if (verifyVariationResult.recordset.length > 0) {
                            const newActualVariationQty = verifyVariationResult.recordset[0].Quantity || 0;
                            const newActualAvailableQty = verifyVariationResult.recordset[0].AvailableQuantity || 0;
                            console.log(`[STOCK DECREMENT] ✅ Verified: InventoryProductVariation (VariationID: ${variationId})`);
                            console.log(`[STOCK DECREMENT]    Quantity: ${newActualVariationQty} (was: ${currentVariationQty})`);
                            console.log(`[STOCK DECREMENT]    AvailableQuantity: ${newActualAvailableQty} (was: ${currentAvailableQty})`);
                        }

                        // NOTE: When a variation is ordered, we do NOT decrement the main product stock
                        // Only the variation stock should decrease
                        // Variations are tracked separately from the main product inventory
                        console.log(`[STOCK DECREMENT] ⚠️ Variation order - NOT decrementing main product stock (only variation stock decreases)`);

                        // Sync variation stock to ProductVariations table
                        console.log(`[STOCK DECREMENT] Syncing variation stock to ProductVariations...`);
                        await syncInventoryVariationToProductsVariation(variationId, transaction);

                        // NOTE: Do NOT sync main product stock when variation is ordered
                        // The main product stock should remain unchanged
                        console.log(`[STOCK DECREMENT] ⚠️ Variation order - NOT syncing main product stock (only variation stock is updated)`);
                    } else {
                        console.log(`[STOCK DECREMENT] ⚠️ No InventoryProductVariation found for VariationID ${variationId}, skipping variation decrement`);
                    }
                } else {
                    // Decrement main product available quantity
                    const newAvailable = Math.max(0, currentAvailable - quantity);
                    console.log(`[STOCK DECREMENT] Current AvailableQuantity: ${currentAvailable}, Decrementing by: ${quantity}, New AvailableQuantity: ${newAvailable}`);

                    const updateResult = await request
                        .input('inventoryProductId', sql.Int, inventoryProductId)
                        .input('quantity', sql.Int, quantity)
                        .query(`
                            UPDATE InventoryProducts
                            SET AvailableQuantity = CASE WHEN AvailableQuantity >= @quantity THEN AvailableQuantity - @quantity ELSE 0 END,
                                DateUpdated = GETDATE()
                            WHERE InventoryProductID = @inventoryProductId
                        `);

                    console.log(`[STOCK DECREMENT] UPDATE query executed, rows affected: ${updateResult.rowsAffected[0] || 0}`);

                    // Verify the update actually happened - create a new request to avoid parameter conflicts
                    const verifyRequest = transaction ? transaction.request() : pool.request();
                    const verifyResult = await verifyRequest
                        .input('inventoryProductId', sql.Int, inventoryProductId)
                        .query(`
                            SELECT AvailableQuantity
                            FROM InventoryProducts
                            WHERE InventoryProductID = @inventoryProductId
                        `);

                    if (verifyResult.recordset.length > 0) {
                        const newActualQty = verifyResult.recordset[0].AvailableQuantity || 0;
                        console.log(`[STOCK DECREMENT] ✅ Verified: InventoryProduct ${inventoryProductId} AvailableQuantity is now: ${newActualQty} (was: ${currentAvailable})`);
                    } else {
                        console.log(`[STOCK DECREMENT] ⚠️ WARNING: Could not verify update - InventoryProduct ${inventoryProductId} not found after update!`);
                    }

                    console.log(`[STOCK DECREMENT] ✅ Decremented ${quantity} from InventoryProducts (ProductID: ${productId}, InventoryProductID: ${inventoryProductId}), AvailableQuantity: ${currentAvailable} -> ${newAvailable}`);

                    // Sync to Products table for CMS display
                    console.log(`[STOCK DECREMENT] Syncing stock to Products table...`);
                    await syncInventoryToProductsStock(productId, transaction);
                }
            } else {
                // No inventory product linked, decrement from Products directly (fallback)
                console.log(`[STOCK DECREMENT] ⚠️ No InventoryProduct found for ProductID ${productId}, decrementing from Products directly (fallback)`);

                // Check if InventoryProduct exists but not linked (ProductID is NULL)
                const unlinkedCheck = await request
                    .input('productId', sql.Int, productId)
                    .query(`
                        SELECT TOP 1 
                            InventoryProductID,
                            AvailableQuantity,
                            ProductID
                        FROM InventoryProducts
                        WHERE ProductID IS NULL 
                          AND InventoryProductID = @productId 
                          AND IsActive = 1
                        ORDER BY InventoryProductID DESC
                    `);

                if (unlinkedCheck.recordset.length > 0) {
                    console.log(`[STOCK DECREMENT] ⚠️ Found InventoryProduct ${unlinkedCheck.recordset[0].InventoryProductID} but ProductID is NULL - not linked to CMS product!`);
                    console.log(`[STOCK DECREMENT] ⚠️ Please link the InventoryProduct to the Product first!`);
                }

                if (variationId) {
                    const fallbackResult = await request
                        .input('variationId', sql.Int, variationId)
                        .input('quantity', sql.Int, quantity)
                        .query(`
                            UPDATE ProductVariations
                            SET Quantity = CASE WHEN Quantity >= @quantity THEN Quantity - @quantity ELSE 0 END
                            WHERE VariationID = @variationId
                        `);
                    console.log(`[STOCK DECREMENT] ✅ Decremented ${quantity} from ProductVariations (VariationID: ${variationId}) directly, rows affected: ${fallbackResult.rowsAffected[0] || 0}`);
                } else {
                    const fallbackResult = await request
                        .input('productId', sql.Int, productId)
                        .input('quantity', sql.Int, quantity)
                        .query(`
                            UPDATE Products
                            SET StockQuantity = CASE WHEN StockQuantity >= @quantity THEN StockQuantity - @quantity ELSE 0 END,
                                UpdatedAt = GETDATE()
                            WHERE ProductID = @productId
                        `);
                    console.log(`[STOCK DECREMENT] ✅ Decremented ${quantity} from Products (ProductID: ${productId}) directly, rows affected: ${fallbackResult.rowsAffected[0] || 0}`);
                }
            }

            console.log(`[STOCK DECREMENT] ✅ Completed decrement for ProductID: ${productId}`);
            return true;
        } catch (err) {
            console.error(`[STOCK DECREMENT] ❌ Error decrementing stock for ProductID ${productId}:`, err);
            console.error(`[STOCK DECREMENT] Error message:`, err.message);
            console.error(`[STOCK DECREMENT] Error stack:`, err.stack);
            throw err;
        }
    }

    // Helper function to increment stock in both InventoryProducts and Products
    // isReturn=true: increments ReturnedQuantity (for actual returns)
    // isReturn=false: only increments AvailableQuantity (for cancelled orders or normal stock restoration)
    async function incrementStockToInventory(productId, quantity, variationId = null, transaction = null, isReturn = false) {
        // Always create a new request object to avoid parameter conflicts
        const inventoryRequest = transaction ? transaction.request() : pool.request();

        try {
            console.log(`[STOCK INCREMENT] Starting increment for ProductID: ${productId}, Quantity: ${quantity}, VariationID: ${variationId || 'none'}, IsReturn: ${isReturn}`);

            // First, increment InventoryProducts if linked
            const inventoryResult = await inventoryRequest
                .input('productId', sql.Int, productId)
                .query(`
                    SELECT TOP 1 
                        InventoryProductID,
                        AvailableQuantity,
                        ReturnedQuantity
                    FROM InventoryProducts
                    WHERE ProductID = @productId AND IsActive = 1
                    ORDER BY InventoryProductID DESC
                `);

            console.log(`[STOCK INCREMENT] InventoryProducts query result: ${inventoryResult.recordset.length} records found`);

            if (inventoryResult.recordset.length > 0) {
                const inventoryProduct = inventoryResult.recordset[0];
                const inventoryProductId = inventoryProduct.InventoryProductID;
                const currentAvailable = inventoryProduct.AvailableQuantity || 0;
                const currentReturned = inventoryProduct.ReturnedQuantity || 0;

                console.log(`[STOCK INCREMENT] Found InventoryProduct ${inventoryProductId} for ProductID ${productId}`);
                console.log(`[STOCK INCREMENT] Current AvailableQuantity: ${currentAvailable}, ReturnedQuantity: ${currentReturned}`);

                if (variationId) {
                    // For variations, check InventoryProductVariations
                    console.log(`[STOCK INCREMENT] Processing variation: VariationID ${variationId}`);
                    const variationQueryRequest = transaction ? transaction.request() : pool.request();
                    const variationResult = await variationQueryRequest
                        .input('inventoryProductId', sql.Int, inventoryProductId)
                        .input('variationId', sql.Int, variationId)
                        .query(`
                            SELECT TOP 1 
                                Quantity,
                                AvailableQuantity,
                                ReturnedQuantity
                            FROM InventoryProductVariations
                            WHERE InventoryProductID = @inventoryProductId 
                              AND VariationID = @variationId 
                              AND IsActive = 1
                        `);

                    console.log(`[STOCK INCREMENT] InventoryProductVariations query result: ${variationResult.recordset.length} records found`);

                    if (variationResult.recordset.length > 0) {
                        const variation = variationResult.recordset[0];
                        const currentVariationQty = variation.Quantity || 0;
                        const currentVariationAvailable = variation.AvailableQuantity || 0;
                        const currentVariationReturned = variation.ReturnedQuantity || 0;

                        console.log(`[STOCK INCREMENT] Current variation Quantity: ${currentVariationQty}, AvailableQuantity: ${currentVariationAvailable}, ReturnedQuantity: ${currentVariationReturned}`);

                        // Create new request for variation update
                        const variationUpdateRequest = transaction ? transaction.request() : pool.request();
                        if (isReturn) {
                            // When returning (cancelling order), increment ReturnedQuantity
                            await variationUpdateRequest
                                .input('inventoryProductId', sql.Int, inventoryProductId)
                                .input('variationId', sql.Int, variationId)
                                .input('quantity', sql.Int, quantity)
                                .query(`
                                    UPDATE InventoryProductVariations
                                    SET Quantity = Quantity + @quantity,
                                        AvailableQuantity = AvailableQuantity + @quantity,
                                        ReturnedQuantity = ReturnedQuantity + @quantity,
                                        UpdatedAt = GETDATE()
                                    WHERE InventoryProductID = @inventoryProductId 
                                      AND VariationID = @variationId
                                `);
                            console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to InventoryProductVariations (VariationID: ${variationId}) - Quantity, AvailableQuantity, and ReturnedQuantity`);
                        } else {
                            // Normal increment (not a return)
                            await variationUpdateRequest
                                .input('inventoryProductId', sql.Int, inventoryProductId)
                                .input('variationId', sql.Int, variationId)
                                .input('quantity', sql.Int, quantity)
                                .query(`
                                    UPDATE InventoryProductVariations
                                    SET Quantity = Quantity + @quantity,
                                        AvailableQuantity = AvailableQuantity + @quantity,
                                        UpdatedAt = GETDATE()
                                    WHERE InventoryProductID = @inventoryProductId 
                                      AND VariationID = @variationId
                                `);
                            console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to InventoryProductVariations (VariationID: ${variationId}) - Quantity and AvailableQuantity`);
                        }

                        // Sync variation stock to ProductVariations table
                        console.log(`[STOCK INCREMENT] Syncing variation stock to ProductVariations...`);
                        await syncInventoryVariationToProductsVariation(variationId, transaction);

                        // NOTE: Do NOT increment main product stock when variation is returned
                        console.log(`[STOCK INCREMENT] ⚠️ Variation return - NOT incrementing main product stock (only variation stock is restored)`);
                    } else {
                        console.log(`[STOCK INCREMENT] ⚠️ No InventoryProductVariation found for VariationID ${variationId}, skipping variation increment`);
                    }
                } else {
                    // Increment main product available quantity
                    console.log(`[STOCK INCREMENT] Current AvailableQuantity: ${currentAvailable}, Incrementing by: ${quantity}`);

                    // Create new request for main product update
                    const mainProductUpdateRequest = transaction ? transaction.request() : pool.request();
                    if (isReturn) {
                        // When returning (cancelling order), increment ReturnedQuantity
                        await mainProductUpdateRequest
                            .input('inventoryProductId', sql.Int, inventoryProductId)
                            .input('quantity', sql.Int, quantity)
                            .query(`
                                UPDATE InventoryProducts
                                SET AvailableQuantity = AvailableQuantity + @quantity,
                                    ReturnedQuantity = ReturnedQuantity + @quantity,
                                    DateUpdated = GETDATE()
                                WHERE InventoryProductID = @inventoryProductId
                            `);
                        console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to InventoryProducts (ProductID: ${productId}) - AvailableQuantity and ReturnedQuantity`);
                    } else {
                        // Normal increment (not a return)
                        await mainProductUpdateRequest
                            .input('inventoryProductId', sql.Int, inventoryProductId)
                            .input('quantity', sql.Int, quantity)
                            .query(`
                                UPDATE InventoryProducts
                                SET AvailableQuantity = AvailableQuantity + @quantity,
                                    DateUpdated = GETDATE()
                                WHERE InventoryProductID = @inventoryProductId
                            `);
                        console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to InventoryProducts (ProductID: ${productId}) - AvailableQuantity`);
                    }

                    // Sync to Products table for CMS display
                    console.log(`[STOCK INCREMENT] Syncing stock to Products table...`);
                    await syncInventoryToProductsStock(productId, transaction);
                }
            } else {
                // No inventory product linked, increment Products directly (fallback)
                console.log(`[STOCK INCREMENT] ⚠️ No InventoryProduct found for ProductID ${productId}, incrementing Products directly (fallback)`);
                const fallbackRequest = transaction ? transaction.request() : pool.request();
                if (variationId) {
                    await fallbackRequest
                        .input('variationId', sql.Int, variationId)
                        .input('quantity', sql.Int, quantity)
                        .query(`
                            UPDATE ProductVariations
                            SET Quantity = Quantity + @quantity
                            WHERE VariationID = @variationId
                        `);
                    console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to ProductVariations (VariationID: ${variationId}) directly`);
                } else {
                    await fallbackRequest
                        .input('productId', sql.Int, productId)
                        .input('quantity', sql.Int, quantity)
                        .query(`
                            UPDATE Products
                            SET StockQuantity = StockQuantity + @quantity,
                                UpdatedAt = GETDATE()
                            WHERE ProductID = @productId
                        `);
                    console.log(`[STOCK INCREMENT] ✅ Incremented ${quantity} to Products (ProductID: ${productId}) directly`);
                }
            }

            console.log(`[STOCK INCREMENT] ✅ Completed increment for ProductID: ${productId}`);
            return true;
        } catch (err) {
            console.error(`[STOCK INCREMENT] ❌ Error incrementing stock for ProductID ${productId}:`, err);
            console.error(`[STOCK INCREMENT] Error message:`, err.message);
            console.error(`[STOCK INCREMENT] Error stack:`, err.stack);
            throw err;
        }
    }

    // Helper function to create summary stats box
    function createStatsBox(worksheet, startRow, startCol, stats) {
        let currentRow = startRow;
        stats.forEach(stat => {
            const row = worksheet.getRow(currentRow++);
            row.getCell(startCol).value = stat.label;
            row.getCell(startCol).font = { bold: true };
            row.getCell(startCol + 1).value = stat.value;
            if (stat.format) {
                row.getCell(startCol + 1).numFmt = stat.format;
            }
            // Add borders
            for (let i = startCol; i <= startCol + 1; i++) {
                const cell = row.getCell(i);
                cell.border = {
                    top: { style: 'thin' },
                    left: { style: 'thin' },
                    bottom: { style: 'thin' },
                    right: { style: 'thin' }
                };
                if (i === startCol) {
                    cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF2F2F2' } };
                }
            }
        });
        return currentRow;
    }

    // Helper function to safely delete old image files
    async function deleteOldImageFile(imageUrl) {
        if (!imageUrl) return;

        try {
            // Convert URL path to file system path
            const filePath = path.join(__dirname, 'public', imageUrl);

            // Check if file exists and delete it
            if (fs.existsSync(filePath)) {
                fs.unlinkSync(filePath);
                console.log(`Deleted old image file: ${filePath}`);
            }
        } catch (error) {
            console.error(`Error deleting old image file ${imageUrl}:`, error);
            // Don't throw error - file deletion failure shouldn't break the update
        }
    }

    // Helper function to delete old thumbnail files
    async function deleteOldThumbnailFiles(thumbnailUrls) {
        if (!thumbnailUrls) return;

        try {
            const thumbnails = JSON.parse(thumbnailUrls);
            for (const thumbnailUrl of thumbnails) {
                await deleteOldImageFile(thumbnailUrl);
            }
        } catch (error) {
            console.error(`Error deleting old thumbnail files ${thumbnailUrls}:`, error);
        }
    }

    // Helper function to decrease raw materials inventory when materials are added to a product
    // Formula: quantityRequired × stockQuantity = total materials to decrease
    async function decreaseMaterialsForProduct(transaction, productId, stockQuantity, materials) {
        if (!materials || materials.length === 0 || stockQuantity <= 0) {
            console.log(`[MATERIALS] Skipping decrease - materials: ${materials?.length || 0}, stockQuantity: ${stockQuantity}`);
            return;
        }

        console.log(`[MATERIALS] Starting decrease for product ${productId} with ${materials.length} materials, stock: ${stockQuantity}`);

        for (const material of materials) {
            const materialId = parseInt(material.materialId || material.materialID || material.MaterialID, 10);
            const quantityRequired = parseInt(material.quantityRequired || material.QuantityRequired, 10) || 1;
            const totalToDecrease = quantityRequired * stockQuantity;

            if (totalToDecrease > 0 && materialId && !isNaN(materialId)) {
                // Check current available quantity
                const currentStockResult = await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .query('SELECT QuantityAvailable, Name FROM RawMaterials WHERE MaterialID = @materialId');

                if (currentStockResult.recordset.length === 0) {
                    console.error(`[MATERIALS] Material ${materialId} not found in RawMaterials`);
                    continue;
                }

                const currentAvailable = currentStockResult.recordset[0].QuantityAvailable || 0;
                const materialName = currentStockResult.recordset[0].Name || 'Unknown';

                console.log(`[MATERIALS] Material ${materialId} (${materialName}): Current available: ${currentAvailable}, Need to decrease: ${totalToDecrease}`);

                // Decrease materials (remove the WHERE clause check to allow decrease even if it goes negative)
                // This ensures materials are always decreased when assigned to products
                const updateResult = await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .input('quantity', sql.Int, totalToDecrease)
                    .query(`
                        UPDATE RawMaterials 
                        SET QuantityAvailable = QuantityAvailable - @quantity,
                            LastUpdated = GETDATE()
                        WHERE MaterialID = @materialId
                    `);

                // Verify the update
                const verifyResult = await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .query('SELECT QuantityAvailable FROM RawMaterials WHERE MaterialID = @materialId');

                const newAvailable = verifyResult.recordset[0]?.QuantityAvailable || 0;

                console.log(`[MATERIALS] ✅ Decreased ${totalToDecrease} units of material ${materialId} (${materialName}) for product ${productId}`);
                console.log(`[MATERIALS]    Old available: ${currentAvailable}, New available: ${newAvailable} (${quantityRequired} × ${stockQuantity})`);

                if (newAvailable < 0) {
                    console.warn(`[MATERIALS] ⚠️ WARNING: Material ${materialId} (${materialName}) now has negative quantity: ${newAvailable}`);
                }
            }
        }
    }

    // Helper function to restore raw materials inventory when materials are removed from a product
    async function restoreMaterialsForProduct(transaction, productId, stockQuantity, materials) {
        if (!materials || materials.length === 0 || stockQuantity <= 0) {
            console.log(`[MATERIALS] Skipping restore - materials: ${materials?.length || 0}, stockQuantity: ${stockQuantity}`);
            return;
        }

        console.log(`[MATERIALS] Starting restore for product ${productId} with ${materials.length} materials, stock: ${stockQuantity}`);

        for (const material of materials) {
            const materialId = parseInt(material.materialId || material.materialID || material.MaterialID, 10);
            const quantityRequired = parseInt(material.quantityRequired || material.QuantityRequired, 10) || 1;
            const totalToRestore = quantityRequired * stockQuantity;

            if (totalToRestore > 0 && materialId && !isNaN(materialId)) {
                // Check current available quantity before restore
                const currentStockResult = await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .query('SELECT QuantityAvailable, Name FROM RawMaterials WHERE MaterialID = @materialId');

                if (currentStockResult.recordset.length === 0) {
                    console.error(`[MATERIALS] Material ${materialId} not found in RawMaterials during restore`);
                    continue;
                }

                const currentAvailable = currentStockResult.recordset[0].QuantityAvailable || 0;
                const materialName = currentStockResult.recordset[0].Name || 'Unknown';

                console.log(`[MATERIALS] Material ${materialId} (${materialName}): Current available: ${currentAvailable}, Restoring: ${totalToRestore}`);

                // Restore materials
                await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .input('quantity', sql.Int, totalToRestore)
                    .query(`
                        UPDATE RawMaterials 
                        SET QuantityAvailable = QuantityAvailable + @quantity,
                            LastUpdated = GETDATE()
                        WHERE MaterialID = @materialId
                    `);

                // Verify the restore
                const verifyResult = await transaction.request()
                    .input('materialId', sql.Int, materialId)
                    .query('SELECT QuantityAvailable FROM RawMaterials WHERE MaterialID = @materialId');

                const newAvailable = verifyResult.recordset[0]?.QuantityAvailable || 0;

                console.log(`[MATERIALS] ✅ Restored ${totalToRestore} units of material ${materialId} (${materialName}) from product ${productId}`);
                console.log(`[MATERIALS]    Old available: ${currentAvailable}, New available: ${newAvailable} (${quantityRequired} × ${stockQuantity})`);
            }
        }
    }

    // Helper function to get product materials
    async function getProductMaterials(transaction, productId) {
        const result = await transaction.request()
            .input('productId', sql.Int, productId)
            .query(`
                SELECT MaterialID, QuantityRequired
                FROM ProductMaterials
                WHERE ProductID = @productId
            `);
        return result.recordset;
    }

    function mapMaterialRows(recordset) {
        return (recordset || []).map((row) => ({
            materialId: row.MaterialID,
            quantityRequired: row.QuantityRequired || 1
        })).filter((m) => m.materialId);
    }

    async function getInventoryProductMaterials(transaction, inventoryProductId) {
        const invId = parseInt(inventoryProductId, 10);
        if (!invId) {
            return [];
        }

        // 1) Materials defined on the inventory product
        try {
            const invMaterials = await transaction.request()
                .input('inventoryProductId', sql.Int, invId)
                .query(`
                    SELECT MaterialID, QuantityRequired
                    FROM InventoryProductMaterials
                    WHERE InventoryProductID = @inventoryProductId
                `);
            const fromInventory = mapMaterialRows(invMaterials.recordset);
            if (fromInventory.length > 0) {
                return fromInventory;
            }
        } catch (invMatErr) {
            console.log('[MATERIALS] InventoryProductMaterials:', invMatErr.message);
        }

        // 2) Linked CMS product (InventoryProducts.ProductID)
        let linkedProductId = null;
        try {
            const linkResult = await transaction.request()
                .input('inventoryProductId', sql.Int, invId)
                .query(`
                    SELECT ProductID
                    FROM InventoryProducts
                    WHERE InventoryProductID = @inventoryProductId
                `);
            linkedProductId = linkResult.recordset[0]?.ProductID || null;
        } catch (linkErr) {
            console.log('[MATERIALS] InventoryProducts link lookup:', linkErr.message);
        }

        // 3) Legacy: CMS ProductID equals inventory product id
        const productIdsToTry = [];
        if (linkedProductId) {
            productIdsToTry.push(parseInt(linkedProductId, 10));
        }
        if (!productIdsToTry.includes(invId)) {
            productIdsToTry.push(invId);
        }

        for (const productId of productIdsToTry) {
            try {
                const pmResult = await transaction.request()
                    .input('productId', sql.Int, productId)
                    .query(`
                        SELECT MaterialID, QuantityRequired
                        FROM ProductMaterials
                        WHERE ProductID = @productId
                    `);
                const fromProduct = mapMaterialRows(pmResult.recordset);
                if (fromProduct.length > 0) {
                    console.log(`[MATERIALS] Using ProductMaterials for inventory ${invId} (ProductID ${productId}), count: ${fromProduct.length}`);
                    for (const m of fromProduct) {
                        try {
                            await transaction.request()
                                .input('inventoryProductId', sql.Int, invId)
                                .input('materialId', sql.Int, m.materialId)
                                .input('quantityRequired', sql.Int, m.quantityRequired)
                                .query(`
                                    IF NOT EXISTS (
                                        SELECT 1 FROM InventoryProductMaterials
                                        WHERE InventoryProductID = @inventoryProductId AND MaterialID = @materialId
                                    )
                                    INSERT INTO InventoryProductMaterials (InventoryProductID, MaterialID, QuantityRequired)
                                    VALUES (@inventoryProductId, @materialId, @quantityRequired)
                                `);
                        } catch (persistErr) {
                            // ignore duplicate / table missing
                        }
                    }
                    return fromProduct;
                }
            } catch (pmErr) {
                console.log(`[MATERIALS] ProductMaterials ProductID ${productId}:`, pmErr.message);
            }
        }

        console.log(`[MATERIALS] No materials found for inventory product ${invId}`);
        return [];
    }

    async function saveInventoryProductMaterials(transaction, inventoryProductId, materialsData) {
        const invId = parseInt(inventoryProductId, 10);
        if (!invId || !Array.isArray(materialsData)) {
            return;
        }

        try {
            await transaction.request()
                .input('inventoryProductId', sql.Int, invId)
                .query('DELETE FROM InventoryProductMaterials WHERE InventoryProductID = @inventoryProductId');

            for (const material of materialsData) {
                const materialId = parseInt(material.materialId || material.materialID || material.MaterialID, 10);
                const quantityRequired = parseInt(material.quantityRequired || material.QuantityRequired, 10) || 1;
                if (!materialId || isNaN(materialId) || quantityRequired <= 0) {
                    continue;
                }
                await transaction.request()
                    .input('inventoryProductId', sql.Int, invId)
                    .input('materialId', sql.Int, materialId)
                    .input('quantityRequired', sql.Int, quantityRequired)
                    .query(`
                        INSERT INTO InventoryProductMaterials (InventoryProductID, MaterialID, QuantityRequired)
                        VALUES (@inventoryProductId, @materialId, @quantityRequired)
                    `);
            }
            console.log(`[MATERIALS] Saved recipe for inventory product ${invId} (${materialsData.length} row(s))`);
        } catch (saveErr) {
            console.error('[MATERIALS] saveInventoryProductMaterials error:', saveErr.message);
            throw saveErr;
        }
    }

    // Decrease or restore raw materials when inventory stock changes (restock, edit qty, create with stock)
    async function applyMaterialsDeltaForInventoryProduct(transaction, inventoryProductId, stockDelta) {
        const delta = parseInt(stockDelta, 10) || 0;
        if (delta === 0) {
            return;
        }

        const materials = await getInventoryProductMaterials(transaction, inventoryProductId);
        if (materials.length === 0) {
            console.log(`[MATERIALS] Skipping delta ${delta} — no materials for inventory product ${inventoryProductId}`);
            return;
        }

        const qty = Math.abs(delta);
        console.log(`[MATERIALS] Applying delta ${delta} (${qty} units) for inventory product ${inventoryProductId}, ${materials.length} material(s)`);
        if (delta > 0) {
            await decreaseMaterialsForProduct(transaction, inventoryProductId, qty, materials);
        } else {
            await restoreMaterialsForProduct(transaction, inventoryProductId, qty, materials);
        }
    }

    // Helper function to sync all bulk orders with their converted orders
    async function syncAllBulkOrderStatuses() {
        try {
            await pool.connect();

            // Find all bulk orders that need syncing
            // Check if OrderID column exists first
            const columnCheck = await pool.request()
                .query(`
                    SELECT COUNT(*) as columnExists
                    FROM sys.columns 
                    WHERE object_id = OBJECT_ID(N'[dbo].[BulkOrders]') 
                    AND name = 'OrderID'
                `);

            const hasOrderIDColumn = columnCheck.recordset[0].columnExists > 0;

            let bulkOrdersQuery = `
                SELECT BulkOrderID, CustomerID, GrandTotal, CreatedAt, Status
            `;

            if (hasOrderIDColumn) {
                bulkOrdersQuery += `, OrderID`;
            }

            bulkOrdersQuery += `
                FROM BulkOrders
                WHERE Status IN ('Pending', 'Processing', 'Shipping', 'Delivery', 'Received', 'Completed')
                ORDER BY CreatedAt DESC
            `;

            const bulkOrdersResult = await pool.request().query(bulkOrdersQuery);

            const totalCountResult = await pool.request().query('SELECT COUNT(*) as total FROM BulkOrders');
            const totalBulkOrders = totalCountResult.recordset[0].total;
            console.log(`[BULK ORDER SYNC] Found ${bulkOrdersResult.recordset.length} bulk orders to sync (out of ${totalBulkOrders} total bulk orders)`);

            if (totalBulkOrders === 0) {
                console.log('[BULK ORDER SYNC] WARNING: No bulk orders found in database. This might indicate bulk orders are not being saved.');
            }

            let syncedCount = 0;

            for (const bulkOrder of bulkOrdersResult.recordset) {
                let orderResult;

                if (hasOrderIDColumn && bulkOrder.OrderID) {
                    // Direct link via OrderID column
                    orderResult = await pool.request()
                        .input('orderId', sql.Int, bulkOrder.OrderID)
                        .query(`
                            SELECT OrderID, Status, OrderDate, TotalAmount
                            FROM Orders
                            WHERE OrderID = @orderId
                        `);
                } else {
                    // Fall back to matching by customer, amount, and date
                    orderResult = await pool.request()
                        .input('customerId', sql.Int, bulkOrder.CustomerID)
                        .input('totalAmount', sql.Decimal(10, 2), bulkOrder.GrandTotal)
                        .input('bulkOrderDate', sql.DateTime, bulkOrder.CreatedAt)
                        .query(`
                            SELECT TOP 1 OrderID, Status, OrderDate, TotalAmount
                            FROM Orders
                            WHERE CustomerID = @customerId
                              AND ABS(TotalAmount - @totalAmount) < 0.01
                              AND OrderDate >= @bulkOrderDate
                              AND OrderDate <= DATEADD(DAY, 1, @bulkOrderDate)
                              AND DeliveryType = 'pickup'
                            ORDER BY OrderDate ASC
                        `);
                }

                if (orderResult.recordset.length > 0) {
                    const order = orderResult.recordset[0];

                    // Map order status to bulk order status
                    // Bulk order status should match where the order is (Pending, Processing, Shipping, Delivery, Received)
                    let bulkOrderStatus = order.Status; // Default: use order status directly

                    // Map order statuses to bulk order statuses
                    if (order.Status === 'Pending') {
                        bulkOrderStatus = 'Pending';
                    } else if (order.Status === 'Processing') {
                        bulkOrderStatus = 'Processing';
                    } else if (order.Status === 'Shipping') {
                        bulkOrderStatus = 'Shipping';
                    } else if (order.Status === 'Delivery') {
                        bulkOrderStatus = 'Delivery';
                    } else if (order.Status === 'Received') {
                        bulkOrderStatus = 'Received';
                    } else if (order.Status === 'Completed') {
                        bulkOrderStatus = 'Completed';
                    } else if (order.Status === 'Cancelled') {
                        bulkOrderStatus = 'Cancelled';
                    } else {
                        // For any other status, default to Processing
                        bulkOrderStatus = 'Processing';
                    }

                    // Only update if status changed
                    if (bulkOrderStatus !== bulkOrder.Status) {
                        await pool.request()
                            .input('bulkOrderId', sql.Int, bulkOrder.BulkOrderID)
                            .input('status', sql.NVarChar, bulkOrderStatus)
                            .query('UPDATE BulkOrders SET Status = @status, UpdatedAt = GETDATE() WHERE BulkOrderID = @bulkOrderId');

                        console.log(`[BULK ORDER SYNC] Synced bulk order ${bulkOrder.BulkOrderID} from ${bulkOrder.Status} to ${bulkOrderStatus} based on order ${order.OrderID} status ${order.Status}`);
                        syncedCount++;
                    } else {
                        console.log(`[BULK ORDER SYNC] Bulk order ${bulkOrder.BulkOrderID} already has correct status ${bulkOrder.Status} (order ${order.OrderID} is ${order.Status})`);
                    }
                } else {
                    console.log(`[BULK ORDER SYNC] No matching order found for bulk order ${bulkOrder.BulkOrderID} (Customer: ${bulkOrder.CustomerID}, Amount: ${bulkOrder.GrandTotal})`);
                }
            }

            console.log(`[BULK ORDER SYNC] Synced ${syncedCount} bulk orders`);
            return syncedCount;
        } catch (err) {
            console.error('Error syncing bulk order statuses:', err);
            return 0;
        }
    }

    // Helper function to update bulk order status when order status changes
    async function updateBulkOrderStatus(orderId, newStatus) {
        try {
            // First, try to find bulk order by direct OrderID link (if column exists)
            const columnCheck = await pool.request()
                .query(`
                    SELECT COUNT(*) as columnExists
                    FROM sys.columns 
                    WHERE object_id = OBJECT_ID(N'[dbo].[BulkOrders]') 
                    AND name = 'OrderID'
                `);

            const hasOrderIDColumn = columnCheck.recordset[0].columnExists > 0;

            let bulkOrderResult;

            if (hasOrderIDColumn) {
                // Direct link via OrderID column
                bulkOrderResult = await pool.request()
                    .input('orderId', sql.Int, orderId)
                    .query(`
                        SELECT TOP 1 BulkOrderID, Status
                        FROM BulkOrders
                        WHERE OrderID = @orderId
                          AND Status IN ('Pending', 'Processing', 'Shipping', 'Delivery', 'Received', 'Completed')
                    `);
            }

            // If no direct link found, fall back to matching by customer, amount, and date
            if (!hasOrderIDColumn || bulkOrderResult.recordset.length === 0) {
                const orderResult = await pool.request()
                    .input('orderId', sql.Int, orderId)
                    .query(`
                        SELECT o.CustomerID, o.TotalAmount, o.OrderDate, o.Status
                        FROM Orders o
                        WHERE o.OrderID = @orderId
                    `);

                if (orderResult.recordset.length === 0) return;

                const order = orderResult.recordset[0];

                // Find matching bulk order
                // Match by customer, grand total, and created within 24 hours before order date (more flexible)
                bulkOrderResult = await pool.request()
                    .input('customerId', sql.Int, order.CustomerID)
                    .input('totalAmount', sql.Decimal(10, 2), order.TotalAmount)
                    .input('orderDate', sql.DateTime, order.OrderDate)
                    .query(`
                        SELECT TOP 1 BulkOrderID, Status
                        FROM BulkOrders
                        WHERE CustomerID = @customerId
                          AND ABS(GrandTotal - @totalAmount) < 0.01
                          AND CreatedAt <= @orderDate
                          AND CreatedAt >= DATEADD(DAY, -1, @orderDate)
                          AND Status IN ('Pending', 'Processing', 'Shipping', 'Delivery', 'Received', 'Completed')
                        ORDER BY CreatedAt DESC
                    `);
            }

            if (bulkOrderResult.recordset.length > 0) {
                const bulkOrder = bulkOrderResult.recordset[0];

                // Map order status to bulk order status
                // Bulk order status should match where the order is (Pending, Processing, Shipping, Delivery, Received)
                let bulkOrderStatus = newStatus; // Default: use order status directly

                // Map order statuses to bulk order statuses
                if (newStatus === 'Pending') {
                    bulkOrderStatus = 'Pending';
                } else if (newStatus === 'Processing') {
                    bulkOrderStatus = 'Processing';
                } else if (newStatus === 'Shipping') {
                    bulkOrderStatus = 'Shipping';
                } else if (newStatus === 'Delivery') {
                    bulkOrderStatus = 'Delivery';
                } else if (newStatus === 'Received') {
                    bulkOrderStatus = 'Received';
                } else if (newStatus === 'Completed') {
                    bulkOrderStatus = 'Completed';
                } else if (newStatus === 'Cancelled') {
                    bulkOrderStatus = 'Cancelled';
                } else {
                    // For any other status, default to Processing
                    bulkOrderStatus = 'Processing';
                }

                // Update bulk order status
                await pool.request()
                    .input('bulkOrderId', sql.Int, bulkOrder.BulkOrderID)
                    .input('status', sql.NVarChar, bulkOrderStatus)
                    .query('UPDATE BulkOrders SET Status = @status, UpdatedAt = GETDATE() WHERE BulkOrderID = @bulkOrderId');

                console.log(`[BULK ORDER SYNC] Updated bulk order ${bulkOrder.BulkOrderID} status to ${bulkOrderStatus} based on order ${orderId} status ${newStatus}`);
            }
        } catch (err) {
            // Don't fail the order update if bulk order sync fails
            console.error('Error updating bulk order status:', err);
        }
    }

    // Helper function to safely delete a customer and all related data
    async function deleteCustomerSafely(customerId, transaction) {
        // First, set ShippingAddressID to NULL in orders to break foreign key references
        await transaction.request()
            .input('customerId', sql.Int, customerId)
            .query('UPDATE Orders SET ShippingAddressID = NULL WHERE CustomerID = @customerId');

        // Delete order items first (they reference orders)
        await transaction.request()
            .input('customerId', sql.Int, customerId)
            .query(`
                DELETE FROM OrderItems 
                WHERE OrderID IN (
                    SELECT OrderID FROM Orders WHERE CustomerID = @customerId
                )
            `);

        // Delete customer orders (now safe since order items are deleted)
        await transaction.request()
            .input('customerId', sql.Int, customerId)
            .query('DELETE FROM Orders WHERE CustomerID = @customerId');

        // Delete customer addresses
        await transaction.request()
            .input('customerId', sql.Int, customerId)
            .query('DELETE FROM CustomerAddresses WHERE CustomerID = @customerId');

        // Delete customer cart items (if table exists)
        try {
            await transaction.request()
                .input('customerId', sql.Int, customerId)
                .query('DELETE FROM CartItems WHERE CustomerID = @customerId');
        } catch (error) {
            // Table doesn't exist, continue
            console.log('CartItems table not found, skipping...');
        }

        // Delete customer wishlist items (if table exists)
        try {
            await transaction.request()
                .input('customerId', sql.Int, customerId)
                .query('DELETE FROM WishlistItems WHERE CustomerID = @customerId');
        } catch (error) {
            // Table doesn't exist, continue
            console.log('WishlistItems table not found, skipping...');
        }

        // Delete customer reviews (if table exists)
        try {
            await transaction.request()
                .input('customerId', sql.Int, customerId)
                .query('DELETE FROM ProductReviews WHERE CustomerID = @customerId');
        } catch (error) {
            // Table doesn't exist, continue
            console.log('ProductReviews table not found, skipping...');
        }

        // Delete OTP records (if table exists)
        try {
            await transaction.request()
                .input('customerId', sql.Int, customerId)
                .query('DELETE FROM CustomerDeleteOTP WHERE CustomerID = @customerId');
        } catch (error) {
            // Table doesn't exist, continue
            console.log('CustomerDeleteOTP table not found, skipping...');
        }

        // Finally, delete the customer account
        await transaction.request()
            .input('customerId', sql.Int, customerId)
            .query('DELETE FROM Customers WHERE CustomerID = @customerId');
    }

    // =============================================================================
    // FILE UPLOAD CONFIGURATION
    // =============================================================================

    // Configure multer for file uploads (hero banners) – Azure-aware
    const heroBannerStorageEngine = isAzureBlobConfigured()
        ? {
            _handleFile: async (req, file, cb) => {
                try {
                    const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
                    const ext = path.extname(file.originalname) || '.jpg';
                    const blobPath = `hero-banners/${file.fieldname}-${uniqueSuffix}${ext}`;
                    const chunks = [];
                    file.stream.on('data', (c) => chunks.push(c));
                    file.stream.on('error', cb);
                    file.stream.on('end', async () => {
                        try {
                            const buffer = Buffer.concat(chunks);
                            const url = await uploadBufferToAzureBlob(blobPath, buffer, file.mimetype);
                            cb(null, { filename: blobPath, destination: 'azure-blob', size: buffer.length, path: blobPath, azureUrl: url });
                        } catch (e) { cb(e); }
                    });
                } catch (e) { cb(e); }
            },
            _removeFile: (req, file, cb) => cb(null)
        }
        : multer.diskStorage({
            destination: function (req, file, cb) {
                const uploadDir = path.join(__dirname, 'public', 'uploads');
                const heroBannersDir = path.join(uploadDir, 'hero-banners');
                if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir, { recursive: true });
                if (!fs.existsSync(heroBannersDir)) fs.mkdirSync(heroBannersDir, { recursive: true });
                cb(null, heroBannersDir);
            },
            filename: function (req, file, cb) {
                const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
                cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
            }
        });

    const upload = multer({
        storage: heroBannerStorageEngine,
        limits: { fileSize: 10 * 1024 * 1024 },
        fileFilter: function (req, file, cb) {
            if (file.mimetype.startsWith('image/')) { cb(null, true); }
            else { cb(new Error('Only image files are allowed!'), false); }
        }
    });

    // Configure multer for testimonials uploads
    const testimonialsStorage = multer.diskStorage({
        destination: function (req, file, cb) {
            const uploadDir = path.join(__dirname, 'public', 'uploads');
            const testimonialsDir = path.join(uploadDir, 'testimonials');

            // Ensure directory exists
            if (!fs.existsSync(uploadDir)) {
                fs.mkdirSync(uploadDir, { recursive: true });
            }
            if (!fs.existsSync(testimonialsDir)) {
                fs.mkdirSync(testimonialsDir, { recursive: true });
            }

            cb(null, testimonialsDir);
        },
        filename: function (req, file, cb) {
            const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
            cb(null, 'testimonial-' + uniqueSuffix + path.extname(file.originalname));
        }
    });

    const testimonialsUpload = multer({
        storage: testimonialsStorage,
        limits: {
            fileSize: 10 * 1024 * 1024 // 10MB limit
        },
        fileFilter: function (req, file, cb) {
            if (file.mimetype.startsWith('image/')) {
                cb(null, true);
            } else {
                cb(new Error('Only image files are allowed!'), false);
            }
        }
    });

    // Configure multer for product uploads
    // If Azure Blob is configured, files are uploaded directly to blob storage.
    const getProductSubdirectory = (fieldname = '') => {
        if (fieldname === 'image') return 'images';
        if (fieldname === 'thumbnails') return 'thumbnails';
        if (fieldname.startsWith('thumbnail')) return 'thumbnails';
        if (fieldname === 'model3d') return 'models';
        if (fieldname === 'inventoryImage' || fieldname === 'productImage') return 'inventory';
        if (fieldname === 'variationImage' || fieldname === 'variationMainImage') return 'variations';
        if (fieldname === 'variationModel3d') return 'models';
        if (fieldname === 'variationThumbnail') return 'thumbnails';
        return '';
    };

    const sanitizeFileName = (name = 'file') => {
        return String(name).replace(/[^a-zA-Z0-9._-]/g, '_');
    };

    const productStorage = isAzureProductAssetMode()
        ? {
            _handleFile: async (req, file, cb) => {
                try {
                    const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
                    const safeOriginalName = sanitizeFileName(file.originalname || 'upload.bin');
                    const finalName = `${uniqueSuffix}-${safeOriginalName}`;
                    const subdirectory = getProductSubdirectory(file.fieldname);
                    const blobPath = (file.fieldname === 'variationImage' || file.fieldname === 'variationMainImage')
                        ? `variations/${finalName}`
                        : file.fieldname === 'variationModel3d'
                            ? `products/models/${finalName}`
                            : file.fieldname === 'variationThumbnail'
                                ? `products/thumbnails/${finalName}`
                                : (subdirectory
                            ? `products/${subdirectory}/${finalName}`
                            : `products/${finalName}`);

                    const chunks = [];
                    file.stream.on('data', (chunk) => chunks.push(chunk));
                    file.stream.on('error', (error) => cb(error));
                    file.stream.on('end', async () => {
                        try {
                            const buffer = Buffer.concat(chunks);
                            await uploadBufferToAzureBlob(blobPath, buffer, file.mimetype);

                            // Backward compatibility for legacy routes that save `/uploads/products/<filename>`
                            if (file.fieldname === 'image') {
                                await uploadBufferToAzureBlob(`products/${finalName}`, buffer, file.mimetype);
                            }

                            cb(null, {
                                filename: finalName,
                                destination: 'azure-blob',
                                size: buffer.length,
                                path: blobPath
                            });
                        } catch (uploadError) {
                            cb(uploadError);
                        }
                    });
                } catch (error) {
                    cb(error);
                }
            },
            _removeFile: (req, file, cb) => cb(null)
        }
        : multer.diskStorage({
            destination: function (req, file, cb) {
                let dest;
                if (file.fieldname === 'image') {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'images');
                } else if (file.fieldname.startsWith('thumbnail')) {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'thumbnails');
                } else if (file.fieldname === 'model3d') {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'models');
                } else if (file.fieldname === 'inventoryImage' || file.fieldname === 'productImage') {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'inventory');
                } else if (file.fieldname === 'variationImage' || file.fieldname === 'variationMainImage') {
                    dest = path.join(__dirname, 'public', 'uploads', 'variations');
                } else if (file.fieldname === 'variationModel3d') {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'models');
                } else if (file.fieldname === 'variationThumbnail') {
                    dest = path.join(__dirname, 'public', 'uploads', 'products', 'thumbnails');
                } else {
                    dest = path.join(__dirname, 'public', 'uploads', 'products');
                }

                if (!fs.existsSync(dest)) {
                    fs.mkdirSync(dest, { recursive: true });
                }
                cb(null, dest);
            },
            filename: function (req, file, cb) {
                const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
                cb(null, uniqueSuffix + '-' + file.originalname);
            }
        });

    const productUpload = multer({
        storage: productStorage,
        limits: {
            fileSize: function (req, file) {
                // 30MB limit for 3D models, 10MB for other files
                if (file.fieldname === 'model3d' || file.fieldname === 'variationModel3d') {
                    return 30 * 1024 * 1024; // 30MB for 3D models
                }
                return 10 * 1024 * 1024; // 10MB for images and other files
            }
        },
        fileFilter: function (req, file, cb) {
            if (file.fieldname === 'model3d' || file.fieldname === 'variationModel3d') {
                // Allow GLB and GLTF files for 3D models
                if (file.mimetype === 'model/gltf-binary' || file.mimetype === 'model/gltf+json' ||
                    file.originalname.toLowerCase().endsWith('.glb') || file.originalname.toLowerCase().endsWith('.gltf')) {
                    cb(null, true);
                } else {
                    cb(new Error('Only GLB and GLTF files are allowed for 3D models!'), false);
                }
            } else if (file.fieldname === 'variationMainImage' || file.fieldname === 'variationThumbnail' || file.mimetype.startsWith('image/')) {
                cb(null, true);
            } else {
                cb(new Error('Only image files are allowed!'), false);
            }
        }
    });

    // Configure multer for variation uploads (Azure Blob in production when configured)
    const variationStorageEngine = isAzureProductAssetMode()
        ? {
            _handleFile: async (req, file, cb) => {
                try {
                    const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
                    const ext = path.extname(file.originalname) || '.jpg';
                    const blobPath = `variations/variation-${uniqueSuffix}${ext}`;
                    const chunks = [];
                    file.stream.on('data', (c) => chunks.push(c));
                    file.stream.on('error', cb);
                    file.stream.on('end', async () => {
                        try {
                            const buffer = Buffer.concat(chunks);
                            const url = await uploadBufferToAzureBlob(blobPath, buffer, file.mimetype);
                            cb(null, {
                                filename: `variation-${uniqueSuffix}${ext}`,
                                destination: 'azure-blob',
                                size: buffer.length,
                                path: blobPath,
                                azureUrl: url
                            });
                        } catch (e) {
                            cb(e);
                        }
                    });
                } catch (e) {
                    cb(e);
                }
            },
            _removeFile: (req, file, cb) => cb(null)
        }
        : multer.diskStorage({
            destination: function (req, file, cb) {
                const uploadDir = path.join(__dirname, 'public', 'uploads');
                const variationsDir = path.join(uploadDir, 'variations');
                if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir, { recursive: true });
                if (!fs.existsSync(variationsDir)) fs.mkdirSync(variationsDir, { recursive: true });
                cb(null, variationsDir);
            },
            filename: function (req, file, cb) {
                const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
                cb(null, 'variation-' + uniqueSuffix + path.extname(file.originalname));
            }
        });

    const variationUpload = multer({
        storage: variationStorageEngine,
        limits: {
            fileSize: 10 * 1024 * 1024 // 10MB limit
        },
        fileFilter: function (req, file, cb) {
            if (file.mimetype.startsWith('image/')) {
                cb(null, true);
            } else {
                cb(new Error('Only image files are allowed!'), false);
            }
        }
    });

    // Configure multer for return uploads (images and videos)
    const returnStorage = multer.diskStorage({
        destination: function (req, file, cb) {
            const uploadDir = path.join(__dirname, 'public', 'uploads');
            const returnsDir = path.join(uploadDir, 'returns');

            // Ensure directory exists
            if (!fs.existsSync(uploadDir)) {
                fs.mkdirSync(uploadDir, { recursive: true });
            }
            if (!fs.existsSync(returnsDir)) {
                fs.mkdirSync(returnsDir, { recursive: true });
            }

            cb(null, returnsDir);
        },
        filename: function (req, file, cb) {
            const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
            cb(null, 'return-' + uniqueSuffix + path.extname(file.originalname));
        }
    });

    const returnUpload = multer({
        storage: returnStorage,
        limits: {
            fileSize: 50 * 1024 * 1024 // 50MB limit for videos
        },
        fileFilter: function (req, file, cb) {
            // Allow images and videos
            if (file.mimetype.startsWith('image/') || file.mimetype.startsWith('video/')) {
                cb(null, true);
            } else {
                cb(new Error('Only image and video files are allowed!'), false);
            }
        }
    });

