    async function ensureCustomerGoogleAuthColumns() {
        try {
            await pool.connect();
            const columns = [
                { name: 'GoogleSub', type: 'NVARCHAR(255)' },
                { name: 'AuthProvider', type: 'NVARCHAR(32)' }
            ];
            for (const col of columns) {
                const check = await pool.request().query(`
                    SELECT COUNT(*) AS cnt
                    FROM INFORMATION_SCHEMA.COLUMNS
                    WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = 'Customers' AND COLUMN_NAME = '${col.name}'
                `);
                if (check.recordset[0].cnt === 0) {
                    await pool.request().query(`ALTER TABLE dbo.Customers ADD ${col.name} ${col.type} NULL`);
                }
            }

            const pwdCol = await pool.request().query(`
                SELECT COUNT(*) AS cnt
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = 'Customers' AND COLUMN_NAME = 'PasswordSetupCompleted'
            `);
            if (pwdCol.recordset[0].cnt === 0) {
                await pool.request().query(`
                    ALTER TABLE dbo.Customers ADD PasswordSetupCompleted BIT NOT NULL
                    CONSTRAINT DF_Customers_PasswordSetupCompleted DEFAULT 1
                `);
                await pool.request().query(`
                    UPDATE dbo.Customers SET PasswordSetupCompleted = 0 WHERE GoogleSub IS NOT NULL
                `);
            }
        } catch (e) {
            console.error('[GOOGLE AUTH] ensureCustomerGoogleAuthColumns:', e.message);
        }
    }

    /** True when customer must set a local password (e.g. after Google signup). */
    function customerRequiresPasswordSetup(row) {
        if (!row) return false;
        const v = row.PasswordSetupCompleted;
        if (v === undefined || v === null) return false;
        return v === false || v === 0;
    }

    function buildGoogleCustomerCallbackUrl() {
        if (process.env.GOOGLE_CALLBACK_URL) {
            return process.env.GOOGLE_CALLBACK_URL;
        }
        const port = process.env.PORT || 5000;
        const base = (process.env.PUBLIC_API_URL || process.env.BACKEND_PUBLIC_URL || `http://localhost:${port}`).replace(/\/$/, '');
        return `${base}/api/auth/google/callback`;
    }

    if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
        passport.use('google-customer', new GoogleStrategy({
            clientID: process.env.GOOGLE_CLIENT_ID,
            clientSecret: process.env.GOOGLE_CLIENT_SECRET,
            callbackURL: buildGoogleCustomerCallbackUrl(),
            passReqToCallback: true
        }, async (req, accessToken, refreshToken, profile, done) => {
            try {
                await ensureCustomerGoogleAuthColumns();
                await pool.connect();

                const googleSub = String(profile.id || '');
                const emailRaw = profile.emails && profile.emails[0] && profile.emails[0].value;
                const email = String(emailRaw || '').trim().toLowerCase();
                const displayName = profile.displayName
                    || (profile.name && [profile.name.givenName, profile.name.familyName].filter(Boolean).join(' '))
                    || 'Customer';

                if (!email || !googleSub) {
                    return done(null, false);
                }

                let bySub = await pool.request()
                    .input('sub', sql.NVarChar(255), googleSub)
                    .query(`
                        SELECT TOP 1 CustomerID, Email, FullName, PhoneNumber, IsActive, ProfileImage, GoogleSub, AuthProvider, PasswordSetupCompleted
                        FROM Customers
                        WHERE GoogleSub = @sub
                    `);

                let customer = bySub.recordset[0];

                if (!customer) {
                    const byEmail = await pool.request()
                        .input('email', sql.NVarChar(255), email)
                        .query(`
                            SELECT TOP 1 CustomerID, Email, FullName, PhoneNumber, IsActive, ProfileImage, GoogleSub, AuthProvider, PasswordSetupCompleted
                            FROM Customers
                            WHERE Email = @email
                        `);
                    customer = byEmail.recordset[0];
                }

                if (customer) {
                    if (!customer.IsActive) {
                        return done(null, false);
                    }
                    if (customer.GoogleSub && String(customer.GoogleSub) !== googleSub) {
                        return done(null, false);
                    }
                    if (!customer.GoogleSub) {
                        await pool.request()
                            .input('sub', sql.NVarChar(255), googleSub)
                            .input('id', sql.Int, customer.CustomerID)
                            .query(`
                                UPDATE Customers
                                SET GoogleSub = @sub, AuthProvider = 'google'
                                WHERE CustomerID = @id
                            `);
                    }
                    await pool.request()
                        .input('id', sql.Int, customer.CustomerID)
                        .query('UPDATE Customers SET LastLogin = GETDATE() WHERE CustomerID = @id');

                    const customerData = {
                        id: customer.CustomerID,
                        fullName: customer.FullName || displayName,
                        email: customer.Email,
                        phoneNumber: customer.PhoneNumber,
                        role: 'Customer',
                        type: 'customer',
                        profileImage: customer.ProfileImage || null,
                        requiresPasswordSetup: customerRequiresPasswordSetup(customer)
                    };
                    return done(null, customerData);
                }

                try {
                    const insertResult = await pool.request()
                        .input('fullName', sql.NVarChar(255), displayName)
                        .input('email', sql.NVarChar(255), email)
                        .input('sub', sql.NVarChar(255), googleSub)
                        .query(`
                            INSERT INTO Customers (FullName, Email, PhoneNumber, PasswordHash, IsActive, CreatedAt, GoogleSub, AuthProvider, PasswordSetupCompleted)
                            OUTPUT INSERTED.CustomerID, INSERTED.FullName, INSERTED.Email, INSERTED.PhoneNumber, INSERTED.ProfileImage
                            VALUES (@fullName, @email, NULL, NULL, 1, GETDATE(), @sub, 'google', 0)
                        `);
                    const row = insertResult.recordset[0];
                    const customerData = {
                        id: row.CustomerID,
                        fullName: row.FullName || displayName,
                        email: row.Email,
                        phoneNumber: row.PhoneNumber,
                        role: 'Customer',
                        type: 'customer',
                        profileImage: row.ProfileImage || null,
                        requiresPasswordSetup: true
                    };
                    return done(null, customerData);
                } catch (insertErr) {
                    const randomHash = await bcrypt.hash(crypto.randomBytes(32).toString('hex'), 12);
                    const insertResult = await pool.request()
                        .input('fullName', sql.NVarChar(255), displayName)
                        .input('email', sql.NVarChar(255), email)
                        .input('sub', sql.NVarChar(255), googleSub)
                        .input('passwordHash', sql.NVarChar(255), randomHash)
                        .query(`
                            INSERT INTO Customers (FullName, Email, PhoneNumber, PasswordHash, IsActive, CreatedAt, GoogleSub, AuthProvider, PasswordSetupCompleted)
                            OUTPUT INSERTED.CustomerID, INSERTED.FullName, INSERTED.Email, INSERTED.PhoneNumber, INSERTED.ProfileImage
                            VALUES (@fullName, @email, NULL, @passwordHash, 1, GETDATE(), @sub, 'google', 0)
                        `);
                    const row = insertResult.recordset[0];
                    const customerData = {
                        id: row.CustomerID,
                        fullName: row.FullName || displayName,
                        email: row.Email,
                        phoneNumber: row.PhoneNumber,
                        role: 'Customer',
                        type: 'customer',
                        profileImage: row.ProfileImage || null,
                        requiresPasswordSetup: true
                    };
                    return done(null, customerData);
                }
            } catch (err) {
                console.error('[GOOGLE AUTH] Strategy error:', err);
                return done(err);
            }
        }));
    } else if (process.env.NODE_ENV === 'development') {
        console.log('[GOOGLE AUTH] GOOGLE_CLIENT_ID / GOOGLE_CLIENT_SECRET not set — Google Sign-In disabled.');
    }


    /**
     * Enhanced middleware to check if user is logged in (supports both session and JWT)
     */
    function isAuthenticated(req, res, next) {
        if (process.env.NODE_ENV === 'development' || process.env.DEBUG_AUTH === 'true') {
            console.log('=== AUTHENTICATION CHECK ===', req.method, req.url);
        }

        // Check session-based authentication first
        if (req.session && req.session.user) {
            return next();
        }

        // Check JWT authentication for API requests
        const authHeader = req.headers.authorization;
        if (authHeader && authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            try {
                const decoded = jwtUtils.verifyToken(token);
                // Set user data from JWT
                req.session = req.session || {};
                req.session.user = {
                    id: decoded.id,
                    email: decoded.email,
                    role: decoded.role,
                    type: decoded.type,
                    fullName: decoded.fullName
                };
                return next();
            } catch (error) {
                if (process.env.NODE_ENV === 'development') {
                    console.log('JWT Authentication failed:', error.message);
                }
                // Fall through to check legacy tokens
            }
        }

        // Legacy token validation removed - using JWT only

        // Check if this is an AJAX/API request
        const isAjaxRequest = req.xhr ||
            (req.headers.accept && req.headers.accept.indexOf('json') > -1) ||
            (req.headers['content-type'] && req.headers['content-type'].indexOf('json') > -1) ||
            req.path.startsWith('/api/');

        if (isAjaxRequest) {
            return res.status(401).json({
                success: false,
                message: 'Authentication required. Please log in.',
                requiresLogin: true,
                code: 'AUTHENTICATION_REQUIRED'
            });
        }

        req.flash('error', 'Please log in to access this page.');
        res.redirect('/login');
    }

    // Legacy token validation removed - using JWT validation only


    /**
     * EMPLOYEE ACCESS SYSTEM: All employee roles have access
     */
    function hasEmployeeAccess(req, res, next) {
        if (!req.session || !req.session.user) {
            return redirectToLogin(req, res, 'Authentication required.');
        }

        const userRole = req.session.user.role;

        // Define allowed employee roles
        const allowedRoles = [
            'Admin',
            'TransactionManager',
            'InventoryManager',
            'UserManager',
            'OrderSupport',
            'Employee'
        ];

        // Check if user has an allowed role
        if (allowedRoles.includes(userRole)) {
            return next();
        }

        // Non-employee users are denied access
        return handleAccessDenied(req, res, userRole);
    }

    /**
     * Simple access denied handler for non-admin users
     */

    /**
     * Handle access denied scenarios for non-employee users
     */
    function handleAccessDenied(req, res, userRole) {
        const isAjaxRequest = req.xhr ||
            (req.headers.accept && req.headers.accept.indexOf('json') > -1) ||
            req.path.startsWith('/api/');

        if (isAjaxRequest) {
            return res.status(403).json({
                success: false,
                message: 'Access denied. Employee access required.',
                code: 'EMPLOYEE_ACCESS_REQUIRED'
            });
        }

        // Redirect non-employee users to login with error message
        req.flash('error', 'Employee access required. Please log in with an employee account.');
        res.redirect('/login');
    }

    /**
     * Helper function to redirect to login
     */
    function redirectToLogin(req, res, message) {
        const isAjaxRequest = req.xhr ||
            (req.headers.accept && req.headers.accept.indexOf('json') > -1) ||
            req.path.startsWith('/api/');

        if (isAjaxRequest) {
            return res.status(401).json({
                success: false,
                message: message,
                requiresLogin: true,
                code: 'AUTHENTICATION_REQUIRED'
            });
        }

        req.flash('error', message);
        res.redirect('/login');
    }

