    // Inventory Manager - Product Inventory (InventoryProducts table)
    router.get('/Employee/InventoryManager/ProductInventory', isAuthenticated, checkPermission('inventory_products'), async (req, res) => {
        let inventoryItems = [];
        let products = [];
        let categories = [];
        let allInventoryProducts = [];

        try {
            await pool.connect();

            // Fetch all products from InventoryProducts table with inventory data
            try {
                const allProductsResult = await pool.request().query(`
                    SELECT 
                        ip.InventoryProductID,
                        ip.Name as InventoryProductName,
                        ip.SKU as InventoryProductSKU,
                        ip.Category as InventoryProductCategory,
                        ip.Price as InventoryProductPrice,
                        COALESCE(
                            -- Prefer customer-facing product URLs (often already Azure/public)
                            NULLIF(pLinked.ImageURL, ''),
                            NULLIF(pById.ImageURL, ''),
                            NULLIF(pBySku.ImageURL, ''),
                            NULLIF(JSON_VALUE(pLinked.ThumbnailURLs, '$[0]'), ''),
                            NULLIF(JSON_VALUE(pById.ThumbnailURLs, '$[0]'), ''),
                            NULLIF(JSON_VALUE(pBySku.ThumbnailURLs, '$[0]'), ''),
                            -- Fallback to InventoryProducts.ImageURL (often local /uploads path)
                            NULLIF(ip.ImageURL, '')
                        ) as InventoryProductImageURL,
                        ip.DateAdded,
                        (COALESCE(ip.AvailableQuantity, 0) + COALESCE(ip.DamagedQuantity, 0)) as TotalQuantity,
                        COALESCE(ip.AvailableQuantity, 0) as AvailableQuantity,
                        COALESCE(ip.DamagedQuantity, 0) as DamagedQuantity,
                        COALESCE(ip.ReturnedQuantity, 0) as ReturnedQuantity,
                        COALESCE(ip.RepairedQuantity, 0) as RepairedQuantity,
                        COALESCE(ip.DisposedQuantity, 0) as DisposedQuantity,
                        CASE 
                            WHEN COALESCE(ip.AvailableQuantity, 0) > 0 THEN 'available'
                            WHEN COALESCE(ip.RepairedQuantity, 0) > 0 THEN 'repaired'
                            WHEN COALESCE(ip.DamagedQuantity, 0) > 0 THEN 'damaged'
                            WHEN COALESCE(ip.ReturnedQuantity, 0) > 0 THEN 'returned'
                            WHEN COALESCE(ip.DisposedQuantity, 0) > 0 THEN 'disposed'
                            ELSE COALESCE(ip.InventoryStatus, 'available')
                        END as InventoryStatus,
                        ip.Dimensions,
                        ip.InventoryNotes as Notes,
                        ip.DateUpdated
                    FROM InventoryProducts ip
                    LEFT JOIN Products pLinked ON pLinked.ProductID = ip.ProductID AND pLinked.IsActive = 1
                    LEFT JOIN Products pById ON pById.ProductID = ip.InventoryProductID AND pById.IsActive = 1
                    LEFT JOIN Products pBySku 
                        ON UPPER(LTRIM(RTRIM(pBySku.SKU))) = UPPER(LTRIM(RTRIM(ip.SKU))) 
                        AND pBySku.IsActive = 1
                    WHERE ip.IsActive = 1
                    ORDER BY ip.DateAdded DESC
                `);
                allInventoryProducts = allProductsResult.recordset || [];
                inventoryItems = allInventoryProducts;
            } catch (allProductsErr) {
                console.error('Error fetching all inventory products (InventoryManager):', allProductsErr);
                allInventoryProducts = [];
                inventoryItems = [];
            }

            // Fetch products for dropdown (from both Products and InventoryProducts tables)
            try {
                const productsFromProducts = await pool.request().query(`
                    SELECT 
                        ProductID as ID,
                        Name,
                        SKU,
                        Category,
                        Price,
                        'Products' as SourceTable
                    FROM Products
                    WHERE IsActive = 1
                `);

                const productsFromInventory = await pool.request().query(`
                    SELECT 
                        InventoryProductID as ID,
                        Name,
                        SKU,
                        Category,
                        Price,
                        'InventoryProducts' as SourceTable
                    FROM InventoryProducts
                    WHERE IsActive = 1
                `);

                products = [
                    ...productsFromProducts.recordset.map(p => ({ ...p, SourceTable: 'Products' })),
                    ...productsFromInventory.recordset.map(p => ({ ...p, SourceTable: 'InventoryProducts' }))
                ];
            } catch (productsErr) {
                console.error('Error fetching products for dropdown (InventoryManager):', productsErr);
                products = [];
            }

            // Fetch categories for dropdown
            try {
                const categoriesFromProducts = await pool.request().query(`
                    SELECT DISTINCT Category 
                    FROM Products 
                    WHERE IsActive = 1 AND Category IS NOT NULL
                `);

                const categoriesFromInventory = await pool.request().query(`
                    SELECT DISTINCT Category 
                    FROM InventoryProducts 
                    WHERE IsActive = 1 AND Category IS NOT NULL
                `);

                const allCategories = new Set();
                categoriesFromProducts.recordset.forEach(r => allCategories.add(r.Category));
                categoriesFromInventory.recordset.forEach(r => allCategories.add(r.Category));
                categories = Array.from(allCategories).sort();
            } catch (categoriesErr) {
                console.error('Error fetching categories (InventoryManager ProductInventory):', categoriesErr);
                categories = [];
            }

            res.render('Employee/InventoryManager/InventoryProductInventory', {
                user: req.session.user,
                inventoryItems,
                products,
                categories,
                allInventoryProducts
            });
        } catch (err) {
            console.error('Error in InventoryManager ProductInventory route:', err);
            req.flash('error', 'Could not fetch inventory items.');
            res.render('Employee/InventoryManager/InventoryProductInventory', {
                user: req.session.user,
                inventoryItems: [],
                products: [],
                categories: [],
                allInventoryProducts: []
            });
        }
    });
    // Inventory Manager - Add Product
    router.post('/Employee/InventoryManager/InventoryProducts/Add', isAuthenticated, checkPermission('inventory_products'), productUpload.fields([
        { name: 'image', maxCount: 1 },
        { name: 'thumbnail1', maxCount: 1 },
        { name: 'thumbnail2', maxCount: 1 },
        { name: 'thumbnail3', maxCount: 1 },
        { name: 'thumbnail4', maxCount: 1 },
        { name: 'model3d', maxCount: 1 }
    ]), async (req, res) => {
        try {
            await pool.connect();
            const { name, description, price, stockquantity, category, requiredMaterials } = req.body;

            // Start transaction
            const transaction = new sql.Transaction(pool);
            await transaction.begin();

            try {
                // Generate temporary SKU and Slug to satisfy UNIQUE constraints
                // Use SQL Server's NEWID() for PublicId directly in the query
                const tempSku = `TEMP-SKU-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
                const tempSlug = `temp-${Date.now()}-${Math.floor(Math.random() * 10000)}`;

                // Insert product with temporary identifiers
                // Use NEWID() for PublicId to ensure proper uniqueidentifier format
                const productResult = await transaction.request()
                    .input('name', sql.NVarChar, name)
                    .input('description', sql.NVarChar, description)
                    .input('price', sql.Decimal(10, 2), price)
                    .input('stockquantity', sql.Int, stockquantity)
                    .input('category', sql.NVarChar, category)
                    .input('dimensions', sql.NVarChar, dimensionsJson)
                    .input('tempSku', sql.NVarChar, tempSku)
                    .input('tempSlug', sql.NVarChar, tempSlug)
                    .query(`
                        INSERT INTO Products (Name, Description, Price, StockQuantity, Category, DateAdded, IsActive, SKU, PublicId, Slug)
                        VALUES (@name, @description, @price, @stockquantity, @category, GETDATE(), 1, @tempSku, NEWID(), @tempSlug)
                        SELECT SCOPE_IDENTITY() as ProductID
                    `);

                const productId = productResult.recordset[0].ProductID;

                // Generate final SKU and Slug based on actual ProductID
                // Generate a new GUID for the final PublicId
                const { sku, slug } = generateProductIdentifiers(productId, name);
                const finalPublicId = generateGuid(); // Generate final GUID (uppercase format)

                // Update with final identifiers
                // Use CAST to convert GUID string to uniqueidentifier
                try {
                    await transaction.request()
                        .input('productId', sql.Int, productId)
                        .input('sku', sql.NVarChar, sku)
                        .input('publicId', sql.NVarChar, finalPublicId)
                        .input('slug', sql.NVarChar, slug)
                        .query('UPDATE Products SET SKU = @sku, PublicId = CAST(@publicId AS UNIQUEIDENTIFIER), Slug = @slug WHERE ProductID = @productId');
                } catch (updateErr) {
                    console.error('Error updating product identifiers:', updateErr);
                    console.error('ProductID:', productId, 'SKU:', sku, 'PublicId:', finalPublicId, 'Slug:', slug);
                    throw updateErr;
                }

                // Handle file uploads if any
                if (req.files) {
                    // Handle main image
                    if (req.files.image) {
                        const imageFile = req.files.image[0];
                        const imageUrl = publicUrlFromMulterProductFile(imageFile);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('imageUrl', sql.NVarChar, imageUrl)
                            .query('UPDATE Products SET ImageURL = @imageUrl WHERE ProductID = @productId');
                    }

                    // Handle thumbnails
                    const thumbnails = [];
                    for (let i = 1; i <= 4; i++) {
                        if (req.files[`thumbnail${i}`]) {
                            const thumbnailFile = req.files[`thumbnail${i}`][0];
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                        }
                    }

                    if (thumbnails.length > 0) {
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('thumbnails', sql.NVarChar, JSON.stringify(thumbnails))
                            .query('UPDATE Products SET ThumbnailURLs = @thumbnails WHERE ProductID = @productId');
                    }
                }

                // Handle required materials
                console.log(`[PRODUCT ADD] Product ${productId} - Stock quantity: ${stockquantity}`);
                console.log(`[PRODUCT ADD] Product ${productId} - Required materials received:`, requiredMaterials);

                const materials = [];
                if (requiredMaterials) {
                    let materialsData;
                    try {
                        // Try parsing as JSON string first
                        if (typeof requiredMaterials === 'string') {
                            materialsData = JSON.parse(requiredMaterials);
                        } else {
                            materialsData = requiredMaterials;
                        }
                    } catch (parseError) {
                        console.error(`[PRODUCT ADD] Error parsing requiredMaterials:`, parseError);
                        console.error(`[PRODUCT ADD] requiredMaterials value:`, requiredMaterials);
                        materialsData = [];
                    }

                    console.log(`[PRODUCT ADD] Product ${productId} - Parsed materials data:`, materialsData);
                    console.log(`[PRODUCT ADD] Product ${productId} - Materials data type:`, typeof materialsData, 'Is array:', Array.isArray(materialsData));

                    for (const material of materialsData) {
                        console.log(`[PRODUCT ADD] Processing material:`, material);
                        if (material.materialId && material.quantityRequired > 0) {
                            await transaction.request()
                                .input('productId', sql.Int, productId)
                                .input('materialId', sql.Int, material.materialId)
                                .input('quantityRequired', sql.Int, material.quantityRequired)
                                .query(`
                                    INSERT INTO ProductMaterials (ProductID, MaterialID, QuantityRequired)
                                    VALUES (@productId, @materialId, @quantityRequired)
                                `);

                            materials.push({
                                materialId: material.materialId,
                                quantityRequired: material.quantityRequired
                            });

                            console.log(`[PRODUCT ADD] Added material ${material.materialId} (qty: ${material.quantityRequired}) to product ${productId}`);
                        } else {
                            console.warn(`[PRODUCT ADD] Skipping invalid material:`, material);
                        }
                    }

                    console.log(`[PRODUCT ADD] Product ${productId} - Total materials collected: ${materials.length}`);
                    console.log(`[PRODUCT ADD] Product ${productId} - Stock quantity check: ${stockquantity} > 0 = ${stockquantity > 0}`);

                    // Decrease raw materials inventory when materials are added to product
                    // Formula: quantityRequired × stockQuantity = total materials to decrease
                    if (materials.length > 0 && stockquantity > 0) {
                        console.log(`[PRODUCT ADD] Calling decreaseMaterialsForProduct for product ${productId}`);
                        await decreaseMaterialsForProduct(transaction, productId, parseInt(stockquantity) || 0, materials);
                    } else {
                        console.log(`[PRODUCT ADD] Skipping decrease - materials.length: ${materials.length}, stockquantity: ${stockquantity}`);
                    }
                } else {
                    console.log(`[PRODUCT ADD] No requiredMaterials provided for product ${productId}`);
                }

                await transaction.commit();

                // Log the activity
                await logActivity(
                    req.session.user.id,
                    'INSERT',
                    'Products',
                    productId.toString(),
                    `InventoryManager created new product: "${name}" (ID: ${productId})`
                );

                res.json({
                    success: true,
                    message: 'Product created successfully!',
                    productId: productId
                });
            } catch (err) {
                console.error('Transaction error details:', {
                    message: err.message,
                    code: err.code,
                    number: err.number,
                    originalError: err.originalError,
                    stack: err.stack
                });
                try {
                    await transaction.rollback();
                } catch (rollbackErr) {
                    // Transaction may already be aborted, ignore rollback error
                    console.error('Error during transaction rollback (may be already aborted):', rollbackErr.message);
                }
                throw err;
            }
        } catch (err) {
            console.error('Error creating product:', err);
            console.error('Error details:', {
                message: err.message,
                code: err.code,
                number: err.number,
                originalError: err.originalError
            });
            res.json({
                success: false,
                message: 'Failed to create product: ' + err.message
            });
        }
    });

    // Inventory Manager - Edit Product
