    // Inventory Manager: Delete Product Variation
    router.post('/Employee/InventoryManager/InventoryVariations/Delete/:id', isAuthenticated, checkPermission('inventory_variations'), async (req, res) => {
        try {
            await pool.connect();
            const variationID = parseInt(req.params.id);

            // Get variation info including ProductID, Quantity, and IsActive status
            const variationResult = await pool.request()
                .input('variationID', sql.Int, variationID)
                .query('SELECT ProductID, Quantity, IsActive FROM ProductVariations WHERE VariationID = @variationID');

            if (variationResult.recordset.length === 0) {
                return res.json({
                    success: false,
                    message: 'Variation not found.'
                });
            }

            const variation = variationResult.recordset[0];
            const productID = variation.ProductID;
            const variationQuantity = variation.Quantity || 0;
            const wasActive = variation.IsActive === 1;

            // Start transaction to ensure both variation delete and stock update succeed or fail together
            const transaction = new sql.Transaction(pool);
            await transaction.begin();

            try {
                // Soft delete the variation
                await transaction.request()
                    .input('variationID', sql.Int, variationID)
                    .query(`
                        UPDATE ProductVariations 
                        SET IsActive = 0 
                        WHERE VariationID = @variationID
                    `);

                // If variation was active, restore product stock by variation quantity
                if (wasActive && variationQuantity > 0) {
                    await transaction.request()
                        .input('productID', sql.Int, productID)
                        .input('quantity', sql.Int, variationQuantity)
                        .query('UPDATE Products SET StockQuantity = StockQuantity + @quantity, UpdatedAt = GETDATE() WHERE ProductID = @productID');
                }

                await transaction.commit();

                // Log the activity
                const logMessage = wasActive && variationQuantity > 0
                    ? `InventoryManager deleted product variation ID ${variationID}. Product stock restored by ${variationQuantity}.`
                    : `InventoryManager deleted product variation ID ${variationID}`;

                await logActivity(
                    req.session.user.id,
                    'DELETE',
                    'ProductVariations',
                    variationID.toString(),
                    logMessage,
                    JSON.stringify({ IsActive: { old: wasActive ? 1 : 0, new: 0 } })
                );

                res.json({
                    success: true,
                    message: wasActive && variationQuantity > 0 ? `Variation deleted successfully. Product stock restored by ${variationQuantity}.` : 'Variation deleted successfully.'
                });
            } catch (err) {
                await transaction.rollback();
                throw err;
            }
        } catch (err) {
            console.error('Error deleting inventory manager variation:', err);
            res.json({
                success: false,
                message: 'Failed to delete variation.'
            });
        }
    });
