    // User Manager OrdersPending: Proceed to Processing
    router.post('/Employee/UserManager/UserOrdersPending/Proceed/:orderId', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const orderId = parseInt(req.params.orderId);

            console.log(`[USER MANAGER ORDER PROCESSING] ====== Processing Order ${orderId} ======`);

            // Get order items to decrease stock when status changes to Processing
            const orderItemsResult = await pool.request()
                .input('orderId', sql.Int, orderId)
                .query(`
                    SELECT oi.ProductID, oi.Quantity, oi.VariationID
                    FROM OrderItems oi
                    WHERE oi.OrderID = @orderId
                `);

            console.log(`[USER MANAGER ORDER PROCESSING] Found ${orderItemsResult.recordset.length} order items`);

            // Decrease stock for each item when status changes to Processing
            // Use inventory-aware stock decrement (decrements from InventoryProducts and syncs to Products)
            for (const item of orderItemsResult.recordset) {
                try {
                    console.log(`[USER MANAGER ORDER PROCESSING] Decrementing stock for ProductID: ${item.ProductID}, Quantity: ${item.Quantity}, VariationID: ${item.VariationID || 'none'}`);
                    await decrementStockFromInventory(item.ProductID, item.Quantity, item.VariationID || null, null);
                    console.log(`[USER MANAGER ORDER PROCESSING] ✅ Successfully decremented stock for ProductID: ${item.ProductID}`);
                } catch (stockErr) {
                    console.error(`[USER MANAGER ORDER PROCESSING] ❌ Error decrementing stock for ProductID ${item.ProductID}:`, stockErr);
                    // Continue processing other items even if one fails
                }
            }

            // Update order status to Processing
            await pool.request()
                .input('orderId', sql.Int, orderId)
                .query(`UPDATE Orders SET Status = 'Processing' WHERE OrderID = @orderId`);

            console.log(`[USER MANAGER ORDER PROCESSING] ✅ Order ${orderId} status updated to Processing`);

            // Log the activity
            await logActivity(
                req.session.user.id,
                'UPDATE',
                'Orders',
                orderId,
                `Order #${orderId} status changed to Processing by User Manager`
            );

            res.json({ success: true });
        } catch (err) {
            console.error(`[USER MANAGER ORDER PROCESSING] ❌ Error processing order ${req.params.orderId}:`, err);
            res.json({ success: false, message: 'Failed to update order status.' });
        }
    });

