    // Get all region-based delivery rates (Admin)
    router.get('/api/admin/region-delivery-rates', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();

            // Ensure table exists
            await pool.request().query(`
                IF OBJECT_ID('dbo.RegionDeliveryRates','U') IS NULL
                BEGIN
                    CREATE TABLE dbo.RegionDeliveryRates (
                        RegionRateID INT IDENTITY(1,1) PRIMARY KEY,
                        Region NVARCHAR(100) NULL,
                        Province NVARCHAR(100) NULL,
                        City NVARCHAR(100) NOT NULL,
                        Price DECIMAL(18,2) NOT NULL,
                        ServiceType NVARCHAR(150) NULL,
                        IsActive BIT NOT NULL DEFAULT 1,
                        CreatedAt DATETIME2(0) NOT NULL DEFAULT SYSUTCDATETIME(),
                        UpdatedAt DATETIME2(0) NULL,
                        CreatedByUserID INT NULL,
                        CreatedByUsername NVARCHAR(150) NULL,
                        UpdatedByUserID INT NULL,
                        UpdatedByUsername NVARCHAR(150) NULL,
                        Notes NVARCHAR(500) NULL
                    );
                    
                    -- Create filtered unique index (WHERE clause not allowed in constraint)
                    CREATE UNIQUE INDEX UX_RegionDeliveryRates_Location_ServiceType 
                        ON dbo.RegionDeliveryRates (Region, Province, City, ServiceType)
                        WHERE IsActive = 1;
                    
                    -- Create other indexes for faster lookups
                    CREATE INDEX IX_RegionDeliveryRates_City ON dbo.RegionDeliveryRates (City) WHERE IsActive = 1;
                    CREATE INDEX IX_RegionDeliveryRates_Province ON dbo.RegionDeliveryRates (Province) WHERE IsActive = 1;
                    CREATE INDEX IX_RegionDeliveryRates_Region ON dbo.RegionDeliveryRates (Region) WHERE IsActive = 1;
                END
            `);

            const result = await pool.request().query(`
                SELECT 
                    RegionRateID,
                    Region,
                    Province,
                    City,
                    Price,
                    ServiceType,
                    IsActive,
                    CreatedAt, 
                    UpdatedAt,
                    CreatedByUsername,
                    UpdatedByUsername,
                    Notes
                FROM RegionDeliveryRates
                ORDER BY 
                    CASE WHEN Region IS NULL THEN 1 ELSE 0 END,
                    Region,
                    Province,
                    City,
                    ServiceType
            `);

            res.json({ success: true, rates: result.recordset });
        } catch (err) {
            console.error('Error fetching region delivery rates:', err);
            res.status(500).json({ success: false, message: 'Failed to fetch region delivery rates', error: err.message });
        }
    });
    // Add region-based delivery rate (Admin)
    router.post('/api/admin/region-delivery-rates', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const { region, province, city, price, serviceType, notes } = req.body;
            const user = req.session.user || {};

            if (!region || !region.trim()) {
                return res.json({ success: false, message: 'Region is required' });
            }

            if (!city || price === undefined || price === null) {
                return res.json({ success: false, message: 'City and price are required' });
            }

            const result = await pool.request()
                .input('Region', sql.NVarChar(100), region.trim())
                .input('Province', sql.NVarChar(100), province || null)
                .input('City', sql.NVarChar(100), city)
                .input('Price', sql.Decimal(18, 2), Number(price))
                .input('ServiceType', sql.NVarChar(150), serviceType || null)
                .input('CreatedByUserID', sql.Int, user.id || null)
                .input('CreatedByUsername', sql.NVarChar(150), user.username || null)
                .input('Notes', sql.NVarChar(500), notes || null)
                .query(`
                    IF EXISTS (
                        SELECT 1 FROM RegionDeliveryRates 
                        WHERE (Region = @Region OR (Region IS NULL AND @Region IS NULL))
                        AND (Province = @Province OR (Province IS NULL AND @Province IS NULL))
                        AND City = @City
                        AND (ServiceType = @ServiceType OR (ServiceType IS NULL AND @ServiceType IS NULL))
                        AND IsActive = 1
                    )
                    BEGIN
                        SELECT 0 AS success, 'This location and service type combination already exists' AS message;
                        RETURN;
                    END
                    
                    INSERT INTO RegionDeliveryRates 
                        (Region, Province, City, Price, ServiceType, CreatedByUserID, CreatedByUsername, Notes)
                    VALUES 
                        (@Region, @Province, @City, @Price, @ServiceType, @CreatedByUserID, @CreatedByUsername, @Notes);
                    
                    SELECT 1 AS success, SCOPE_IDENTITY() AS RegionRateID;
                `);

            if (result.recordset[0].success) {
                // Log the activity
                await logActivity(
                    req.session.user.id,
                    'INSERT',
                    'RegionDeliveryRates',
                    result.recordset[0].RegionRateID.toString(),
                    `Admin added region delivery rate: ${city} ${province ? `(${province})` : ''} - ₱${price}`
                );

                res.json({ success: true, regionRateId: result.recordset[0].RegionRateID });
            } else {
                res.json({ success: false, message: result.recordset[0].message });
            }
        } catch (err) {
            console.error('Error adding region delivery rate:', err);
            res.status(500).json({ success: false, message: 'Failed to add region delivery rate', error: err.message });
        }
    });

    // Update region-based delivery rate (Admin)
    router.put('/api/admin/region-delivery-rates/:id', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const regionRateId = parseInt(req.params.id);
            const { region, province, city, price, serviceType, isActive, notes } = req.body;
            const user = req.session.user || {};

            if (!regionRateId) {
                return res.json({ success: false, message: 'Invalid region rate ID' });
            }

            // Validate region is required
            if (region !== undefined && (!region || !region.trim())) {
                return res.json({ success: false, message: 'Region is required' });
            }

            const request = pool.request()
                .input('RegionRateID', sql.Int, regionRateId)
                .input('UpdatedByUserID', sql.Int, user.id || null)
                .input('UpdatedByUsername', sql.NVarChar(150), user.username || null);

            let setClauses = ['UpdatedAt = SYSUTCDATETIME()', 'UpdatedByUserID = @UpdatedByUserID', 'UpdatedByUsername = @UpdatedByUsername'];

            if (region !== undefined) {
                request.input('Region', sql.NVarChar(100), region.trim());
                setClauses.push('Region = @Region');
            }
            if (province !== undefined) {
                request.input('Province', sql.NVarChar(100), province || null);
                setClauses.push('Province = @Province');
            }
            if (city !== undefined) {
                request.input('City', sql.NVarChar(100), city);
                setClauses.push('City = @City');
            }
            if (price !== undefined) {
                request.input('Price', sql.Decimal(18, 2), Number(price));
                setClauses.push('Price = @Price');
            }
            if (serviceType !== undefined) {
                request.input('ServiceType', sql.NVarChar(150), serviceType || null);
                setClauses.push('ServiceType = @ServiceType');
            }
            if (isActive !== undefined) {
                request.input('IsActive', sql.Bit, Boolean(isActive));
                setClauses.push('IsActive = @IsActive');
            }
            if (notes !== undefined) {
                request.input('Notes', sql.NVarChar(500), notes || null);
                setClauses.push('Notes = @Notes');
            }

            if (setClauses.length === 3) {
                return res.json({ success: false, message: 'No fields to update' });
            }

            const setSql = setClauses.join(', ');
            await request.query(`
                UPDATE RegionDeliveryRates 
                SET ${setSql}
                WHERE RegionRateID = @RegionRateID;
            `);

            // Log the activity
            await logActivity(
                req.session.user.id,
                'UPDATE',
                'RegionDeliveryRates',
                regionRateId.toString(),
                `Admin updated region delivery rate ID ${regionRateId}`
            );

            res.json({ success: true });
        } catch (err) {
            console.error('Error updating region delivery rate:', err);
            res.status(500).json({ success: false, message: 'Failed to update region delivery rate', error: err.message });
        }
    });

    // Delete/deactivate region-based delivery rate (Admin)
    router.delete('/api/admin/region-delivery-rates/:id', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const regionRateId = parseInt(req.params.id);

            if (!regionRateId) {
                return res.json({ success: false, message: 'Invalid region rate ID' });
            }

            // Get rate details before deletion for logging
            const rateDetails = await pool.request()
                .input('RegionRateID', sql.Int, regionRateId)
                .query(`
                    SELECT Region, Province, City, Price, ServiceType
                    FROM RegionDeliveryRates
                    WHERE RegionRateID = @RegionRateID
                `);

            // Actually delete the record from the database
            await pool.request()
                .input('RegionRateID', sql.Int, regionRateId)
                .query(`
                    DELETE FROM RegionDeliveryRates 
                    WHERE RegionRateID = @RegionRateID
                `);

            // Log the activity
            const rateInfo = rateDetails.recordset[0];
            const rateDescription = rateInfo ?
                `${rateInfo.City || 'Unknown'} (${rateInfo.Region || rateInfo.Province || 'N/A'}) - ₱${rateInfo.Price || 0}` :
                `ID ${regionRateId}`;

            await logActivity(
                req.session.user.id,
                'DELETE',
                'RegionDeliveryRates',
                regionRateId.toString(),
                `Admin permanently deleted region delivery rate: ${rateDescription}`
            );

            res.json({ success: true, message: 'Region delivery rate permanently deleted' });
        } catch (err) {
            console.error('Error deleting region delivery rate:', err);
            res.status(500).json({ success: false, message: 'Failed to delete region delivery rate', error: err.message });
        }
    });

    // Get delivery rate for specific address (Public API for checkout)
    router.post('/api/delivery-rate/calculate', async (req, res) => {
        try {
            await pool.connect();
            const { city, province, region, serviceType } = req.body;

            if (!city) {
                return res.json({ success: false, message: 'City is required' });
            }

            // Check if region-based delivery is enabled
            const settingResult = await pool.request().query(`
                SELECT SettingValue 
                FROM SystemSettings 
                WHERE SettingKey = 'USE_REGION_BASED_DELIVERY'
            `);

            const useRegionBased = settingResult.recordset.length > 0 &&
                settingResult.recordset[0].SettingValue === '1';

            if (!useRegionBased) {
                // Fall back to legacy DeliveryRates
                const legacyRates = await pool.request().query(`
                    SELECT RateID, ServiceType, Price
                    FROM DeliveryRates
                    WHERE IsActive = 1
                    ORDER BY Price ASC
                `);

                return res.json({
                    success: true,
                    rates: legacyRates.recordset,
                    useLegacy: true
                });
            }

            // Get all available service types for this city that match the address
            const result = await pool.request()
                .input('City', sql.NVarChar(100), city)
                .input('Province', sql.NVarChar(100), province || null)
                .input('Region', sql.NVarChar(100), region || null)
                .query(`
                    SELECT 
                        RegionRateID,
                        Region,
                        Province,
                        City,
                        Price,
                        ServiceType,
                        Notes,
                        CASE 
                            -- Priority 1: Exact match (City + Province + Region)
                            WHEN (Province = @Province OR (Province IS NULL AND @Province IS NULL)) 
                                 AND (Region = @Region OR (Region IS NULL AND @Region IS NULL)) THEN 1
                            -- Priority 2: City + Province match (rate has NULL region)
                            WHEN (Province = @Province OR (Province IS NULL AND @Province IS NULL)) 
                                 AND Region IS NULL AND @Region IS NOT NULL THEN 2
                            -- Priority 3: City + Region match (rate has NULL province) - for NCR
                            WHEN Province IS NULL AND @Province IS NULL 
                                 AND (Region = @Region OR (Region IS NULL AND @Region IS NULL)) THEN 3
                            -- Priority 4: City only match (rate has NULL province and region)
                            WHEN Province IS NULL AND Region IS NULL THEN 4
                            ELSE 5
                        END AS MatchPriority
                    FROM RegionDeliveryRates
                    WHERE IsActive = 1
                        AND City = @City
                        AND (
                            -- Exact match (handles NULL = NULL properly)
                            ((Province = @Province OR (Province IS NULL AND @Province IS NULL)) 
                             AND (Region = @Region OR (Region IS NULL AND @Region IS NULL)))
                            OR
                            -- City + Province (generic for all regions)
                            ((Province = @Province OR (Province IS NULL AND @Province IS NULL)) 
                             AND Region IS NULL)
                            OR
                            -- City + Region only (NULL province) - NCR case
                            (Province IS NULL AND @Province IS NULL 
                             AND (Region = @Region OR (Region IS NULL AND @Region IS NULL)))
                            OR
                            -- City only (generic for all provinces/regions)
                            (Province IS NULL AND Region IS NULL)
                        )
                    ORDER BY MatchPriority ASC, Price ASC
                `);

            if (result.recordset.length > 0) {
                // Return all matching rates for this location
                res.json({
                    success: true,
                    rate: result.recordset[0],
                    availableServiceTypes: result.recordset,
                    useRegionBased: true
                });
            } else {
                // No rate found for this location
                res.json({
                    success: false,
                    message: `No delivery rate found for ${city}${province ? ', ' + province : ''}. Please contact us for a quote.`,
                    useRegionBased: true
                });
            }
        } catch (err) {
            console.error('Error calculating delivery rate:', err);
            res.status(500).json({ success: false, message: 'Failed to calculate delivery rate', error: err.message });
        }
    });

