    // Helper function to ensure WalkInOrders table exists
    async function ensureWalkInOrdersTable(pool) {
        try {
            console.log('Checking if WalkInOrders table exists...');

            // First check if table exists
            const tableExists = await pool.request().query(`
                SELECT COUNT(*) as count FROM sys.tables WHERE name = 'WalkInOrders'
            `);

            if (tableExists.recordset[0].count === 0) {
                console.log('Creating WalkInOrders table...');
                await pool.request().query(`
                    CREATE TABLE WalkInOrders (
                        BulkOrderID INT IDENTITY(1,1) PRIMARY KEY,
                        CustomerName NVARCHAR(255) NOT NULL,
                        Address NVARCHAR(MAX) NULL,
                        ContactNumber NVARCHAR(100) NULL,
                        ContactEmail NVARCHAR(255) NULL,
                        OrderedProducts NVARCHAR(MAX) NULL, -- JSON or text description
                        Discount DECIMAL(10,2) NULL DEFAULT(0),
                        TotalAmount DECIMAL(10,2) NOT NULL,
                        Status NVARCHAR(50) NOT NULL DEFAULT('Processing'),
                        ExpectedArrival DATETIME NULL,
                        CompletedAt DATETIME NULL,
                        CreatedAt DATETIME NOT NULL DEFAULT(GETDATE()),
                        DeliveryType NVARCHAR(100) NOT NULL DEFAULT('pickup'),
                        AddressRegion NVARCHAR(100) NULL,
                        AddressProvince NVARCHAR(100) NULL,
                        AddressCity NVARCHAR(100) NULL,
                        AddressBarangay NVARCHAR(100) NULL,
                        AddressPostalCode NVARCHAR(20) NULL
                    )
                `);
                console.log('WalkInOrders table created successfully');
            } else {
                console.log('WalkInOrders table already exists');

                // Check if BulkOrderID column exists
                const columnExists = await pool.request().query(`
                    SELECT COUNT(*) as count 
                    FROM INFORMATION_SCHEMA.COLUMNS 
                    WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = 'BulkOrderID'
                `);

                if (columnExists.recordset[0].count === 0) {
                    console.log('BulkOrderID column missing, recreating table...');
                    // Drop and recreate table
                    await pool.request().query(`DROP TABLE WalkInOrders`);
                    await pool.request().query(`
                        CREATE TABLE WalkInOrders (
                            BulkOrderID INT IDENTITY(1,1) PRIMARY KEY,
                            CustomerName NVARCHAR(255) NOT NULL,
                            Address NVARCHAR(MAX) NULL,
                            ContactNumber NVARCHAR(100) NULL,
                            ContactEmail NVARCHAR(255) NULL,
                            OrderedProducts NVARCHAR(MAX) NULL, -- JSON or text description
                            Discount DECIMAL(10,2) NULL DEFAULT(0),
                            TotalAmount DECIMAL(10,2) NOT NULL,
                            Status NVARCHAR(50) NOT NULL DEFAULT('Processing'),
                            ExpectedArrival DATETIME NULL,
                            CompletedAt DATETIME NULL,
                            CreatedAt DATETIME NOT NULL DEFAULT(GETDATE()),
                            DeliveryType NVARCHAR(100) NOT NULL DEFAULT('pickup'),
                            AddressRegion NVARCHAR(100) NULL,
                            AddressProvince NVARCHAR(100) NULL,
                            AddressCity NVARCHAR(100) NULL,
                            AddressBarangay NVARCHAR(100) NULL,
                            AddressPostalCode NVARCHAR(20) NULL
                        )
                    `);
                    console.log('WalkInOrders table recreated successfully');
                }
            }

            // Add constraints if they don't exist
            const statusConstraintExists = await pool.request().query(`
                SELECT COUNT(*) as count FROM sys.check_constraints 
                WHERE name = 'CHK_WalkInOrders_Status' AND parent_object_id = OBJECT_ID('WalkInOrders')
            `);

            if (statusConstraintExists.recordset[0].count === 0) {
                console.log('Adding Status constraint...');
                await pool.request().query(`
                    ALTER TABLE WalkInOrders WITH NOCHECK
                    ADD CONSTRAINT CHK_WalkInOrders_Status
                    CHECK (Status IN ('Processing', 'On delivery', 'Completed'))
                `);
                console.log('Status constraint added');
            }

            // Remove DeliveryType constraint if it exists (since it can now be a rate ID like 'rate_123')
            const deliveryConstraintExists = await pool.request().query(`
                SELECT COUNT(*) as count FROM sys.check_constraints 
                WHERE name = 'CHK_WalkInOrders_DeliveryType' AND parent_object_id = OBJECT_ID('WalkInOrders')
            `);

            if (deliveryConstraintExists.recordset[0].count > 0) {
                console.log('Removing old DeliveryType constraint to allow rate IDs...');
                await pool.request().query(`
                    ALTER TABLE WalkInOrders DROP CONSTRAINT CHK_WalkInOrders_DeliveryType
                `);
                console.log('DeliveryType constraint removed');
            }

            // Add new address columns if they don't exist
            const addressColumns = ['AddressRegion', 'AddressProvince', 'AddressCity', 'AddressBarangay', 'AddressPostalCode'];
            for (const colName of addressColumns) {
                const colExists = await pool.request().query(`
                    SELECT COUNT(*) as count 
                    FROM INFORMATION_SCHEMA.COLUMNS 
                    WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = '${colName}'
                `);

                if (colExists.recordset[0].count === 0) {
                    const colType = colName === 'AddressPostalCode' ? 'NVARCHAR(20)' : 'NVARCHAR(100)';
                    await pool.request().query(`
                        ALTER TABLE WalkInOrders ADD ${colName} ${colType} NULL
                    `);
                    console.log(`Added ${colName} column to WalkInOrders`);
                }
            }

            // Ensure Discount column exists (older tables may not have it)
            const discountColExists = await pool.request().query(`
                SELECT COUNT(*) as count
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = 'Discount'
            `);

            if (discountColExists.recordset[0].count === 0) {
                await pool.request().query(`
                    ALTER TABLE WalkInOrders ADD Discount DECIMAL(10,2) NULL
                `);
                await pool.request().query(`
                    UPDATE WalkInOrders SET Discount = 0 WHERE Discount IS NULL
                `);
                console.log('Added Discount column to WalkInOrders');
            }

            // Update DeliveryType column size if needed (to accommodate rate IDs)
            const deliveryTypeCol = await pool.request().query(`
                SELECT CHARACTER_MAXIMUM_LENGTH 
                FROM INFORMATION_SCHEMA.COLUMNS 
                WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = 'DeliveryType'
            `);

            if (deliveryTypeCol.recordset.length > 0 && deliveryTypeCol.recordset[0].CHARACTER_MAXIMUM_LENGTH < 100) {
                await pool.request().query(`
                    ALTER TABLE WalkInOrders ALTER COLUMN DeliveryType NVARCHAR(100) NOT NULL
                `);
                console.log('Updated DeliveryType column size to 100');
            }

            // Additional tracking/payment columns for walk-in cards
            const extraColumns = [
                { name: 'OrderNumber', type: 'NVARCHAR(50)' },
                { name: 'TransactionID', type: 'NVARCHAR(120)' },
                { name: 'PaymentMethod', type: 'NVARCHAR(50)' },
                { name: 'PaymentStatus', type: 'NVARCHAR(50)' },
                { name: 'StripeSessionID', type: 'NVARCHAR(255)' },
                { name: 'AddressHouseNumber', type: 'NVARCHAR(100)' },
                { name: 'AddressStreet', type: 'NVARCHAR(500)' }
            ];
            for (const col of extraColumns) {
                const exists = await pool.request().query(`
                    SELECT COUNT(*) as count
                    FROM INFORMATION_SCHEMA.COLUMNS
                    WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = '${col.name}'
                `);
                if (exists.recordset[0].count === 0) {
                    await pool.request().query(`
                        ALTER TABLE WalkInOrders ADD ${col.name} ${col.type} NULL
                    `);
                    console.log(`Added ${col.name} column to WalkInOrders`);
                }
            }

            // Widen legacy TransactionID column if still NVARCHAR(50)
            try {
                const txnLen = await pool.request().query(`
                    SELECT CHARACTER_MAXIMUM_LENGTH AS len
                    FROM INFORMATION_SCHEMA.COLUMNS
                    WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = 'TransactionID'
                `);
                const len = txnLen.recordset?.[0]?.len;
                if (len && len < 120) {
                    await pool.request().query(`
                        ALTER TABLE WalkInOrders ALTER COLUMN TransactionID NVARCHAR(120) NULL
                    `);
                    console.log('Widened WalkInOrders.TransactionID to NVARCHAR(120)');
                }
            } catch (widenErr) {
                console.warn('Could not widen WalkInOrders.TransactionID:', widenErr.message);
            }

            console.log('WalkInOrders table setup completed');
        } catch (err) {
            console.error('Error in ensureWalkInOrdersTable:', err);
            throw err;
        }
    }

    // Admin WalkIn: Add new walk-in order
    router.post('/Employee/Admin/WalkIn/Add', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            await ensureWalkInOrdersTable(pool);
            const { customerName, address, contactNumber, contactEmail, orderedProducts, discount, totalAmount, expectedArrival, deliveryType, deliveryRate, addressRegion, addressProvince, addressCity, addressBarangay, addressPostalCode, addressHouseNumber, addressStreet, paymentMethod, stripeSessionId } = req.body;
            const ordered = JSON.parse(orderedProducts || '[]');

            const pmKey = String(paymentMethod || 'cash').toLowerCase();
            let walkInPaymentLabel = 'Cash';
            if (pmKey === 'stripe') walkInPaymentLabel = 'Stripe';
            else if (pmKey === 'paymongo') walkInPaymentLabel = 'PayMongo';

            const gatewayAwaitingPayment = pmKey === 'stripe' || pmKey === 'paymongo';
            const walkInPaymentStatusForInsert = gatewayAwaitingPayment ? 'Pending' : 'Paid';
            const linkedOrderPaymentStatusForInsert = gatewayAwaitingPayment ? 'Pending' : 'Paid';

            if (deliveryType === 'pickup' && pmKey !== 'cash') {
                return res.status(400).send('Pickup orders can only use Cash payment.');
            }

            if (deliveryType === 'delivery') {
                const hn = String(addressHouseNumber || '').trim();
                const st = String(addressStreet || '').trim();
                if (!hn && !st) {
                    return res.status(400).send('Delivery requires House/Unit and/or Street in the delivery address (use Add Address).');
                }
            }

            // Determine delivery type - if deliveryRate is provided, use it; otherwise use deliveryType
            const finalDeliveryType = (deliveryType === 'delivery' && deliveryRate) ? deliveryRate : (deliveryType || 'pickup');

            // For delivery orders, require a valid existing customer account by email
            let linkedCustomer = null;
            if (deliveryType === 'delivery') {
                if (!contactEmail || !String(contactEmail).trim()) {
                    return res.status(400).send('Delivery orders require a customer account email.');
                }

                const customerResult = await pool.request()
                    .input('email', sql.NVarChar, String(contactEmail).trim())
                    .query(`
                        SELECT TOP 1 CustomerID, FullName, Email, IsActive
                        FROM Customers
                        WHERE Email = @email
                    `);

                if (!customerResult.recordset.length) {
                    return res.status(400).send('Customer account email not found. Please use a registered customer email.');
                }

                linkedCustomer = customerResult.recordset[0];
                if (linkedCustomer.IsActive === 0 || linkedCustomer.IsActive === false) {
                    return res.status(400).send('Customer account is inactive. Please use an active customer account.');
                }
            }

            // Resolve a valid PaymentMethod based on current DB constraint (CHK_PaymentMethod)
            async function resolveAllowedPaymentMethod() {
                try {
                    const constraintResult = await pool.request().query(`
                        SELECT TOP 1 cc.definition
                        FROM sys.check_constraints cc
                        INNER JOIN sys.objects o ON cc.parent_object_id = o.object_id
                        WHERE o.name = 'Orders' AND cc.name = 'CHK_PaymentMethod'
                    `);

                    const definition = constraintResult.recordset?.[0]?.definition || '';
                    const allowed = [];
                    const matcher = /'([^']+)'/g;
                    let match;
                    while ((match = matcher.exec(definition)) !== null) {
                        if (match[1]) allowed.push(match[1]);
                    }

                    // Prefer methods already used by existing customer order flow
                    const preferredOrder = ['E-Wallet', 'Cash on Delivery', 'Bank Transfer'];
                    for (const preferred of preferredOrder) {
                        if (allowed.includes(preferred)) return preferred;
                    }
                    if (allowed.length > 0) return allowed[0];
                } catch (constraintErr) {
                    console.warn('[WALKIN LINKED ORDER] Could not parse CHK_PaymentMethod, using fallback:', constraintErr.message);
                }

                // Fallback to last used method in Orders
                try {
                    const recent = await pool.request().query(`
                        SELECT TOP 1 PaymentMethod
                        FROM Orders
                        WHERE PaymentMethod IS NOT NULL
                        ORDER BY OrderID DESC
                    `);
                    const fallback = recent.recordset?.[0]?.PaymentMethod;
                    if (fallback) return fallback;
                } catch (recentErr) {
                    console.warn('[WALKIN LINKED ORDER] Could not fetch fallback PaymentMethod:', recentErr.message);
                }

                return 'E-Wallet';
            }

            async function resolveLinkedOrderPaymentMethodFromWalkIn(walkInLabel) {
                let allowed = [];
                try {
                    const constraintResult = await pool.request().query(`
                        SELECT TOP 1 cc.definition
                        FROM sys.check_constraints cc
                        INNER JOIN sys.objects o ON cc.parent_object_id = o.object_id
                        WHERE o.name = 'Orders' AND cc.name = 'CHK_PaymentMethod'
                    `);
                    const definition = constraintResult.recordset?.[0]?.definition || '';
                    const matcher = /'([^']+)'/g;
                    let match;
                    while ((match = matcher.exec(definition)) !== null) {
                        if (match[1]) allowed.push(match[1]);
                    }
                } catch (constraintErr) {
                    console.warn('[WALKIN LINKED ORDER] Could not read CHK_PaymentMethod:', constraintErr.message);
                }

                const label = String(walkInLabel || 'Cash');
                if (label === 'Stripe') {
                    const hit = allowed.find(a => /e-wallet|wallet|stripe|card/i.test(a));
                    if (hit) return hit;
                    return 'E-Wallet';
                }
                if (label === 'PayMongo') {
                    if (allowed.includes('PayMongo')) return 'PayMongo';
                    const hit = allowed.find(a => /paymongo/i.test(a));
                    if (hit) return hit;
                    return 'E-Wallet';
                }
                const cod = allowed.find(a => /cash on delivery|cod/i.test(a));
                if (cod) return cod;
                if (allowed.includes('Cash')) return 'Cash';
                return await resolveAllowedPaymentMethod();
            }

            const lineSubtotal = ordered.reduce((sum, it) => {
                const unit = Number(it.unitPrice || 0);
                const qty = Math.max(0, parseInt(it.quantity || 0, 10));
                return sum + unit * qty;
            }, 0);
            const discPct = Number(discount || 0);
            const safeDiscPct = Math.min(100, Math.max(0, Number.isFinite(discPct) ? discPct : 0));
            const discountedMerchandise = lineSubtotal * (1 - safeDiscPct / 100);

            let walkInServiceType = 'Standard Delivery';
            let walkInDeliveryCost = 0;
            if (finalDeliveryType && String(finalDeliveryType).startsWith('rate_')) {
                const rateId = parseInt(String(finalDeliveryType).replace('rate_', ''), 10);
                if (!Number.isNaN(rateId)) {
                    const rateResult = await pool.request()
                        .input('rateId', sql.Int, rateId)
                        .query(`
                            SELECT TOP 1 ServiceType, Price
                            FROM RegionDeliveryRates
                            WHERE RegionRateID = @rateId
                        `);
                    if (rateResult.recordset.length > 0) {
                        walkInServiceType = rateResult.recordset[0].ServiceType || walkInServiceType;
                        walkInDeliveryCost = Number(rateResult.recordset[0].Price || 0);
                    }
                }
            }

            const finalOrderTotal = Math.round((discountedMerchandise + walkInDeliveryCost) * 100) / 100;

            // Insert bulk order with ETA
            const nowForIds = new Date();
            const walkInTransactionId = generateTransactionId(nowForIds);
            const walkInInsert = await pool.request()
                .input('CustomerName', customerName || '')
                .input('Address', address || '')
                .input('ContactNumber', contactNumber || '')
                .input('ContactEmail', contactEmail || '')
                .input('OrderedProducts', orderedProducts || '')
                .input('Discount', Number(discount || 0))
                .input('TotalAmount', Number(finalOrderTotal))
                .input('ExpectedArrival', expectedArrival ? new Date(expectedArrival) : null)
                .input('DeliveryType', finalDeliveryType)
                .input('AddressRegion', addressRegion || null)
                .input('AddressProvince', addressProvince || null)
                .input('AddressCity', addressCity || null)
                .input('AddressBarangay', addressBarangay || null)
                .input('AddressPostalCode', addressPostalCode || null)
                .input('AddressHouseNumber', addressHouseNumber || null)
                .input('AddressStreet', addressStreet || null)
                .input('PaymentMethod', walkInPaymentLabel)
                .input('PaymentStatus', walkInPaymentStatusForInsert)
                .input('StripeSessionID', stripeSessionId || null)
                .input('TransactionID', walkInTransactionId)
                .query(`
                    INSERT INTO WalkInOrders 
                        (CustomerName, Address, ContactNumber, ContactEmail, OrderedProducts, Discount, TotalAmount, Status, ExpectedArrival, DeliveryType, AddressRegion, AddressProvince, AddressCity, AddressBarangay, AddressPostalCode, AddressHouseNumber, AddressStreet, PaymentMethod, PaymentStatus, StripeSessionID, TransactionID)
                    OUTPUT INSERTED.BulkOrderID
                    VALUES 
                        (@CustomerName, @Address, @ContactNumber, @ContactEmail, @OrderedProducts, @Discount, @TotalAmount, 'Processing', @ExpectedArrival, @DeliveryType, @AddressRegion, @AddressProvince, @AddressCity, @AddressBarangay, @AddressPostalCode, @AddressHouseNumber, @AddressStreet, @PaymentMethod, @PaymentStatus, @StripeSessionID, @TransactionID)
                `);
            const walkInOrderId = walkInInsert.recordset?.[0]?.BulkOrderID;
            const walkInOrderNumber = generateReferenceNumber(nowForIds, walkInOrderId);
            await pool.request()
                .input('walkInOrderId', sql.Int, walkInOrderId)
                .input('orderNumber', sql.NVarChar, walkInOrderNumber)
                .query(`UPDATE WalkInOrders SET OrderNumber = @orderNumber WHERE BulkOrderID = @walkInOrderId`);

            // If delivery and customer email is valid, create a linked customer Order for dashboard tracking
            if (deliveryType === 'delivery' && linkedCustomer && walkInOrderId) {
                const safePaymentMethod = await resolveLinkedOrderPaymentMethodFromWalkIn(walkInPaymentLabel);
                console.log('[WALKIN LINKED ORDER] Using PaymentMethod:', safePaymentMethod);

                // Ensure LinkedOrderID column exists
                const linkedOrderColCheck = await pool.request().query(`
                    SELECT COUNT(*) as count
                    FROM INFORMATION_SCHEMA.COLUMNS
                    WHERE TABLE_NAME = 'WalkInOrders' AND COLUMN_NAME = 'LinkedOrderID'
                `);
                if (linkedOrderColCheck.recordset[0].count === 0) {
                    await pool.request().query(`
                        ALTER TABLE WalkInOrders ADD LinkedOrderID INT NULL
                    `);
                }

                // Reuse existing customer address if exact match exists, otherwise create one
                let shippingAddressId = null;
                const shipHouse = addressHouseNumber ? String(addressHouseNumber).trim() : null;
                const shipStreet = addressStreet ? String(addressStreet).trim() : null;
                if (addressCity || addressProvince || addressRegion) {
                    const existingAddressResult = await pool.request()
                        .input('customerId', sql.Int, linkedCustomer.CustomerID)
                        .input('houseNumber', sql.NVarChar, shipHouse)
                        .input('street', sql.NVarChar, shipStreet)
                        .input('barangay', sql.NVarChar, addressBarangay || null)
                        .input('city', sql.NVarChar, addressCity || null)
                        .input('province', sql.NVarChar, addressProvince || null)
                        .input('region', sql.NVarChar, addressRegion || null)
                        .input('postalCode', sql.NVarChar, addressPostalCode || null)
                        .query(`
                            SELECT TOP 1 AddressID
                            FROM CustomerAddresses
                            WHERE CustomerID = @customerId
                              AND ISNULL(HouseNumber,'') = ISNULL(@houseNumber,'')
                              AND ISNULL(Street,'') = ISNULL(@street,'')
                              AND ISNULL(Barangay,'') = ISNULL(@barangay,'')
                              AND ISNULL(City,'') = ISNULL(@city,'')
                              AND ISNULL(Province,'') = ISNULL(@province,'')
                              AND ISNULL(Region,'') = ISNULL(@region,'')
                              AND ISNULL(PostalCode,'') = ISNULL(@postalCode,'')
                            ORDER BY AddressID DESC
                        `);

                    if (existingAddressResult.recordset.length > 0) {
                        shippingAddressId = existingAddressResult.recordset[0].AddressID;
                    } else {
                        const newAddressResult = await pool.request()
                            .input('customerId', sql.Int, linkedCustomer.CustomerID)
                            .input('label', sql.NVarChar, 'Walk-in Delivery')
                            .input('houseNumber', sql.NVarChar, shipHouse)
                            .input('street', sql.NVarChar, shipStreet)
                            .input('barangay', sql.NVarChar, addressBarangay || null)
                            .input('city', sql.NVarChar, addressCity || null)
                            .input('province', sql.NVarChar, addressProvince || null)
                            .input('region', sql.NVarChar, addressRegion || null)
                            .input('postalCode', sql.NVarChar, addressPostalCode || null)
                            .input('country', sql.NVarChar, 'Philippines')
                            .query(`
                                INSERT INTO CustomerAddresses
                                    (CustomerID, Label, HouseNumber, Street, Barangay, City, Province, Region, PostalCode, Country, IsDefault)
                                OUTPUT INSERTED.AddressID
                                VALUES
                                    (@customerId, @label, @houseNumber, @street, @barangay, @city, @province, @region, @postalCode, @country, 0)
                            `);
                        shippingAddressId = newAddressResult.recordset?.[0]?.AddressID || null;
                    }
                }

                const serviceType = walkInServiceType;
                const deliveryCost = walkInDeliveryCost;

                const now = new Date();
                const orderInsertResult = await pool.request()
                    .input('customerId', sql.Int, linkedCustomer.CustomerID)
                    .input('status', sql.NVarChar, 'Pending')
                    .input('totalAmount', sql.Decimal(10, 2), finalOrderTotal)
                    .input('paymentMethod', sql.NVarChar, safePaymentMethod)
                    .input('currency', sql.NVarChar, 'PHP')
                    .input('orderDate', sql.DateTime, now)
                    .input('paymentDate', sql.DateTime, now)
                    .input('shippingAddressId', sql.Int, shippingAddressId)
                    .input('deliveryType', sql.NVarChar, finalDeliveryType)
                    .input('serviceType', sql.NVarChar, serviceType)
                    .input('deliveryCost', sql.Decimal(10, 2), deliveryCost)
                    .input('paymentStatus', sql.NVarChar, linkedOrderPaymentStatusForInsert)
                    .input('stripeSessionId', sql.NVarChar, stripeSessionId || null)
                    .query(`
                        INSERT INTO Orders
                            (CustomerID, Status, TotalAmount, PaymentMethod, Currency, OrderDate, PaymentDate, ShippingAddressID, DeliveryType, ServiceType, DeliveryCost, PaymentStatus, StripeSessionID)
                        OUTPUT INSERTED.OrderID
                        VALUES
                            (@customerId, @status, @totalAmount, @paymentMethod, @currency, @orderDate, @paymentDate, @shippingAddressId, @deliveryType, @serviceType, @deliveryCost, @paymentStatus, @stripeSessionId)
                    `);

                const linkedOrderId = orderInsertResult.recordset?.[0]?.OrderID || null;
                if (linkedOrderId) {
                    const linkedOrderNumber = generateReferenceNumber(now, linkedOrderId);
                    const linkedTransactionId = generateTransactionId(now);
                    await pool.request()
                        .input('orderId', sql.Int, linkedOrderId)
                        .input('referenceNumber', sql.NVarChar, linkedOrderNumber)
                        .input('transactionId', sql.NVarChar, linkedTransactionId)
                        .query(`
                            UPDATE Orders
                            SET ReferenceNumber = @referenceNumber,
                                TransactionID = @transactionId
                            WHERE OrderID = @orderId
                        `);

                    // Add order items for customer dashboard visibility
                    for (const item of ordered) {
                        const pid = parseInt(item.productId || item.ProductID);
                        const qty = parseInt(item.quantity || 0);
                        const unitPrice = Number(item.unitPrice || item.price || 0);
                        const variationId = item.variationID || item.VariationID || null;
                        const itemName = String(item.name || '').replace(/\s*\(Stock:.*\)$/, '').trim() || 'Walk-in Item';

                        if (pid && qty > 0) {
                            await pool.request()
                                .input('orderId', sql.Int, linkedOrderId)
                                .input('productId', sql.Int, pid)
                                .input('quantity', sql.Int, qty)
                                .input('priceAtPurchase', sql.Decimal(10, 2), unitPrice)
                                .input('name', sql.NVarChar, itemName)
                                .input('variationId', sql.Int, variationId ? parseInt(variationId) : null)
                                .query(`
                                    INSERT INTO OrderItems (OrderID, ProductID, Quantity, PriceAtPurchase, Name, VariationID)
                                    VALUES (@orderId, @productId, @quantity, @priceAtPurchase, @name, @variationId)
                                `);
                        }
                    }

                    // Link the generated customer order to walk-in order
                    await pool.request()
                        .input('walkInOrderId', sql.Int, walkInOrderId)
                        .input('linkedOrderId', sql.Int, linkedOrderId)
                        .input('orderNumber', sql.NVarChar, linkedOrderNumber)
                        .input('transactionId', sql.NVarChar, linkedTransactionId)
                        .query(`
                            UPDATE WalkInOrders
                            SET LinkedOrderID = @linkedOrderId,
                                OrderNumber = @orderNumber,
                                TransactionID = @transactionId
                            WHERE BulkOrderID = @walkInOrderId
                        `);

                    // Email notification like customer receipt
                    try {
                        if (!gatewayAwaitingPayment) {
                        await sendgridHelper.sendOrderReceiptEmail(
                            linkedCustomer.Email,
                            linkedCustomer.FullName || customerName || 'Customer',
                            {
                                orderNumber: linkedOrderNumber,
                                totalAmount: finalOrderTotal,
                                paymentMethod: safePaymentMethod,
                                paymentStatus: linkedOrderPaymentStatusForInsert,
                                deliveryType: finalDeliveryType,
                                shippingCost: Number(deliveryCost || 0),
                                extraDeliveryFee: 0,
                                orderDate: now,
                                items: ordered.map(it => ({
                                    name: String(it.name || '').replace(/\s*\(Stock:.*\)$/, '').trim(),
                                    quantity: Number(it.quantity || 0),
                                    unitPrice: Number(it.unitPrice || 0),
                                    totalPrice: Number(it.unitPrice || 0) * Number(it.quantity || 0),
                                    image: null,
                                    variationName: null,
                                    color: null
                                })),
                                shippingAddress: {
                                    houseNumber: shipHouse || '',
                                    street: shipStreet || '',
                                    barangay: addressBarangay || '',
                                    city: addressCity || '',
                                    province: addressProvince || '',
                                    region: addressRegion || '',
                                    postalCode: addressPostalCode || '',
                                    country: 'Philippines'
                                }
                            }
                        );
                        }
                    } catch (mailErr) {
                        console.error('[WALKIN LINKED ORDER] Failed to send receipt email:', mailErr.message);
                    }
                }
            }

            // Deduct stock quantities using inventory-aware flow
            for (const item of ordered) {
                const pid = parseInt(item.productId || item.ProductID);
                const qty = parseInt(item.quantity || 0);
                const variationID = item.variationID || item.VariationID || null;

                if (pid && qty > 0) {
                    await decrementStockFromInventory(pid, qty, variationID, null);
                }
            }
            res.redirect('/Employee/Admin/WalkIn');
        } catch (err) {
            console.error('Error adding admin walk in order:', err);
            res.status(500).send('Failed to add walk in order');
        }
    });

    // Admin WalkIn: Proceed to On delivery
    router.post('/Employee/Admin/WalkIn/ProceedToDelivery/:id', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const id = parseInt(req.params.id, 10);
            if (!id) {
                return res.status(400).json({ success: false, message: 'Invalid walk-in order id' });
            }

            const confirmed = String(req.body?.confirmedGatewayTxnId ?? '').trim();
            if (confirmed) {
                await pool.request()
                    .input('txn', sql.NVarChar, confirmed)
                    .input('id', sql.Int, id)
                    .query(`UPDATE WalkInOrders SET TransactionID = @txn WHERE BulkOrderID = @id`);
                await pool.request()
                    .input('txn', sql.NVarChar, confirmed)
                    .input('id', sql.Int, id)
                    .query(`
                        UPDATE o SET o.TransactionID = @txn
                        FROM Orders o
                        INNER JOIN WalkInOrders w ON w.LinkedOrderID = o.OrderID
                        WHERE w.BulkOrderID = @id
                    `);
            }

            await pool.request()
                .input('id', sql.Int, id)
                .query(`UPDATE WalkInOrders SET Status = 'On delivery' WHERE BulkOrderID = @id`);

            // Sync to linked customer order so dashboard gets real-time status updates
            const linkResult = await pool.request()
                .input('id', sql.Int, id)
                .query(`SELECT LinkedOrderID FROM WalkInOrders WHERE BulkOrderID = @id`);
            const linkedOrderId = linkResult.recordset?.[0]?.LinkedOrderID || null;
            if (linkedOrderId) {
                await pool.request()
                    .input('orderId', sql.Int, linkedOrderId)
                    .query(`UPDATE Orders SET Status = 'Shipping' WHERE OrderID = @orderId`);
            }
            res.json({ success: true });
        } catch (err) {
            console.error('Error updating bulk order to delivery:', err);
            res.json({ success: false, message: 'Update failed' });
        }
    });

