            // Chart Data: Category Breakdown
            const chartDataStartRow = currentRow;
            worksheet.getRow(currentRow++).getCell(11).value = 'Category Breakdown';
            worksheet.getRow(currentRow - 1).getCell(11).font = { bold: true, size: 11 };
