    router.get('/api/cms/testimonials', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const top = parseInt(req.query.top) || 20;
            const result = await pool.request().query(`
                SELECT TOP (${top})
                    pr.ReviewID as id,
                    COALESCE(pr.ReviewerName, c.FullName, 'Anonymous') as name,
                    p.Name as profession, -- display product name as subtext
                    NULLIF(LTRIM(RTRIM(COALESCE(pr.Comment, pr.Title, ''))),'') as content,
                    pr.Rating as rating,
                    c.ProfileImage as imageUrl,
                    pr.IsActive as active,
                    pr.ShowAsTestimonial as showOnFrontend,
                    pr.CreatedAt as createdAt
                FROM ProductReviews pr
                LEFT JOIN Products p ON pr.ProductID = p.ProductID
                LEFT JOIN Customers c ON pr.CustomerID = c.CustomerID
                WHERE pr.IsActive IN (0,1)
                  AND NULLIF(LTRIM(RTRIM(COALESCE(pr.Comment, pr.Title, ''))),'') IS NOT NULL
                ORDER BY pr.CreatedAt DESC
            `);
            res.json({ success: true, testimonials: result.recordset });
        } catch (err) {
            console.error('Error fetching testimonials from reviews:', err);
            res.json({ success: false, message: 'Failed to retrieve testimonials.' });
        }
    });

