    // Employee/Admin Login POST route
    router.post('/auth/login', async (req, res) => {
        try {
            const { email, password, rememberMe } = req.body;
            const loginIdentifier = typeof email === 'string' ? email.trim() : '';

            console.log('=== LOGIN ATTEMPT ===');
            console.log('Login identifier:', loginIdentifier);
            console.log('Password provided:', password ? 'Yes' : 'No');

            if (!loginIdentifier || !password) {
                console.log('Missing login identifier or password');
                req.flash('error', 'Email or username and password are required.');
                if (loginIdentifier) req.flash('email', loginIdentifier);
                return res.redirect('/login');
            }

            console.log('Connecting to database...');
            await pool.connect();
            console.log('Database connected successfully');

            // Find user by email or username (case-insensitive)
            const userResult = await pool.request()
                .input('loginId', sql.NVarChar, loginIdentifier)
                .query(`
                    SELECT TOP 1 *
                    FROM Users
                    WHERE LOWER(LTRIM(RTRIM(Email))) = LOWER(@loginId)
                       OR LOWER(LTRIM(RTRIM(Username))) = LOWER(@loginId)
                `);

            const user = userResult.recordset[0];

            console.log('Login attempt for:', loginIdentifier);
            console.log('User found:', user ? 'Yes' : 'No');
            if (user) {
                console.log('User details:', {
                    UserID: user.UserID,
                    Username: user.Username,
                    Email: user.Email,
                    FullName: user.FullName,
                    RoleID: user.RoleID,
                    IsActive: user.IsActive
                });
            }

            if (!user) {
                req.flash('error', 'Invalid email, username, or password.');
                req.flash('email', loginIdentifier);
                return res.redirect('/login');
            }

            // Get password hash for verification
            const passwordResult = await pool.request()
                .input('userId', sql.Int, user.UserID)
                .query('SELECT PasswordHash FROM Users WHERE UserID = @userId');

            if (passwordResult.recordset.length === 0) {
                console.log('No password hash found for user');
                req.flash('error', 'Invalid email, username, or password.');
                req.flash('email', loginIdentifier);
                return res.redirect('/login');
            }

            const passwordHash = passwordResult.recordset[0].PasswordHash;
            console.log('Password hash found:', passwordHash ? 'Yes' : 'No');

            // Get role name from Roles table
            const roleResult = await pool.request()
                .input('roleId', sql.Int, user.RoleID)
                .query('SELECT RoleName FROM Roles WHERE RoleID = @roleId');

            if (roleResult.recordset.length === 0) {
                console.log('No role found for user');
                req.flash('error', 'User role not found. Please contact administrator.');
                return res.redirect('/login');
            }

            const roleName = roleResult.recordset[0].RoleName;
            console.log('Role name found:', roleName);

            if (!user.IsActive) {
                req.flash('error', 'Your account has been deactivated. Please contact administrator.');
                return res.redirect('/login');
            }

            // Verify password (handle bcrypt variants and minor input whitespace)
            let passwordMatch = false;
            const hasPasswordHash = typeof passwordHash === 'string' && passwordHash.length > 0;
            let normalizedHash = passwordHash;

            // Normalize legacy bcrypt prefixes from other ecosystems (e.g., $2y$, $2x$)
            if (hasPasswordHash && (passwordHash.startsWith('$2y$') || passwordHash.startsWith('$2x$'))) {
                normalizedHash = '$2b$' + passwordHash.slice(4);
            }

            if (hasPasswordHash && (normalizedHash.startsWith('$2a$') || normalizedHash.startsWith('$2b$'))) {
                // Primary compare with provided password
                passwordMatch = await bcrypt.compare(password, normalizedHash);
                // Fallback: if leading/trailing whitespace likely, try trimmed once
                if (!passwordMatch && typeof password === 'string' && password.trim() !== password) {
                    passwordMatch = await bcrypt.compare(password.trim(), normalizedHash);
                }
            } else if (hasPasswordHash) {
                // Plain text comparison (for backward compatibility)
                passwordMatch = (passwordHash === password) || (typeof password === 'string' && passwordHash === password.trim());
            }

            if (!passwordMatch) {
                // Log failed login attempt
                await logActivity(
                    user.UserID,
                    'LOGIN_FAILED',
                    'Users',
                    user.UserID,
                    `Failed login attempt - incorrect password from ${req.ip || 'unknown IP'}`
                );

                req.flash('error', 'Invalid email, username, or password.');
                req.flash('email', loginIdentifier);
                return res.redirect('/login');
            }

            // Update last login timestamp (used by Reports -> Masterlist)
            try {
                await pool.request()
                    .input('userId', sql.Int, user.UserID)
                    .query(`
                        UPDATE Users
                        SET
                            LastLogin = GETDATE(),
                            CreatedAt = ISNULL(CreatedAt, GETDATE())
                        WHERE UserID = @userId
                    `);
            } catch (lastLoginErr) {
                // Non-blocking: don't fail login if audit fields can't be updated
                console.error('Error updating Users.LastLogin:', lastLoginErr);
            }

            // Create session (using employee session middleware)
            // Clear any existing customer session data to prevent conflicts
            if (req.session.user && req.session.user.type === 'customer') {
                req.session.user = null;
                req.session.customerData = null;
            }

            const userData = {
                id: user.UserID,
                username: user.Username,
                fullName: user.FullName,
                email: user.Email,
                role: roleName,
                type: 'employee'
            };

            req.session.user = userData;

            // Log successful login
            await logActivity(
                user.UserID,
                'LOGIN',
                'Users',
                user.UserID.toString(),
                `Successful login from ${req.ip || 'unknown IP'}`
            );

            // Generate JWT tokens for API access
            let jwtTokens = null;
            try {
                jwtTokens = jwtUtils.generateTokenPair(userData);
                console.log('✅ JWT tokens generated for employee:', email);
            } catch (tokenError) {
                console.error('JWT token generation error:', tokenError);
                // Continue without JWT tokens - session auth will work
            }

            console.log('Login successful for:', email);
            console.log('User role:', roleName);

            // Check if this is an API request (for mobile/frontend)
            const isApiRequest = req.headers.accept && req.headers.accept.includes('application/json');

            if (isApiRequest) {
                return res.json({
                    success: true,
                    message: 'Login successful',
                    user: userData,
                    tokens: jwtTokens,
                    sessionId: req.sessionID
                });
            }

            // Ensure session is saved before redirecting (prevents lost session on redirect)
            return req.session.save((err) => {
                if (err) {
                    console.error('Session save error:', err);
                    req.flash('error', 'Session error, please try again.');
                    return res.redirect('/login');
                }
                // Redirect based on role for web interface
                const roleRedirects = {
                    Admin: '/Employee/AdminManager',
                    InventoryManager: '/Employee/InventoryManager',
                    TransactionManager: '/Employee/TransactionManager',
                    UserManager: '/Employee/UserManager',
                    OrderSupport: '/Employee/OrderSupport'
                };
                const target = roleRedirects[roleName] || '/';
                return res.redirect(target);
            });

        } catch (error) {
            console.error('Login error:', error);
            req.flash('error', 'An error occurred during login. Please try again.');
            res.redirect('/login');
        }
    });

    // Logout
    router.post('/auth/logout', (req, res) => {
        req.session.destroy((err) => {
            if (err) {
                console.error('Logout error:', err);
                return res.status(500).json({ success: false, message: 'Logout failed' });
            }
            res.json({ success: true, message: 'Logged out successfully' });
        });
    });

