    /**
     * Issue JWT pair from an existing customer session (used after Google redirect)
     * POST /api/auth/customer/sync-tokens
     */
    router.post('/api/auth/customer/sync-tokens', async (req, res) => {
        try {
            if (!req.session || !req.session.user || req.session.user.type !== 'customer') {
                return res.status(401).json({
                    success: false,
                    message: 'Not authenticated',
                    code: 'NOT_AUTHENTICATED'
                });
            }
            await ensureCustomerGoogleAuthColumns();
            let requiresPasswordSetup = false;
            try {
                const pr = await pool.request()
                    .input('id', sql.Int, req.session.user.id)
                    .query(`
                        SELECT PasswordSetupCompleted
                        FROM Customers
                        WHERE CustomerID = @id AND IsActive = 1
                    `);
                requiresPasswordSetup = customerRequiresPasswordSetup(pr.recordset[0]);
            } catch (e) {
                console.error('[GOOGLE AUTH] sync-tokens password flag:', e.message);
            }
            const customerData = { ...req.session.user, requiresPasswordSetup };
            req.session.user = customerData;
            try {
                await new Promise((resolve, reject) => {
                    req.session.save((err) => (err ? reject(err) : resolve()));
                });
            } catch (saveErr) {
                console.error('[GOOGLE AUTH] sync-tokens session save:', saveErr.message);
            }
            let jwtTokens = null;
            try {
                jwtTokens = jwtUtils.generateTokenPair(customerData);
            } catch (e) {
                console.error('[GOOGLE AUTH] sync-tokens JWT:', e.message);
            }
            res.setHeader('Access-Control-Allow-Credentials', 'true');
            res.json({
                success: true,
                user: customerData,
                tokens: jwtTokens,
                sessionId: req.sessionID
            });
        } catch (err) {
            console.error('sync-tokens error:', err);
            res.status(500).json({ success: false, message: 'Token sync failed' });
        }
    });

    /**
     * Start Google OAuth (customer)
     * GET /api/auth/google
     */
    router.get('/api/auth/google', (req, res, next) => {
        if (!process.env.GOOGLE_CLIENT_ID || !process.env.GOOGLE_CLIENT_SECRET) {
            return res.status(503).json({
                success: false,
                message: 'Google sign-in is not configured.'
            });
        }
        passport.authenticate('google-customer', { scope: ['profile', 'email'], session: false })(req, res, next);
    });

    /**
     * Google OAuth callback
     * GET /api/auth/google/callback
     */
    router.get('/api/auth/google/callback',
        (req, res, next) => {
            const failUrl = `${customerOAuthFrontendBaseUrl()}/login?google=error`;
            passport.authenticate('google-customer', { session: false, failureRedirect: failUrl })(req, res, next);
        },
        async (req, res) => {
            try {
                const customerData = req.user;
                if (!customerData) {
                    return res.redirect(`${customerOAuthFrontendBaseUrl()}/login?google=error`);
                }
                if (req.session.user && req.session.user.type === 'employee') {
                    req.session.user = null;
                }
                req.session.user = customerData;
                req.session.customerData = customerData;
                await new Promise((resolve, reject) => {
                    req.session.save((err) => (err ? reject(err) : resolve()));
                });
                res.redirect(`${customerOAuthFrontendBaseUrl()}/login?google=success`);
            } catch (e) {
                console.error('[GOOGLE AUTH] Callback session save:', e);
                res.redirect(`${customerOAuthFrontendBaseUrl()}/login?google=error`);
            }
        }
    );

    /**
     * Customer Login (API endpoint)
     * POST /api/auth/customer/login
     */
    router.post('/api/auth/customer/login', async (req, res) => {
        try {
            const { email, password, rememberMe } = req.body;

            await ensureCustomerGoogleAuthColumns();

            console.log('=== CUSTOMER LOGIN ATTEMPT ===');
            console.log('Email:', email);
            console.log('Password provided:', password ? 'Yes' : 'No');

            if (!email || !password) {
                console.log('Missing email or password');
                return res.status(400).json({
                    success: false,
                    message: 'Email and password are required.',
                    code: 'MISSING_CREDENTIALS'
                });
            }

            console.log('Connecting to database...');
            await pool.connect();
            console.log('Database connected successfully');

            console.log('Searching for customer with email:', email);

            // Find customer by email using plain text query
            const allCustomersResult = await pool.request()
                .input('email', sql.NVarChar, email)
                .query(`
                    SELECT 
                        CustomerID,
                        Email,
                        FullName,
                        PhoneNumber,
                        IsActive,
                        CreatedAt
                    FROM Customers 
                    WHERE Email = @email
                `);

            console.log('Customer query result:', allCustomersResult.recordset.length);

            // Customer data is already plain text
            const customer = allCustomersResult.recordset[0] || null;
            console.log('Customer found:', customer ? 'Yes' : 'No');
            if (customer) {
                console.log('Customer ID:', customer.CustomerID);
                console.log('Customer Email:', customer.Email);
                console.log('Customer IsActive:', customer.IsActive);
            }

            if (!customer) {
                console.log('Customer not found with email:', email);
                return res.status(401).json({
                    success: false,
                    message: 'Invalid email or password.',
                    code: 'INVALID_CREDENTIALS'
                });
            }

            // Check if customer account is inactive
            if (!customer.IsActive) {
                console.log('Customer account is inactive');
                return res.status(403).json({
                    success: false,
                    message: 'Your account has been deactivated. Please contact customer support.',
                    code: 'ACCOUNT_INACTIVE'
                });
            }

            // Get password hash for verification
            const passwordResult = await pool.request()
                .input('customerId', sql.Int, customer.CustomerID)
                .query('SELECT PasswordHash FROM Customers WHERE CustomerID = @customerId');

            const passwordHash = passwordResult.recordset[0].PasswordHash;

            if (passwordHash == null || passwordHash === '') {
                return res.status(401).json({
                    success: false,
                    message: 'This account uses Google sign-in. Please use Continue with Google.',
                    code: 'OAUTH_ONLY'
                });
            }

            // Verify password using bcrypt
            console.log('Verifying password...');
            const passwordMatch = await bcrypt.compare(password, passwordHash);
            console.log('Password match result:', passwordMatch);
            if (!passwordMatch) {
                console.log('Password verification failed');
                return res.status(401).json({
                    success: false,
                    message: 'Incorrect password. Please check your password and try again.',
                    code: 'INCORRECT_PASSWORD'
                });
            }

            console.log('Password verification successful!');

            // Update last login timestamp
            await pool.request()
                .input('customerId', sql.Int, customer.CustomerID)
                .query('UPDATE Customers SET LastLogin = GETDATE() WHERE CustomerID = @customerId');

            // Keep Users.LastLogin in sync when a customer also has a Users record
            try {
                await pool.request()
                    .input('email', sql.NVarChar, customer.Email)
                    .query(`
                        UPDATE Users
                        SET
                            LastLogin = GETDATE(),
                            CreatedAt = ISNULL(CreatedAt, GETDATE())
                        WHERE Email = @email
                    `);
            } catch (lastLoginErr) {
                // Non-blocking: don't fail login if audit fields can't be updated
                console.error('Error updating Users.LastLogin for customer:', lastLoginErr);
            }

            try {
                await pool.request()
                    .input('customerId', sql.Int, customer.CustomerID)
                    .query('UPDATE Customers SET PasswordSetupCompleted = 1 WHERE CustomerID = @customerId');
            } catch (e) {
                /* column may not exist on unmigrated DB */
            }

            // Create customer session data
            const customerData = {
                id: customer.CustomerID,
                fullName: customer.FullName,
                email: customer.Email,
                phoneNumber: customer.PhoneNumber,
                role: 'Customer',
                type: 'customer',
                profileImage: customer.ProfileImage,
                requiresPasswordSetup: false
            };

            // Store in session (using customer session middleware)
            // Clear any existing employee session data to prevent conflicts
            if (req.session.user && req.session.user.type === 'employee') {
                req.session.user = null;
            }

            req.session.user = customerData;
            req.session.customerData = customerData;

            // Explicitly save session to ensure cookie is set
            // This is important for cross-origin requests
            await new Promise((resolve, reject) => {
                req.session.save((err) => {
                    if (err) {
                        console.error('❌ Session save error:', err);
                        reject(err);
                    } else {
                        console.log('✅ Session saved successfully');
                        console.log('   Session ID:', req.sessionID);
                        console.log('   Cookie will be set with:', {
                            secure: req.session.cookie.secure,
                            sameSite: req.session.cookie.sameSite,
                            httpOnly: req.session.cookie.httpOnly
                        });
                        resolve();
                    }
                });
            });

            // Generate JWT tokens
            let jwtTokens = null;

            try {
                // Generate JWT token pair
                jwtTokens = jwtUtils.generateTokenPair(customerData);
                console.log('✅ JWT tokens generated successfully');
            } catch (tokenError) {
                console.error('JWT token creation error:', tokenError);
                // Continue without tokens - session auth will work
            }

            // Set additional headers to ensure cookie is set properly
            res.setHeader('Access-Control-Allow-Credentials', 'true');

            // Return success response for frontend
            res.json({
                success: true,
                message: 'Login successful',
                user: customerData,
                tokens: jwtTokens,
                sessionId: req.sessionID,
                persistentLogin: rememberMe
            });

        } catch (err) {
            console.error('=== CUSTOMER LOGIN ERROR ===');
            console.error('Error type:', err.name);
            console.error('Error message:', err.message);
            console.error('Error stack:', err.stack);
            console.error('=============================');
            res.status(500).json({
                success: false,
                message: 'An error occurred during login. Please try again.',
                code: 'SERVER_ERROR'
            });
        }
    });

    /**
     * JWT Token Refresh (API endpoint)
     * POST /api/auth/refresh-token
     */
    router.post('/api/auth/refresh-token', async (req, res) => {
        try {
            const { refreshToken } = req.body;

            if (!refreshToken) {
                return res.status(400).json({
                    success: false,
                    message: 'Refresh token is required',
                    code: 'MISSING_REFRESH_TOKEN'
                });
            }

            // Verify the refresh token
            const decoded = jwtUtils.verifyToken(refreshToken);

            if (decoded.tokenType !== 'refresh') {
                return res.status(401).json({
                    success: false,
                    message: 'Invalid refresh token type',
                    code: 'INVALID_TOKEN_TYPE'
                });
            }

            // Get fresh user data from database
            await pool.connect();
            let userData = null;

            if (decoded.type === 'customer') {
                const result = await pool.request()
                    .input('customerId', sql.Int, decoded.id)
                    .query(`
                        SELECT CustomerID, FullName, Email, PhoneNumber, ProfileImage
                        FROM Customers 
                        WHERE CustomerID = @customerId AND IsActive = 1
                    `);

                if (result.recordset.length > 0) {
                    const customer = result.recordset[0];
                    const decryptedCustomer = TransparentEncryptionService.processCustomerForDisplay(customer);
                    userData = {
                        id: customer.CustomerID,
                        fullName: decryptedCustomer.FullName,
                        email: decryptedCustomer.Email,
                        phoneNumber: decryptedCustomer.PhoneNumber,
                        role: 'Customer',
                        type: 'customer',
                        profileImage: customer.ProfileImage
                    };
                }
            } else if (decoded.type === 'employee') {
                const result = await pool.request()
                    .input('userId', sql.Int, decoded.id)
                    .query(`
                        SELECT u.UserID, u.Username, u.FullName, u.Email, r.RoleName
                        FROM Users u
                        LEFT JOIN Roles r ON u.RoleID = r.RoleID
                        WHERE u.UserID = @userId AND u.IsActive = 1
                    `);

                if (result.recordset.length > 0) {
                    const user = result.recordset[0];
                    const decryptedUser = TransparentEncryptionService.processUserForDisplay(user);
                    userData = {
                        id: user.UserID,
                        username: decryptedUser.Username,
                        fullName: decryptedUser.FullName,
                        email: decryptedUser.Email,
                        role: user.RoleName,
                        type: 'employee'
                    };
                }
            }

            if (!userData) {
                return res.status(401).json({
                    success: false,
                    message: 'User not found or inactive',
                    code: 'USER_NOT_FOUND'
                });
            }

            // Generate new access token
            const newAccessToken = jwtUtils.generateAccessToken(userData);

            res.json({
                success: true,
                message: 'Token refreshed successfully',
                accessToken: newAccessToken,
                tokenType: 'Bearer',
                expiresIn: process.env.JWT_ACCESS_TOKEN_EXPIRES_IN || '15m'
            });

        } catch (error) {
            console.error('Token refresh error:', error);

            if (error.name === 'TokenExpiredError') {
                return res.status(401).json({
                    success: false,
                    message: 'Refresh token expired',
                    code: 'REFRESH_TOKEN_EXPIRED'
                });
            } else if (error.name === 'JsonWebTokenError') {
                return res.status(401).json({
                    success: false,
                    message: 'Invalid refresh token',
                    code: 'INVALID_REFRESH_TOKEN'
                });
            } else {
                return res.status(500).json({
                    success: false,
                    message: 'Token refresh failed',
                    code: 'REFRESH_FAILED'
                });
            }
        }
    });

    /**
     * Customer Registration with OTP Verification (API endpoint)
     * POST /api/auth/customer/register-with-otp
     */
    router.post('/api/auth/customer/register-with-otp', async (req, res) => {
        try {
            const { fullName, email, phoneNumber, password, confirmPassword, otp } = req.body;

            console.log('📧 OTP Registration attempt for email:', email);

            // Validation
            if (!fullName || !email || !password || !otp) {
                return res.status(400).json({
                    success: false,
                    message: 'Full name, email, password, and OTP are required.',
                    code: 'MISSING_REQUIRED_FIELDS'
                });
            }

            if (password !== confirmPassword) {
                return res.status(400).json({
                    success: false,
                    message: 'Passwords do not match.',
                    code: 'PASSWORD_MISMATCH'
                });
            }

            if (password.length < 6) {
                return res.status(400).json({
                    success: false,
                    message: 'Password must be at least 6 characters long.',
                    code: 'PASSWORD_TOO_SHORT'
                });
            }

            if (isCommonPassword(password)) {
                return res.status(400).json({
                    success: false,
                    message: 'This password is too common and easy to guess. Please choose something more unique.',
                    code: 'COMMON_PASSWORD'
                });
            }

            // Email validation
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(email)) {
                return res.status(400).json({
                    success: false,
                    message: 'Please enter a valid email address.',
                    code: 'INVALID_EMAIL'
                });
            }

            await pool.connect();

            // First verify the OTP
            console.log('🔐 Verifying OTP for email:', email);
            const otpResult = await pool.request()
                .input('email', sql.NVarChar, email)
                .input('otp', sql.NVarChar, otp)
                .query(`
                    SELECT OTP, ExpiresAt 
                    FROM OTPVerification 
                    WHERE Email = @email AND OTP = @otp AND ExpiresAt > GETDATE()
                `);

            if (otpResult.recordset.length === 0) {
                console.log('❌ Invalid or expired OTP for email:', email);
                return res.status(400).json({
                    success: false,
                    message: 'Invalid or expired OTP. Please request a new OTP.',
                    code: 'INVALID_OTP'
                });
            }

            console.log('✅ OTP verified successfully for email:', email);

            // Check for duplicate email (double check)
            const existing = await pool.request()
                .input('email', sql.NVarChar, email)
                .query('SELECT CustomerID FROM Customers WHERE Email = @email');

            if (existing.recordset.length > 0) {
                return res.status(409).json({
                    success: false,
                    message: 'An account with this email already exists.',
                    code: 'EMAIL_ALREADY_EXISTS'
                });
            }

            // Hash password
            const saltRounds = 12;
            const hash = await bcrypt.hash(password, saltRounds);

            // Insert new customer
            const insertResult = await pool.request()
                .input('fullName', sql.NVarChar, fullName.trim())
                .input('email', sql.NVarChar, email.toLowerCase().trim())
                .input('phoneNumber', sql.NVarChar, phoneNumber || null)
                .input('passwordHash', sql.NVarChar, hash)
                .query(`
                    INSERT INTO Customers (FullName, Email, PhoneNumber, PasswordHash, IsActive, CreatedAt) 
                    OUTPUT INSERTED.CustomerID
                    VALUES (@fullName, @email, @phoneNumber, @passwordHash, 1, GETDATE())
                `);

            const newCustomerId = insertResult.recordset[0].CustomerID;
            console.log('✅ New customer created with ID:', newCustomerId);

            // Clean up the OTP record
            await pool.request()
                .input('email', sql.NVarChar, email)
                .query('DELETE FROM OTPVerification WHERE Email = @email');

            console.log('✅ OTP record cleaned up for email:', email);

            // Create customer session data
            const customerData = {
                id: newCustomerId,
                fullName: fullName.trim(),
                email: email.toLowerCase().trim(),
                phoneNumber: phoneNumber,
                role: 'Customer',
                type: 'customer',
                isEmailVerified: true, // OTP verification confirms email
                requiresPasswordSetup: false
            };

            // Store in session
            req.session.user = customerData;
            req.session.customerData = customerData;

            // Generate JWT tokens for new customer
            let jwtTokens = null;
            try {
                jwtTokens = jwtUtils.generateTokenPair(customerData);
                console.log('✅ JWT tokens generated for new customer');
            } catch (tokenError) {
                console.error('JWT token creation error:', tokenError);
                // Continue without tokens - session auth will work
            }

            console.log('🎉 Registration completed successfully for:', email);

            res.status(201).json({
                success: true,
                message: 'Registration successful! Welcome to DesignXcel!',
                user: customerData,
                tokens: jwtTokens
            });

        } catch (err) {
            console.error('❌ OTP Registration error:', err);
            console.error('Error details:', err.message);
            console.error('Error stack:', err.stack);
            res.status(500).json({
                success: false,
                message: 'An error occurred during registration. Please try again.',
                code: 'SERVER_ERROR'
            });
        }
    });
