    /**
     * Check Authentication Status
     * GET /api/auth/status
     */
    router.get('/api/auth/status', async (req, res) => {
        try {
            if (process.env.DEBUG_AUTH === 'true') {
                console.log('Auth status check:', {
                    hasSession: !!req.session,
                    hasUser: !!(req.session && req.session.user),
                    sessionId: req.session?.id,
                    userType: req.session?.user?.type
                });
            }

            if (!req.session || !req.session.user) {
                // Check if session exists but user is not set (session might be empty)
                if (req.session && !req.session.user) {
                    console.log('⚠️ Session exists but user is not set');
                }
                return res.json({
                    success: false,
                    authenticated: false,
                    message: 'Not authenticated'
                });
            }

            // For customer routes, only return customer user data
            // Filter out any employee data that might have leaked
            const sessionUser = req.session.user;
            if (sessionUser.type === 'employee') {
                // This is an employee session, but we're on a customer route
                // This shouldn't happen, but clear it to prevent conflicts
                console.log('⚠️ Employee session detected on customer route, clearing...');
                req.session.user = null;
                return res.json({
                    success: false,
                    authenticated: false,
                    message: 'Not authenticated'
                });
            }

            // Ensure credentials header is set
            res.setHeader('Access-Control-Allow-Credentials', 'true');

            let requiresPasswordSetup = Boolean(sessionUser.requiresPasswordSetup);
            if (sessionUser.type === 'customer' && sessionUser.id) {
                try {
                    await ensureCustomerGoogleAuthColumns();
                    const pr = await pool.request()
                        .input('id', sql.Int, sessionUser.id)
                        .query(`
                            SELECT PasswordSetupCompleted
                            FROM Customers
                            WHERE CustomerID = @id AND IsActive = 1
                        `);
                    requiresPasswordSetup = customerRequiresPasswordSetup(pr.recordset[0]);
                } catch (e) {
                    console.error('[AUTH] status password flag:', e.message);
                }
            }

            const userOut = { ...sessionUser, requiresPasswordSetup };
            req.session.user = userOut;

            res.json({
                success: true,
                authenticated: true,
                user: userOut,
                sessionId: req.sessionID
            });
        } catch (err) {
            console.error('Auth status check error:', err);
            res.status(500).json({
                success: false,
                message: 'Error checking authentication status'
            });
        }
    });

    /**
     * Forgot Password
     * POST /api/auth/forgot-password
     */
    router.post('/api/auth/forgot-password', async (req, res) => {
        try {
            const { email } = req.body;

            if (!email) {
                return res.status(400).json({
                    success: false,
                    message: 'Email is required'
                });
            }

            await pool.connect();

            // Check if user exists
            const userResult = await pool.request()
                .input('email', sql.VarChar(255), email)
                .query(`
                    SELECT CustomerID, FullName, Email 
                    FROM Customers 
                    WHERE Email = @email AND IsActive = 1
                `);

            if (userResult.recordset.length === 0) {
                return res.status(404).json({
                    success: false,
                    message: 'No account found with this email address'
                });
            }

            const user = userResult.recordset[0];

            // Generate reset token using crypto for better security
            const crypto = require('crypto');
            const resetToken = crypto.randomBytes(32).toString('hex');
            const resetTokenExpiry = new Date(Date.now() + 3600000); // 1 hour from now

            // Store reset token in database
            try {
                // First, clean up any existing tokens for this user
                await pool.request()
                    .input('customerId', sql.Int, user.CustomerID)
                    .query(`
                        DELETE FROM PasswordResetTokens 
                        WHERE CustomerID = @customerId OR ExpiresAt < GETDATE()
                    `);

                // Insert new reset token
                await pool.request()
                    .input('customerId', sql.Int, user.CustomerID)
                    .input('token', sql.NVarChar(255), resetToken)
                    .input('expiresAt', sql.DateTime2, resetTokenExpiry)
                    .query(`
                        INSERT INTO PasswordResetTokens (CustomerID, Token, ExpiresAt)
                        VALUES (@customerId, @token, @expiresAt)
                    `);

                console.log(`✅ Password reset token stored for ${email}. Token: ${resetToken}`);
            } catch (dbError) {
                console.error('❌ Error storing reset token:', dbError);
                // Continue with email sending even if token storage fails
            }

            // Send password reset email using SendGrid (works on Railway)
            const { sendPasswordResetEmail } = require('./utils/sendgridHelper');

            console.log('📧 Password reset email config check:');
            console.log('  - SENDGRID_API_KEY:', process.env.SENDGRID_API_KEY ? 'Set' : 'Not set');
            console.log('  - OTP_EMAIL_USER:', process.env.OTP_EMAIL_USER ? 'Set' : 'Not set');
            console.log('  - FRONTEND_URL:', process.env.FRONTEND_URL ? 'Set' : 'Not set');

            // Send password reset email via SendGrid
            const emailResult = await sendPasswordResetEmail(email, user.FullName, resetToken);

            if (!emailResult.success) {
                return res.status(500).json({
                    success: false,
                    message: emailResult.message || 'Failed to send password reset email'
                });
            }

            console.log(`✅ Password reset email sent to ${email}`);

            res.json({
                success: true,
                message: 'Password reset instructions have been sent to your email address',
                // In development, you might want to return the token for testing
                ...(process.env.NODE_ENV === 'development' && { resetToken, resetLink: emailResult.resetLink })
            });

        } catch (err) {
            console.error('Forgot password error:', err);
            res.status(500).json({
                success: false,
                message: 'An error occurred while processing your request'
            });
        }
    });

    /**
     * Reset Password
     * POST /api/auth/reset-password
     */
    router.post('/api/auth/reset-password', async (req, res) => {
        try {
            const { token, password, confirmPassword } = req.body;

            if (!token || !password || !confirmPassword) {
                return res.status(400).json({
                    success: false,
                    message: 'Token, password, and confirm password are required'
                });
            }

            if (password !== confirmPassword) {
                return res.status(400).json({
                    success: false,
                    message: 'Passwords do not match'
                });
            }

            if (password.length < 8) {
                return res.status(400).json({
                    success: false,
                    message: 'Password must be at least 8 characters long'
                });
            }

            if (isCommonPassword(password)) {
                return res.status(400).json({
                    success: false,
                    message: 'This password is too common and easy to guess. Please choose something more unique.'
                });
            }

            await pool.connect();

            // Validate the reset token from database
            const tokenResult = await pool.request()
                .input('token', sql.NVarChar(255), token)
                .query(`
                    SELECT prt.TokenID, prt.CustomerID, prt.ExpiresAt, prt.IsUsed,
                           c.Email, c.FullName
                    FROM PasswordResetTokens prt
                    INNER JOIN Customers c ON prt.CustomerID = c.CustomerID
                    WHERE prt.Token = @token AND prt.IsUsed = 0
                `);

            if (tokenResult.recordset.length === 0) {
                return res.status(400).json({
                    success: false,
                    message: 'Invalid or expired reset token'
                });
            }

            const tokenData = tokenResult.recordset[0];

            // Check if token is expired
            if (new Date() > new Date(tokenData.ExpiresAt)) {
                return res.status(400).json({
                    success: false,
                    message: 'Reset token has expired. Please request a new one.'
                });
            }

            // Hash the new password
            const bcrypt = require('bcryptjs');
            const saltRounds = 12;
            const hashedPassword = await bcrypt.hash(password, saltRounds);

            // Update the user's password
            await pool.request()
                .input('customerId', sql.Int, tokenData.CustomerID)
                .input('passwordHash', sql.NVarChar, hashedPassword)
                .query(`
                    UPDATE Customers 
                    SET PasswordHash = @passwordHash
                    WHERE CustomerID = @customerId
                `);

            // Mark the token as used
            await pool.request()
                .input('tokenId', sql.Int, tokenData.TokenID)
                .query(`
                    UPDATE PasswordResetTokens 
                    SET IsUsed = 1, UsedAt = GETDATE()
                    WHERE TokenID = @tokenId
                `);

            console.log(`✅ Password reset successful for customer ${tokenData.CustomerID} (${tokenData.Email})`);

            res.json({
                success: true,
                message: 'Password has been reset successfully'
            });

        } catch (err) {
            console.error('Reset password error:', err);
            res.status(500).json({
                success: false,
                message: 'An error occurred while resetting your password'
            });
        }
    });
    /**
     * User (Employee/Admin) Forgot Password
     * POST /api/auth/forgot-password-user
     */
    router.post('/api/auth/forgot-password-user', async (req, res) => {
        try {
            const { email } = req.body;

            if (!email) {
                return res.status(400).json({
                    success: false,
                    message: 'Email is required'
                });
            }

            await pool.connect();

            // Check if user exists in Users table
            const userResult = await pool.request()
                .input('email', sql.VarChar(255), email)
                .query(`
                    SELECT u.UserID, u.FullName, u.Email, u.IsActive, r.RoleName
                    FROM Users u
                    INNER JOIN Roles r ON u.RoleID = r.RoleID
                    WHERE u.Email = @email AND u.IsActive = 1
                `);

            if (userResult.recordset.length === 0) {
                // Don't reveal if email exists for security
                return res.json({
                    success: true,
                    message: 'If an account with this email exists, password reset instructions have been sent.'
                });
            }

            const user = userResult.recordset[0];

            // Generate reset token using crypto for better security
            const crypto = require('crypto');
            const resetToken = crypto.randomBytes(32).toString('hex');
            const resetTokenExpiry = new Date(Date.now() + 3600000); // 1 hour from now

            // Store reset token in database
            // Check if UserPasswordResetTokens table exists, if not create it on the fly
            try {
                // First, clean up any existing tokens for this user
                await pool.request()
                    .input('userId', sql.Int, user.UserID)
                    .query(`
                        DELETE FROM UserPasswordResetTokens 
                        WHERE UserID = @userId OR ExpiresAt < GETDATE()
                    `);

                // Insert new reset token
                await pool.request()
                    .input('userId', sql.Int, user.UserID)
                    .input('token', sql.NVarChar(255), resetToken)
                    .input('expiresAt', sql.DateTime2, resetTokenExpiry)
                    .query(`
                        INSERT INTO UserPasswordResetTokens (UserID, Token, ExpiresAt)
                        VALUES (@userId, @token, @expiresAt)
                    `);

                console.log(`✅ Password reset token stored for user ${email}. Token: ${resetToken}`);
            } catch (dbError) {
                // If table doesn't exist, create it
                if (dbError.message && dbError.message.includes('Invalid object name')) {
                    console.log('Creating UserPasswordResetTokens table...');
                    try {
                        await pool.request().query(`
                            CREATE TABLE UserPasswordResetTokens (
                                TokenID INT IDENTITY(1,1) PRIMARY KEY,
                                UserID INT NOT NULL,
                                Token NVARCHAR(255) NOT NULL,
                                ExpiresAt DATETIME2 NOT NULL,
                                IsUsed BIT DEFAULT 0,
                                UsedAt DATETIME2 NULL,
                                CreatedAt DATETIME2 DEFAULT GETDATE(),
                                FOREIGN KEY (UserID) REFERENCES Users(UserID) ON DELETE CASCADE
                            );
                            CREATE INDEX IX_UserPasswordResetTokens_Token ON UserPasswordResetTokens(Token);
                            CREATE INDEX IX_UserPasswordResetTokens_UserID ON UserPasswordResetTokens(UserID);
                        `);

                        // Retry inserting the token
                        await pool.request()
                            .input('userId', sql.Int, user.UserID)
                            .input('token', sql.NVarChar(255), resetToken)
                            .input('expiresAt', sql.DateTime2, resetTokenExpiry)
                            .query(`
                                INSERT INTO UserPasswordResetTokens (UserID, Token, ExpiresAt)
                                VALUES (@userId, @token, @expiresAt)
                            `);
                        console.log(`✅ UserPasswordResetTokens table created and token stored for ${email}`);
                    } catch (createError) {
                        console.error('❌ Error creating UserPasswordResetTokens table:', createError);
                        // Continue with email sending even if token storage fails
                    }
                } else {
                    console.error('❌ Error storing reset token:', dbError);
                }
            }

            // Send password reset email using SendGrid
            const { sendUserPasswordResetEmail } = require('./utils/sendgridHelper');

            console.log('📧 User password reset email config check:');
            console.log('  - SENDGRID_API_KEY:', process.env.SENDGRID_API_KEY ? 'Set' : 'Not set');
            console.log('  - OTP_EMAIL_USER:', process.env.OTP_EMAIL_USER ? 'Set' : 'Not set');
            console.log('  - FRONTEND_URL:', process.env.FRONTEND_URL ? 'Set' : 'Not set');

            // Send password reset email via SendGrid
            const emailResult = await sendUserPasswordResetEmail(email, user.FullName, resetToken, user.RoleName);

            if (!emailResult.success) {
                console.error('Failed to send password reset email:', emailResult.message);
                // Still return success to not reveal if email exists
                return res.json({
                    success: true,
                    message: 'If an account with this email exists, password reset instructions have been sent.'
                });
            }

            console.log(`✅ Password reset email sent to ${email}`);

            res.json({
                success: true,
                message: 'Password reset instructions have been sent to your email address',
                // In development, you might want to return the token for testing
                ...(process.env.NODE_ENV === 'development' && { resetToken, resetLink: emailResult.resetLink })
            });

        } catch (err) {
            console.error('Forgot password error:', err);
            res.json({
                success: true,
                message: 'If an account with this email exists, password reset instructions have been sent.'
            });
        }
    });

