    // Add customer address
    router.post('/api/customer/addresses', isAuthenticated, async (req, res) => {
        const customerId = req.session.user && req.session.user.id;
        if (!customerId) {
            return res.status(401).json({ success: false, message: 'Not authenticated.' });
        }
        try {
            await pool.connect();
            const { label, houseNumber, street, barangay, city, province, region, postalCode, country, isDefault } = req.body;

            // Encrypt address data using TransparentEncryptionService
            const encryptedAddressData = TransparentEncryptionService.processAddressForStorage({
                Label: label,
                HouseNumber: houseNumber,
                Street: street,
                Barangay: barangay,
                City: city,
                Province: province,
                Region: region,
                PostalCode: postalCode,
                Country: country || 'Philippines'
            });

            // If this is set as default, unset other defaults first
            if (isDefault) {
                await pool.request()
                    .input('customerId', sql.Int, customerId)
                    .query('UPDATE CustomerAddresses SET IsDefault = 0 WHERE CustomerID = @customerId');
            }

            const result = await pool.request()
                .input('customerId', sql.Int, customerId)
                .input('label', sql.NVarChar, encryptedAddressData.Label)
                .input('houseNumber', sql.NVarChar, encryptedAddressData.HouseNumber)
                .input('street', sql.NVarChar, encryptedAddressData.Street)
                .input('barangay', sql.NVarChar, encryptedAddressData.Barangay)
                .input('city', sql.NVarChar, encryptedAddressData.City)
                .input('province', sql.NVarChar, encryptedAddressData.Province)
                .input('region', sql.NVarChar, encryptedAddressData.Region)
                .input('postalCode', sql.NVarChar, encryptedAddressData.PostalCode)
                .input('country', sql.NVarChar, encryptedAddressData.Country)
                .input('isDefault', sql.Bit, isDefault ? 1 : 0)
                .query(`
                    INSERT INTO CustomerAddresses (CustomerID, Label, HouseNumber, Street, Barangay, City, Province, Region, PostalCode, Country, IsDefault)
                    VALUES (@customerId, @label, @houseNumber, @street, @barangay, @city, @province, @region, @postalCode, @country, @isDefault)
                `);

            return res.json({ success: true, message: 'Address added successfully.' });
        } catch (err) {
            console.error('Error adding customer address:', err);
            return res.status(500).json({ success: false, message: 'Failed to add address.' });
        }
    });

    // Update customer address
    router.put('/api/customer/addresses/:addressId', isAuthenticated, async (req, res) => {
        const customerId = req.session.user && req.session.user.id;
        const addressId = req.params.addressId;
        if (!customerId) {
            return res.status(401).json({ success: false, message: 'Not authenticated.' });
        }
        try {
            await pool.connect();
            const { label, houseNumber, street, barangay, city, province, region, postalCode, country, isDefault } = req.body;

            // Encrypt address data using TransparentEncryptionService
            const encryptedAddressData = TransparentEncryptionService.processAddressForStorage({
                Label: label,
                HouseNumber: houseNumber,
                Street: street,
                Barangay: barangay,
                City: city,
                Province: province,
                Region: region,
                PostalCode: postalCode,
                Country: country || 'Philippines'
            });

            // If this is set as default, unset other defaults first
            if (isDefault) {
                await pool.request()
                    .input('customerId', sql.Int, customerId)
                    .query('UPDATE CustomerAddresses SET IsDefault = 0 WHERE CustomerID = @customerId');
            }

            await pool.request()
                .input('addressId', sql.Int, addressId)
                .input('customerId', sql.Int, customerId)
                .input('label', sql.NVarChar, encryptedAddressData.Label)
                .input('houseNumber', sql.NVarChar, encryptedAddressData.HouseNumber)
                .input('street', sql.NVarChar, encryptedAddressData.Street)
                .input('barangay', sql.NVarChar, encryptedAddressData.Barangay)
                .input('city', sql.NVarChar, encryptedAddressData.City)
                .input('province', sql.NVarChar, encryptedAddressData.Province)
                .input('region', sql.NVarChar, encryptedAddressData.Region)
                .input('postalCode', sql.NVarChar, encryptedAddressData.PostalCode)
                .input('country', sql.NVarChar, encryptedAddressData.Country)
                .input('isDefault', sql.Bit, isDefault ? 1 : 0)
                .query(`
                    UPDATE CustomerAddresses 
                    SET Label = @label, HouseNumber = @houseNumber, Street = @street, Barangay = @barangay, 
                        City = @city, Province = @province, Region = @region, PostalCode = @postalCode, 
                        Country = @country, IsDefault = @isDefault
                    WHERE AddressID = @addressId AND CustomerID = @customerId
                `);

            return res.json({ success: true, message: 'Address updated successfully.' });
        } catch (err) {
            console.error('Error updating customer address:', err);
            return res.status(500).json({ success: false, message: 'Failed to update address.' });
        }
    });

    // Delete customer address
    router.delete('/api/customer/addresses/:addressId', isAuthenticated, async (req, res) => {
        let customerId, addressId, addressIdParam;

        try {
            // TEST: Return immediately to verify route is hit
            // Uncomment the next 2 lines to test if route is being called
            // return res.json({ test: 'Route is working', addressId: req.params.addressId });

            customerId = req.session?.user?.id;
            addressIdParam = req.params.addressId;

            // Write to response to verify route is hit (will be overwritten by actual response)
            res.setHeader('X-Delete-Address-Route', 'hit');
            res.setHeader('X-Address-ID', addressIdParam);

            console.log('🗑️ Delete address request:', { addressIdParam, customerId, hasSession: !!req.session, hasUser: !!req.session?.user });

            if (!customerId) {
                console.log('❌ No customer ID found');
                return res.status(401).json({ success: false, message: 'Not authenticated.' });
            }

            // Validate and parse addressId
            addressId = parseInt(addressIdParam, 10);
            if (isNaN(addressId) || addressId <= 0) {
                console.log('❌ Invalid address ID:', addressIdParam);
                return res.status(400).json({
                    success: false,
                    message: 'Invalid address ID.'
                });
            }

            console.log('✅ Validated address ID:', addressId);

        } catch (earlyErr) {
            console.error('❌ Error in early validation:', earlyErr);
            if (!res.headersSent) {
                return res.status(500).json({
                    success: false,
                    message: 'Error processing request',
                    error: process.env.NODE_ENV === 'development' ? earlyErr.message : undefined
                });
            }
            return;
        }

        try {
            // Ensure database connection is available
            if (!pool) {
                console.error('❌ Database pool not available');
                return res.status(500).json({
                    success: false,
                    message: 'Database connection error. Please try again later.'
                });
            }

            // First, verify the address belongs to this customer
            console.log('🔍 Checking address ownership...');
            let addressCheck;
            try {
                addressCheck = await pool.request()
                    .input('addressId', sql.Int, addressId)
                    .input('customerId', sql.Int, customerId)
                    .query('SELECT AddressID FROM CustomerAddresses WHERE AddressID = @addressId AND CustomerID = @customerId');
                console.log('✅ Address check completed, found:', addressCheck?.recordset?.length || 0, 'records');
            } catch (queryErr) {
                console.error('❌ Error checking address ownership:', queryErr);
                console.error('Query error details:', {
                    message: queryErr.message,
                    code: queryErr.code,
                    number: queryErr.number
                });
                return res.status(500).json({
                    success: false,
                    message: 'Database error while verifying address ownership.'
                });
            }

            if (!addressCheck || !addressCheck.recordset || addressCheck.recordset.length === 0) {
                console.log('❌ Address not found or access denied');
                return res.status(404).json({
                    success: false,
                    message: 'Address not found or you do not have permission to delete it.'
                });
            }

            // Step 0: Check order status - if all orders are completed, we can delete the address
            // by updating completed orders to use an alternative address
            let alternativeAddressId = null;

            // Check orders and their status
            const preOrderCheck = await pool.request()
                .input('addressId', sql.Int, addressId)
                .query(`
                    SELECT 
                        COUNT(*) as orderCount,
                        SUM(CASE WHEN Status = 'Completed' THEN 1 ELSE 0 END) as completedCount,
                        SUM(CASE WHEN Status != 'Completed' THEN 1 ELSE 0 END) as otherCount
                    FROM Orders 
                    WHERE ShippingAddressID = @addressId
                `);

            const preOrderCount = preOrderCheck?.recordset?.[0]?.orderCount || 0;
            const preCompletedCount = preOrderCheck?.recordset?.[0]?.completedCount || 0;
            const preOtherCount = preOrderCheck?.recordset?.[0]?.otherCount || 0;

            // If there are no orders, we can delete directly without transaction
            if (preOrderCount === 0) {
                console.log('✅ No orders reference this address. Deleting directly...');
                try {
                    const deleteResult = await pool.request()
                        .input('addressId', sql.Int, addressId)
                        .input('customerId', sql.Int, customerId)
                        .query('DELETE FROM CustomerAddresses WHERE AddressID = @addressId AND CustomerID = @customerId');

                    const deletedRows = deleteResult.rowsAffected && deleteResult.rowsAffected.length > 0 ? deleteResult.rowsAffected[0] : 0;

                    if (deletedRows === 0) {
                        return res.status(404).json({
                            success: false,
                            message: 'Address not found or already deleted.'
                        });
                    }

                    console.log(`✅ Address ${addressId} deleted successfully for customer ${customerId}`);
                    return res.json({ success: true, message: 'Address deleted successfully.' });
                } catch (deleteErr) {
                    console.error('❌ Delete error:', deleteErr.message);

                    // Check if it's a foreign key constraint error (shouldn't happen if preOrderCount was 0)
                    const isForeignKeyError = deleteErr.number === 547 ||
                        (deleteErr.message && (
                            deleteErr.message.includes('REFERENCE constraint') ||
                            deleteErr.message.includes('FOREIGN KEY') ||
                            deleteErr.message.includes('foreign key') ||
                            deleteErr.message.includes('The DELETE statement conflicted with the REFERENCE constraint')
                        ));

                    if (isForeignKeyError) {
                        // This shouldn't happen, but handle it gracefully
                        return res.status(400).json({
                            success: false,
                            message: 'Cannot delete address because it is associated with existing orders. Please contact support.',
                            usedByOrders: true,
                            error: process.env.NODE_ENV === 'development' ? deleteErr.message : undefined
                        });
                    }

                    throw deleteErr;
                }
            }

            // If there are any orders (completed or not), we need an alternative address
            // Find or create alternative address
            const altAddressCheck = await pool.request()
                .input('addressId', sql.Int, addressId)
                .input('customerId', sql.Int, customerId)
                .query(`
                    SELECT TOP 1 AddressID 
                    FROM CustomerAddresses 
                    WHERE CustomerID = @customerId AND AddressID != @addressId
                `);

            if (altAddressCheck?.recordset?.length > 0) {
                alternativeAddressId = altAddressCheck.recordset[0].AddressID;
            } else {
                // Create temporary address for completed orders
                const addressDetails = await pool.request()
                    .input('addressId', sql.Int, addressId)
                    .input('customerId', sql.Int, customerId)
                    .query(`
                        SELECT Label, HouseNumber, Street, Barangay, City, Province, Region, PostalCode, Country
                        FROM CustomerAddresses
                        WHERE AddressID = @addressId AND CustomerID = @customerId
                    `);

                if (addressDetails?.recordset?.length > 0) {
                    const addr = addressDetails.recordset[0];
                    const tempAddressResult = await pool.request()
                        .input('customerId', sql.Int, customerId)
                        .input('label', sql.NVarChar, (addr.Label || 'Previous Address') + ' (Archived)')
                        .input('houseNumber', sql.NVarChar, addr.HouseNumber || '')
                        .input('street', sql.NVarChar, addr.Street || '')
                        .input('barangay', sql.NVarChar, addr.Barangay || '')
                        .input('city', sql.NVarChar, addr.City || '')
                        .input('province', sql.NVarChar, addr.Province || '')
                        .input('region', sql.NVarChar, addr.Region || '')
                        .input('postalCode', sql.NVarChar, addr.PostalCode || '')
                        .input('country', sql.NVarChar, addr.Country || 'Philippines')
                        .query(`
                            INSERT INTO CustomerAddresses 
                            (CustomerID, Label, HouseNumber, Street, Barangay, City, Province, Region, PostalCode, Country)
                            OUTPUT INSERTED.AddressID
                            VALUES 
                            (@customerId, @label, @houseNumber, @street, @barangay, @city, @province, @region, @postalCode, @country)
                        `);

                    if (tempAddressResult?.recordset?.length > 0) {
                        alternativeAddressId = tempAddressResult.recordset[0].AddressID;
                    }
                }
            }

            if (!alternativeAddressId) {
                return res.status(400).json({
                    success: false,
                    message: 'Cannot delete address. No alternative address available and cannot create one.',
                    usedByOrders: true
                });
            }

            // Use a transaction to ensure atomicity: check, update orders, then delete address
            // This allows deletion even if orders reference the address
            const transaction = new sql.Transaction(pool);
            let transactionStarted = false;

            try {
                await transaction.begin();
                transactionStarted = true;
                console.log('🔄 Transaction started. Checking and removing address reference from all orders...');

                // Step 1: Check orders using this address (inside transaction)
                const orderCheck = await transaction.request()
                    .input('addressId', sql.Int, addressId)
                    .query('SELECT COUNT(*) as orderCount FROM Orders WHERE ShippingAddressID = @addressId');

                const orderCount = orderCheck?.recordset?.[0]?.orderCount || 0;

                // Step 2: Update ALL orders (including completed ones) to use alternative address
                if (orderCount > 0) {
                    if (!alternativeAddressId) {
                        await transaction.rollback();
                        transactionStarted = false;
                        return res.status(400).json({
                            success: false,
                            message: 'Cannot delete address. No alternative address available.',
                            usedByOrders: true
                        });
                    }

                    // Update ALL orders to use alternative address (this includes completed orders)
                    try {
                        const updateAllResult = await transaction.request()
                            .input('addressId', sql.Int, addressId)
                            .input('altAddressId', sql.Int, alternativeAddressId)
                            .query(`
                                UPDATE Orders 
                                SET ShippingAddressID = @altAddressId 
                                WHERE ShippingAddressID = @addressId
                            `);

                        const updatedRows = updateAllResult.rowsAffected && updateAllResult.rowsAffected.length > 0 ? updateAllResult.rowsAffected[0] : 0;

                        if (updatedRows !== orderCount) {
                            await transaction.rollback();
                            transactionStarted = false;
                            return res.status(400).json({
                                success: false,
                                message: `Failed to update all orders. Expected to update ${orderCount} but updated ${updatedRows}.`,
                                usedByOrders: true
                            });
                        }

                        // Verify update worked
                        const verifyCheck = await transaction.request()
                            .input('addressId', sql.Int, addressId)
                            .query('SELECT COUNT(*) as remainingCount FROM Orders WHERE ShippingAddressID = @addressId');

                        const remainingCount = verifyCheck?.recordset?.[0]?.remainingCount || 0;

                        if (remainingCount > 0) {
                            await transaction.rollback();
                            transactionStarted = false;
                            return res.status(400).json({
                                success: false,
                                message: `Verification failed: ${remainingCount} order(s) still reference this address after update.`,
                                usedByOrders: true
                            });
                        }
                    } catch (updateErr) {
                        await transaction.rollback();
                        transactionStarted = false;
                        return res.status(500).json({
                            success: false,
                            message: 'Failed to update orders. Cannot delete address.',
                            error: updateErr.message,
                            usedByOrders: true
                        });
                    }
                }

                // Step 3: Final verification - ensure no orders still reference this address
                console.log('🔍 Final verification: Checking for any remaining orders referencing this address...');
                const finalCheck = await transaction.request()
                    .input('addressId', sql.Int, addressId)
                    .query('SELECT COUNT(*) as finalCount FROM Orders WHERE ShippingAddressID = @addressId');

                const finalCount = finalCheck?.recordset?.[0]?.finalCount || 0;
                console.log(`📊 Final count of orders with this address: ${finalCount}`);

                if (finalCount > 0) {
                    // Get details of remaining orders
                    const remainingOrders = await transaction.request()
                        .input('addressId', sql.Int, addressId)
                        .query(`
                            SELECT OrderID, Status, ShippingAddressID 
                            FROM Orders 
                            WHERE ShippingAddressID = @addressId
                        `);

                    console.log(`⚠️ Still ${finalCount} order(s) referencing this address:`);
                    if (remainingOrders?.recordset) {
                        remainingOrders.recordset.forEach(order => {
                            console.log(`  - OrderID: ${order.OrderID}, Status: ${order.Status}, ShippingAddressID: ${order.ShippingAddressID}`);
                        });
                    }

                    await transaction.rollback();
                    transactionStarted = false;
                    return res.status(400).json({
                        success: false,
                        message: `Cannot delete address. ${finalCount} order(s) still reference this address. Please contact support.`,
                        usedByOrders: true
                    });
                }

                // Step 4: Final check - ensure absolutely no orders reference this address
                console.log('🔍 Final pre-delete verification: Double-checking for any orders...');
                const preDeleteCheck = await transaction.request()
                    .input('addressId', sql.Int, addressId)
                    .query(`
                        SELECT COUNT(*) as count
                        FROM Orders 
                        WHERE ShippingAddressID = @addressId
                    `);

                const preDeleteCount = preDeleteCheck?.recordset?.[0]?.count || 0;
                let preDeleteOrderIds = '';

                // Get order IDs separately if needed (for error reporting)
                if (preDeleteCount > 0) {
                    try {
                        const orderIdsCheck = await transaction.request()
                            .input('addressId', sql.Int, addressId)
                            .query(`
                                SELECT OrderID
                                FROM Orders 
                                WHERE ShippingAddressID = @addressId
                            `);
                        if (orderIdsCheck?.recordset) {
                            preDeleteOrderIds = orderIdsCheck.recordset.map(o => o.OrderID).join(', ');
                        }
                    } catch (e) {
                        // Ignore if we can't get order IDs
                    }
                }

                if (preDeleteCount > 0) {
                    console.error(`❌ CRITICAL: Found ${preDeleteCount} order(s) still referencing address ${addressId} right before delete!`);
                    console.error(`Order IDs: ${preDeleteOrderIds}`);

                    // Try to update these orders one more time
                    console.log('🔄 Attempting emergency update of remaining orders...');
                    const emergencyUpdate = await transaction.request()
                        .input('addressId', sql.Int, addressId)
                        .input('altAddressId', sql.Int, alternativeAddressId)
                        .query(`
                            UPDATE Orders 
                            SET ShippingAddressID = @altAddressId 
                            WHERE ShippingAddressID = @addressId
                        `);

                    const emergencyUpdated = emergencyUpdate.rowsAffected && emergencyUpdate.rowsAffected.length > 0 ? emergencyUpdate.rowsAffected[0] : 0;
                    console.log(`Emergency update affected ${emergencyUpdated} rows`);

                    // Check again
                    const postEmergencyCheck = await transaction.request()
                        .input('addressId', sql.Int, addressId)
                        .query('SELECT COUNT(*) as count FROM Orders WHERE ShippingAddressID = @addressId');

                    const postEmergencyCount = postEmergencyCheck?.recordset?.[0]?.count || 0;

                    if (postEmergencyCount > 0) {
                        await transaction.rollback();
                        transactionStarted = false;
                        return res.status(400).json({
                            success: false,
                            message: `Cannot delete address. ${postEmergencyCount} order(s) still reference this address. Please contact support if you need to delete this address.`,
                            usedByOrders: true,
                            orderCount: postEmergencyCount,
                            orderIds: preDeleteOrderIds
                        });
                    }
                }

                // Step 5: Delete the address (all references verified to be removed)
                console.log('🗑️ All references removed. Deleting address...');
                let deleteResult;
                try {
                    deleteResult = await transaction.request()
                        .input('addressId', sql.Int, addressId)
                        .input('customerId', sql.Int, customerId)
                        .query('DELETE FROM CustomerAddresses WHERE AddressID = @addressId AND CustomerID = @customerId');

                    const deletedRows = deleteResult.rowsAffected && deleteResult.rowsAffected.length > 0 ? deleteResult.rowsAffected[0] : 0;

                    if (deletedRows === 0) {
                        await transaction.rollback();
                        transactionStarted = false;
                        console.log('⚠️ No rows deleted - address may not exist');
                        return res.status(404).json({
                            success: false,
                            message: 'Address not found or already deleted.'
                        });
                    }

                    // Commit the transaction
                    await transaction.commit();
                    transactionStarted = false;

                    console.log(`✅ Address ${addressId} deleted successfully for customer ${customerId}`);
                    return res.json({ success: true, message: 'Address deleted successfully.' });
                } catch (deleteErr) {
                    console.error('❌ Delete error:', deleteErr.message);
                    console.error('Delete error details:', {
                        number: deleteErr.number,
                        code: deleteErr.code,
                        state: deleteErr.state,
                        class: deleteErr.class
                    });

                    // Rollback before handling error
                    if (transactionStarted) {
                        try {
                            await transaction.rollback();
                            transactionStarted = false;
                        } catch (rollbackErr) {
                            console.error('Error during rollback:', rollbackErr.message);
                        }
                    }

                    // Check if it's a foreign key constraint error
                    const isForeignKeyError = deleteErr.number === 547 ||
                        (deleteErr.message && (
                            deleteErr.message.includes('REFERENCE constraint') ||
                            deleteErr.message.includes('FOREIGN KEY') ||
                            deleteErr.message.includes('foreign key') ||
                            deleteErr.message.includes('The DELETE statement conflicted with the REFERENCE constraint')
                        ));

                    if (isForeignKeyError) {
                        console.error('⚠️ Foreign key constraint error even after verification. Checking for remaining orders...');

                        // One final check outside transaction to see what's still referencing this
                        try {
                            const finalOutsideCheck = await pool.request()
                                .input('addressId', sql.Int, addressId)
                                .query(`
                                    SELECT COUNT(*) as count
                                    FROM Orders 
                                    WHERE ShippingAddressID = @addressId
                                `);

                            const finalCount = finalOutsideCheck?.recordset?.[0]?.count || 0;

                            // Get order IDs if needed
                            let finalOrderIds = '';
                            if (finalCount > 0) {
                                try {
                                    const orderIdsResult = await pool.request()
                                        .input('addressId', sql.Int, addressId)
                                        .query(`
                                            SELECT OrderID
                                            FROM Orders 
                                            WHERE ShippingAddressID = @addressId
                                        `);
                                    if (orderIdsResult?.recordset) {
                                        finalOrderIds = orderIdsResult.recordset.map(o => o.OrderID).join(', ');
                                    }
                                } catch (e) {
                                    // Ignore if we can't get order IDs
                                }
                            }

                            return res.status(400).json({
                                success: false,
                                message: `Cannot delete address because it is still referenced by ${finalCount} order(s). Please contact support if you need to delete this address.`,
                                usedByOrders: true,
                                orderCount: finalCount,
                                orderIds: finalOrderIds || undefined
                            });
                        } catch (checkErr) {
                            return res.status(400).json({
                                success: false,
                                message: 'Cannot delete address because it is associated with existing orders. Please contact support.',
                                usedByOrders: true,
                                error: deleteErr.message
                            });
                        }
                    } else {
                        // Other error - re-throw to be handled by outer catch
                        throw deleteErr;
                    }
                }

            } catch (transactionErr) {
                // Rollback on any error
                if (transactionStarted) {
                    try {
                        await transaction.rollback();
                        transactionStarted = false;
                    } catch (rollbackErr) {
                        // Ignore rollback errors
                    }
                }

                // Log error to file for debugging
                try {
                    const errorLog = `\n[${new Date().toISOString()}] ERROR: ${transactionErr.message}\nStack: ${transactionErr.stack}\n`;
                    fs.appendFileSync(path.join(__dirname, 'delete-address-error.log'), errorLog);
                } catch (e) { }

                // Ensure we send a response
                if (!res.headersSent) {
                    // If it's a foreign key constraint error, provide a helpful message
                    const isFKError = transactionErr.number === 547 || (transactionErr.message && (
                        transactionErr.message.includes('REFERENCE constraint') ||
                        transactionErr.message.includes('FOREIGN KEY') ||
                        transactionErr.message.includes('foreign key') ||
                        transactionErr.message.includes('The DELETE statement conflicted with the REFERENCE constraint')
                    ));

                    if (isFKError) {
                        // Try to get order count for better error message
                        let orderCount = 0;
                        try {
                            const orderCheck = await pool.request()
                                .input('addressId', sql.Int, addressId)
                                .query('SELECT COUNT(*) as count FROM Orders WHERE ShippingAddressID = @addressId');
                            orderCount = orderCheck?.recordset?.[0]?.count || 0;
                        } catch (e) {
                            // Ignore if check fails
                        }

                        return res.status(400).json({
                            success: false,
                            message: orderCount > 0
                                ? `Cannot delete address because it is still referenced by ${orderCount} order(s). Please contact support if you need to delete this address.`
                                : 'Cannot delete address because it is associated with existing orders. Please contact support.',
                            usedByOrders: true,
                            orderCount: orderCount || undefined,
                            error: process.env.NODE_ENV === 'development' ? transactionErr.message : undefined,
                            errorNumber: transactionErr.number
                        });
                    }

                    // For other errors, return the actual error message
                    return res.status(500).json({
                        success: false,
                        message: 'Failed to delete address',
                        error: transactionErr.message,
                        errorNumber: transactionErr.number,
                        errorCode: transactionErr.code
                    });
                }

                // Re-throw to be caught by outer catch if response not sent
                throw transactionErr;
            }
        } catch (err) {
            // Ensure we have a valid error object
            const error = err || new Error('Unknown error occurred');

            console.error('❌ Error deleting customer address:', error);
            console.error('Error details:', {
                addressId: addressIdParam,
                customerId: customerId,
                errorMessage: error.message || 'No error message',
                errorCode: error.code,
                errorNumber: error.number,
                errorState: error.state,
                errorClass: error.class,
                errorStack: error.stack
            });

            // Check if response was already sent
            if (res.headersSent) {
                console.error('Response already sent, cannot send error response');
                return;
            }

            // Check for SQL Server specific error codes
            // Error 547 = Foreign key constraint violation
            // Error 515 = Cannot insert NULL value
            const errorMessage = String(error.message || '');
            const errorNumber = error.number;

            console.error('Error message:', errorMessage);
            console.error('Error number:', errorNumber);

            // Check if response was already sent (double check)
            if (res.headersSent) {
                console.error('Response already sent, cannot send error response');
                return;
            }

            // Check for foreign key constraint
            if (errorNumber === 547 || (
                errorMessage.includes('REFERENCE constraint') ||
                errorMessage.includes('FOREIGN KEY') ||
                errorMessage.includes('foreign key') ||
                errorMessage.includes('The DELETE statement conflicted with the REFERENCE constraint')
            )) {
                console.log('Foreign key constraint detected');
                return res.status(400).json({
                    success: false,
                    message: 'Cannot delete address because it is associated with existing orders. You can edit it or add a new address instead.',
                    usedByOrders: true
                });
            }

            // Check for other common SQL errors
            if (errorNumber === 515) {
                console.log('Database constraint error detected');
                return res.status(400).json({
                    success: false,
                    message: 'Cannot delete address due to database constraints.'
                });
            }

            // Check for table/column not found errors
            if (errorMessage.includes('Invalid object name') ||
                errorMessage.includes('Invalid column name') ||
                errorMessage.includes('does not exist')) {
                console.log('Table/column not found error');
                return res.status(500).json({
                    success: false,
                    message: 'Database configuration error. Please contact support.',
                    error: process.env.NODE_ENV === 'development' ? errorMessage : undefined
                });
            }

            // Return generic error response
            console.log('Returning generic error response');
            return res.status(500).json({
                success: false,
                message: 'Failed to delete address. Please try again.',
                error: process.env.NODE_ENV === 'development' ? errorMessage : undefined,
                errorCode: process.env.NODE_ENV === 'development' ? errorNumber : undefined
            });
        }
    });
