    // Product Management API
    router.post('/Employee/Admin/Products/Add', isAuthenticated, productUpload.fields([
        { name: 'image', maxCount: 1 },
        { name: 'thumbnails', maxCount: 8 },
        { name: 'thumbnail1', maxCount: 1 },
        { name: 'thumbnail2', maxCount: 1 },
        { name: 'thumbnail3', maxCount: 1 },
        { name: 'thumbnail4', maxCount: 1 },
        { name: 'model3d', maxCount: 1 }
    ]), async (req, res) => {
        try {
            await pool.connect();
            const { name, description, price, stockquantity, category, requiredMaterials, dimensions, inventoryProductId } = req.body;

            // Validate required fields
            if (!name || !price || !stockquantity || !category) {
                return res.status(400).json({
                    success: false,
                    message: 'Missing required fields: name, price, stockquantity, and category are required.'
                });
            }

            // Validate and parse inventoryProductId - now required
            if (!inventoryProductId || inventoryProductId.toString().trim() === '' || isNaN(parseInt(inventoryProductId))) {
                return res.status(400).json({
                    success: false,
                    message: 'Please select a product from inventory. A product from inventory is required to create a CMS product.'
                });
            }

            const inventoryProductIdNum = parseInt(inventoryProductId);

            console.log('[PRODUCT ADD] Received inventoryProductId:', inventoryProductId, 'parsed as:', inventoryProductIdNum);

            // Check if a product with the same name already exists in Products table
            const existingProductByName = await pool.request()
                .input('name', sql.NVarChar, name.trim())
                .query(`
                    SELECT ProductID, Name, IsActive
                    FROM Products
                    WHERE LOWER(TRIM(Name)) = LOWER(TRIM(@name)) AND IsActive = 1
                `);

            if (existingProductByName.recordset.length > 0) {
                const existingProduct = existingProductByName.recordset[0];
                return res.status(400).json({
                    success: false,
                    message: `A product with the name "${existingProduct.Name}" already exists in the CMS (Product ID: ${existingProduct.ProductID}). You cannot create a duplicate product. Please edit the existing product instead.`
                });
            }

            // ProductInventory table has been removed - CMS products and Inventory products are now separate
            // Check if an inventory product with the same name/SKU already exists in Products table
            // This prevents creating duplicate CMS products for the same inventory product
            const inventoryProductInfo = await pool.request()
                .input('inventoryProductId', sql.Int, inventoryProductIdNum)
                .query(`
                    SELECT Name, SKU, COALESCE(AvailableQuantity, 0) as AvailableQuantity
                    FROM InventoryProducts
                    WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
                `);

            if (inventoryProductInfo.recordset.length === 0) {
                return res.status(400).json({
                    success: false,
                    message: 'Selected inventory product not found or is inactive.'
                });
            }

            const invProduct = inventoryProductInfo.recordset[0];
            const inventoryAvailableQty = invProduct.AvailableQuantity || 0;
            const requestedStockQty = parseInt(stockquantity) || 0;

            // Check if this inventory product is already linked to a CMS product
            // Check InventoryProducts table to see if ProductID is already set
            const inventoryProductLinkCheck = await pool.request()
                .input('inventoryProductId', sql.Int, inventoryProductIdNum)
                .query(`
                    SELECT InventoryProductID, ProductID, Name
                    FROM InventoryProducts
                    WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
                `);

            if (inventoryProductLinkCheck.recordset.length > 0) {
                const inventoryProduct = inventoryProductLinkCheck.recordset[0];

                // If ProductID is already set, it means it's linked to a CMS product
                if (inventoryProduct.ProductID && inventoryProduct.ProductID !== null) {
                    // Get the CMS product details
                    const linkedProductCheck = await pool.request()
                        .input('productId', sql.Int, inventoryProduct.ProductID)
                        .query(`
                            SELECT ProductID, Name, IsActive
                            FROM Products
                            WHERE ProductID = @productId AND IsActive = 1
                        `);

                    if (linkedProductCheck.recordset.length > 0) {
                        const existingProduct = linkedProductCheck.recordset[0];
                        console.log(`[PRODUCT ADD] ❌ DUPLICATE DETECTED: Inventory product "${inventoryProduct.Name}" (ID: ${inventoryProductIdNum}) is already linked to CMS product "${existingProduct.Name}" (ID: ${existingProduct.ProductID})`);
                        return res.status(400).json({
                            success: false,
                            message: `This inventory product "${inventoryProduct.Name || 'ID: ' + inventoryProductIdNum}" is already linked to a CMS product (Product ID: ${existingProduct.ProductID}, Name: "${existingProduct.Name}"). You cannot create a duplicate link. Please edit the existing product instead.`
                        });
                    }
                } else {
                    // ProductID exists in InventoryProducts but the linked CMS product is inactive or deleted
                    // Allow linking to continue - user might be restoring/reactivating
                    console.log(`[PRODUCT ADD] ⚠️ Inventory product has ProductID set but linked CMS product not found or inactive - allowing link`);
                }
            }

            // Validate that stock quantity doesn't exceed inventory available quantity
            if (requestedStockQty > inventoryAvailableQty) {
                return res.status(400).json({
                    success: false,
                    message: `Stock quantity (${requestedStockQty}) cannot exceed inventory available quantity (${inventoryAvailableQty}). Please use the quantity from Product Inventory.`
                });
            }

            // Check if a CMS product with the same name or SKU already exists
            const existingProductCheck = await pool.request()
                .input('productName', sql.NVarChar, invProduct.Name)
                .input('productSKU', sql.NVarChar, invProduct.SKU)
                .query(`
                    SELECT ProductID, Name, SKU, IsActive
                    FROM Products
                    WHERE (LOWER(TRIM(Name)) = LOWER(TRIM(@productName)) 
                           OR (SKU IS NOT NULL AND LOWER(TRIM(SKU)) = LOWER(TRIM(@productSKU))))
                        AND IsActive = 1
                `);

            if (existingProductCheck.recordset.length > 0) {
                const existingProduct = existingProductCheck.recordset[0];
                return res.status(400).json({
                    success: false,
                    message: `A CMS product with the same name or SKU already exists (Product ID: ${existingProduct.ProductID}, Name: "${existingProduct.Name}"). You cannot create a duplicate product. Please edit the existing product instead.`
                });
            }

            console.log('Creating product with data:', {
                name,
                price,
                stockquantity,
                category,
                inventoryProductId: inventoryProductIdNum
            });

            // Start transaction
            const transaction = new sql.Transaction(pool);
            await transaction.begin();

            try {
                // Parse dimensions data
                let dimensionsJson = '{}';
                if (dimensions) {
                    try {
                        const dimensionsData = JSON.parse(dimensions);
                        dimensionsJson = JSON.stringify(dimensionsData);
                    } catch (e) {
                        console.log('Error parsing dimensions:', e);
                    }
                }

                // Generate temporary SKU and Slug to satisfy UNIQUE constraints
                // Use SQL Server's NEWID() for PublicId directly in the query
                const tempSku = `TEMP-SKU-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
                const tempSlug = `temp-${Date.now()}-${Math.floor(Math.random() * 10000)}`;

                // Insert product
                const productResult = await transaction.request()
                    .input('name', sql.NVarChar, name)
                    .input('description', sql.NVarChar, description)
                    .input('price', sql.Decimal(10, 2), price)
                    .input('stockquantity', sql.Int, stockquantity)
                    .input('category', sql.NVarChar, category)
                    .input('dimensions', sql.NVarChar, dimensionsJson)
                    .input('tempSku', sql.NVarChar, tempSku)
                    .input('tempSlug', sql.NVarChar, tempSlug)
                    .query(`
                        INSERT INTO Products (Name, Description, Price, StockQuantity, Category, Dimensions, DateAdded, IsActive, SKU, PublicId, Slug)
                        VALUES (@name, @description, @price, @stockquantity, @category, @dimensions, GETDATE(), 1, @tempSku, NEWID(), @tempSlug)
                        SELECT SCOPE_IDENTITY() as ProductID
                    `);

                const productId = productResult.recordset[0].ProductID;

                // Generate final SKU and Slug based on actual ProductID
                // Generate a new GUID for the final PublicId
                const { sku, slug } = generateProductIdentifiers(productId, name);
                const finalPublicId = generateGuid(); // Generate final GUID (uppercase format)

                // Update with final identifiers
                // Use CAST to convert GUID string to uniqueidentifier
                try {
                    await transaction.request()
                        .input('productId', sql.Int, productId)
                        .input('sku', sql.NVarChar, sku)
                        .input('publicId', sql.NVarChar, finalPublicId)
                        .input('slug', sql.NVarChar, slug)
                        .query('UPDATE Products SET SKU = @sku, PublicId = CAST(@publicId AS UNIQUEIDENTIFIER), Slug = @slug WHERE ProductID = @productId');
                } catch (updateErr) {
                    console.error('Error updating product identifiers:', updateErr);
                    console.error('ProductID:', productId, 'SKU:', sku, 'PublicId:', finalPublicId, 'Slug:', slug);
                    throw updateErr;
                }

                // Handle file uploads if any, or copy from inventory product
                // The inventoryProductId is from InventoryProducts table - copy images/3D model if not provided
                // Copy images and 3D model from InventoryProducts if not provided in form
                const inventoryProductResult = await transaction.request()
                    .input('inventoryProductId', sql.Int, inventoryProductIdNum)
                    .query(`
                        SELECT ImageURL, ThumbnailURLs, Model3D as Model3DURL
                        FROM InventoryProducts
                        WHERE InventoryProductID = @inventoryProductId
                    `);

                if (inventoryProductResult.recordset.length > 0) {

                    const inventoryProduct = inventoryProductResult.recordset[0];

                    // Copy main image if not uploaded
                    if (!req.files || !req.files.image) {
                        if (inventoryProduct.ImageURL) {
                            await transaction.request()
                                .input('productId', sql.Int, productId)
                                .input('imageUrl', sql.NVarChar, inventoryProduct.ImageURL)
                                .query('UPDATE Products SET ImageURL = @imageUrl WHERE ProductID = @productId');
                        }
                    } else {
                        // Use uploaded image
                        const imageFile = req.files.image[0];
                        const imageUrl = publicUrlFromMulterProductFile(imageFile);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('imageUrl', sql.NVarChar, imageUrl)
                            .query('UPDATE Products SET ImageURL = @imageUrl WHERE ProductID = @productId');
                    }

                    // Copy thumbnails if not uploaded, or use uploaded thumbnails
                    let thumbnails = [];
                    let hasUploadedThumbnails = false;

                    // Individual thumbnail fields (thumbnail1, thumbnail2, etc.)
                    for (let i = 1; i <= 4; i++) {
                        if (req.files && req.files[`thumbnail${i}`]) {
                            const thumbnailFile = req.files[`thumbnail${i}`][0];
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                            hasUploadedThumbnails = true;
                        }
                    }

                    // Bulk thumbnails field (matches "Bulk Upload" in AdminProducts.ejs)
                    if (req.files && req.files.thumbnails && req.files.thumbnails.length > 0) {
                        for (const thumbnailFile of req.files.thumbnails) {
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                            hasUploadedThumbnails = true;
                        }
                    }

                    if (!hasUploadedThumbnails && inventoryProduct.ThumbnailURLs) {
                        // Use thumbnails from inventory product
                        try {
                            const inventoryThumbnails = typeof inventoryProduct.ThumbnailURLs === 'string'
                                ? JSON.parse(inventoryProduct.ThumbnailURLs)
                                : inventoryProduct.ThumbnailURLs;
                            if (Array.isArray(inventoryThumbnails)) {
                                thumbnails = inventoryThumbnails;
                            }
                        } catch (e) {
                            console.log('Error parsing inventory thumbnails:', e);
                        }
                    }

                    if (thumbnails.length > 0) {
                        console.log(`[PRODUCT ADD - THUMBNAILS] Found ${thumbnails.length} thumbnails to save from inventory copy. Saving to database...`);
                        console.log(`[PRODUCT ADD - THUMBNAILS] Thumbnail URLs:`, thumbnails);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('thumbnails', sql.NVarChar, JSON.stringify(thumbnails))
                            .query('UPDATE Products SET ThumbnailURLs = @thumbnails WHERE ProductID = @productId');
                        console.log(`[PRODUCT ADD - THUMBNAILS] ✅ Successfully saved ${thumbnails.length} thumbnails to database for ProductID ${productId}`);
                    } else {
                        console.log(`[PRODUCT ADD - THUMBNAILS] No thumbnails to save for ProductID ${productId}`);
                    }

                    // Copy 3D model if not uploaded
                    if (!req.files || !req.files.model3d) {
                        if (inventoryProduct.Model3DURL) {
                            await transaction.request()
                                .input('productId', sql.Int, productId)
                                .input('model3dUrl', sql.NVarChar, inventoryProduct.Model3DURL)
                                .query('UPDATE Products SET Model3DURL = @model3dUrl WHERE ProductID = @productId');
                        }
                    } else {
                        // Use uploaded 3D model
                        const model3dFile = req.files.model3d[0];
                        const model3dUrl = publicUrlFromMulterProductFile(model3dFile);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('model3dUrl', sql.NVarChar, model3dUrl)
                            .query('UPDATE Products SET Model3DURL = @model3dUrl WHERE ProductID = @productId');
                    }
                } else if (req.files) {
                    // Handle file uploads for new products (not from inventory)
                    // Handle main image
                    if (req.files.image) {
                        const imageFile = req.files.image[0];
                        const imageUrl = publicUrlFromMulterProductFile(imageFile);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('imageUrl', sql.NVarChar, imageUrl)
                            .query('UPDATE Products SET ImageURL = @imageUrl WHERE ProductID = @productId');
                    }

                    // Handle thumbnails
                    const thumbnails = [];
                    for (let i = 1; i <= 4; i++) {
                        if (req.files[`thumbnail${i}`]) {
                            const thumbnailFile = req.files[`thumbnail${i}`][0];
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                        }
                    }

                    if (thumbnails.length > 0) {
                        console.log(`[PRODUCT ADD - NEW] Found ${thumbnails.length} uploaded thumbnails. Saving to database...`);
                        console.log(`[PRODUCT ADD - NEW] Thumbnail URLs:`, thumbnails);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('thumbnails', sql.NVarChar, JSON.stringify(thumbnails))
                            .query('UPDATE Products SET ThumbnailURLs = @thumbnails WHERE ProductID = @productId');
                        console.log(`[PRODUCT ADD - NEW] ✅ Successfully saved ${thumbnails.length} thumbnails to database for ProductID ${productId}`);
                    }

                    // Handle 3D model
                    if (req.files.model3d) {
                        const modelFile = req.files.model3d[0];
                        const model3dUrl = publicUrlFromMulterProductFile(modelFile);
                        await transaction.request()
                            .input('productId', sql.Int, productId)
                            .input('model3dUrl', sql.NVarChar, model3dUrl)
                            .query('UPDATE Products SET Model3DURL = @model3dUrl WHERE ProductID = @productId');
                    }
                }

                // Raw material recipes are managed on Product Inventory only (InventoryProductMaterials)

                // Link InventoryProducts to Products by setting ProductID in InventoryProducts
                console.log('[PRODUCT ADD] ====== STARTING LINK PROCESS ======');
                console.log('[PRODUCT ADD] ProductID:', productId);
                console.log('[PRODUCT ADD] inventoryProductIdNum:', inventoryProductIdNum);
                console.log('[PRODUCT ADD] Type of inventoryProductIdNum:', typeof inventoryProductIdNum);
                console.log('[PRODUCT ADD] Is inventoryProductIdNum truthy?', !!inventoryProductIdNum);

                if (inventoryProductIdNum) {
                    console.log('[PRODUCT ADD] Attempting to link InventoryProduct to Product...');
                    try {
                        // First, get the AvailableQuantity from InventoryProducts before linking
                        console.log('[PRODUCT ADD] Querying InventoryProducts for InventoryProductID:', inventoryProductIdNum);
                        const inventoryCheckResult = await transaction.request()
                            .input('inventoryProductId', sql.Int, inventoryProductIdNum)
                            .query(`
                                SELECT AvailableQuantity, ProductID
                                FROM InventoryProducts
                                WHERE InventoryProductID = @inventoryProductId AND IsActive = 1
                            `);

                        console.log('[PRODUCT ADD] InventoryProducts query result count:', inventoryCheckResult.recordset.length);

                        if (inventoryCheckResult.recordset.length > 0) {
                            const inventoryProduct = inventoryCheckResult.recordset[0];
                            const availableQuantity = inventoryProduct.AvailableQuantity || 0;

                            // DOUBLE-CHECK: Verify ProductID is not already set (safety check inside transaction)
                            if (inventoryProduct.ProductID && inventoryProduct.ProductID !== null) {
                                console.log(`[PRODUCT ADD] ❌ DUPLICATE DETECTED INSIDE TRANSACTION: InventoryProduct ${inventoryProductIdNum} already has ProductID: ${inventoryProduct.ProductID}`);
                                await transaction.rollback();

                                // Get the CMS product details for error message
                                const linkedProductCheck = await pool.request()
                                    .input('productId', sql.Int, inventoryProduct.ProductID)
                                    .query(`
                                        SELECT ProductID, Name, IsActive
                                        FROM Products
                                        WHERE ProductID = @productId AND IsActive = 1
                                    `);

                                if (linkedProductCheck.recordset.length > 0) {
                                    const existingProduct = linkedProductCheck.recordset[0];
                                    return res.status(400).json({
                                        success: false,
                                        message: `This inventory product is already linked to a CMS product (Product ID: ${existingProduct.ProductID}, Name: "${existingProduct.Name}"). You cannot create a duplicate link. Please edit the existing product instead.`
                                    });
                                } else {
                                    return res.status(400).json({
                                        success: false,
                                        message: `This inventory product is already linked to another product. You cannot create a duplicate link.`
                                    });
                                }
                            }

                            console.log(`[PRODUCT ADD] InventoryProduct ${inventoryProductIdNum} has AvailableQuantity: ${availableQuantity}`);

                            // Link the InventoryProduct to the new Product
                            await transaction.request()
                                .input('inventoryProductId', sql.Int, inventoryProductIdNum)
                                .input('productId', sql.Int, productId)
                                .query(`
                                UPDATE InventoryProducts 
                                SET ProductID = @productId 
                                    WHERE InventoryProductID = @inventoryProductId AND (ProductID IS NULL OR ProductID = 0)
                                `);
                            console.log(`[PRODUCT ADD] Linked InventoryProduct ${inventoryProductIdNum} to Product ${productId}`);

                            // Verify the link was set correctly
                            const verifyLinkResult = await transaction.request()
                                .input('productId', sql.Int, productId)
                                .query(`
                                    SELECT InventoryProductID, AvailableQuantity, ProductID
                                    FROM InventoryProducts
                                    WHERE ProductID = @productId AND IsActive = 1
                                `);

                            if (verifyLinkResult.recordset.length > 0) {
                                console.log(`[PRODUCT ADD] Verified link: Found ${verifyLinkResult.recordset.length} InventoryProduct(s) linked to ProductID ${productId}`);

                                // Directly update Products.StockQuantity with AvailableQuantity from InventoryProducts
                                await transaction.request()
                                    .input('productId', sql.Int, productId)
                                    .input('availableQuantity', sql.Int, availableQuantity)
                                    .query(`
                                        UPDATE Products 
                                        SET StockQuantity = @availableQuantity,
                                            UpdatedAt = GETDATE()
                                        WHERE ProductID = @productId
                                    `);
                                console.log(`[PRODUCT ADD] Directly synced stock: Products.StockQuantity = ${availableQuantity} for ProductID ${productId}`);
                            } else {
                                console.warn(`[PRODUCT ADD] Warning: Link verification failed - no InventoryProduct found for ProductID ${productId} after linking`);
                            }
                        } else {
                            console.warn(`[PRODUCT ADD] Warning: InventoryProduct ${inventoryProductIdNum} not found or inactive`);
                        }
                    } catch (linkErr) {
                        console.error('[PRODUCT ADD] Error linking InventoryProducts to Products:', linkErr);
                        console.error('[PRODUCT ADD] Error details:', linkErr.message, linkErr.stack);
                        // Don't fail the transaction if linking fails - product is still created
                    }
                }

                // Note: ProductInventory table is no longer used - inventory is managed through InventoryProducts only

                await transaction.commit();

                // Log the activity
                await logActivity(
                    req.session.user.id,
                    'INSERT',
                    'Products',
                    productId.toString(),
                    `Admin created new product: "${name}" (ID: ${productId})`
                );

                console.log('Product created successfully with ID:', productId);

                // Check if response has already been sent
                if (!res.headersSent) {
                    res.json({
                        success: true,
                        message: 'Product created successfully!',
                        productId: productId
                    });
                } else {
                    console.error('Response already sent, cannot send success response');
                }
            } catch (err) {
                console.error('Transaction error details:', {
                    message: err.message,
                    code: err.code,
                    number: err.number,
                    originalError: err.originalError,
                    stack: err.stack
                });
                try {
                    await transaction.rollback();
                } catch (rollbackErr) {
                    // Transaction may already be aborted, ignore rollback error
                    console.error('Error during transaction rollback (may be already aborted):', rollbackErr.message);
                }
                throw err;
            }
        } catch (err) {
            console.error('Error creating product:', err);
            console.error('Error details:', {
                message: err.message,
                code: err.code,
                number: err.number,
                originalError: err.originalError,
                stack: err.stack
            });

            // Check if response has already been sent
            if (!res.headersSent) {
                res.status(500).json({
                    success: false,
                    message: 'Failed to create product: ' + (err.message || 'Unknown error'),
                    error: err.message
                });
            } else {
                console.error('Response already sent, cannot send error response');
            }
        }
    });
    router.post('/Employee/Admin/Products/Edit', isAuthenticated, productUpload.fields([
        { name: 'image', maxCount: 1 },
        { name: 'thumbnail1', maxCount: 1 },
        { name: 'thumbnail2', maxCount: 1 },
        { name: 'thumbnail3', maxCount: 1 },
        { name: 'thumbnail4', maxCount: 1 },
        { name: 'thumbnails', maxCount: 4 }, // Add support for thumbnails field
        { name: 'model3d', maxCount: 1 }
    ]), async (req, res) => {
        try {
            await pool.connect();
            const { productid, name, description, price, stockquantity, category, requiredMaterials, dimensions } = req.body;

            // Parse dimensions data
            let dimensionsJson = '{}';
            if (dimensions) {
                try {
                    const dimensionsData = JSON.parse(dimensions);
                    dimensionsJson = JSON.stringify(dimensionsData);
                } catch (e) {
                    console.log('Error parsing dimensions:', e);
                }
            }

            // Start transaction
            const transaction = new sql.Transaction(pool);
            await transaction.begin();

            try {
                // Get old product data for change tracking
                const oldProductResult = await transaction.request()
                    .input('productId', sql.Int, productid)
                    .query(`
                        SELECT Name, Description, Price, StockQuantity, Category 
                        FROM Products 
                        WHERE ProductID = @productId
                    `);

                const oldProduct = oldProductResult.recordset[0];

                // Stock quantity cannot be edited from this page - preserve existing value
                const currentStockQuantity = oldProduct.StockQuantity || 0;

                // Update product (excluding StockQuantity - it cannot be edited from this page)
                await transaction.request()
                    .input('productId', sql.Int, productid)
                    .input('name', sql.NVarChar, name)
                    .input('description', sql.NVarChar, description)
                    .input('price', sql.Decimal(10, 2), price)
                    .input('category', sql.NVarChar, category)
                    .input('dimensions', sql.NVarChar, dimensionsJson)
                    .query(`
                        UPDATE Products 
                        SET Name = @name, Description = @description, Price = @price,
                            Category = @category, Dimensions = @dimensions, UpdatedAt = GETDATE()
                        WHERE ProductID = @productId
                    `);

                // Handle file uploads if any
                if (req.files) {
                    // Get current image URLs before updating
                    const currentProduct = await transaction.request()
                        .input('productId', sql.Int, productid)
                        .query('SELECT ImageURL, ThumbnailURLs, Model3DURL FROM Products WHERE ProductID = @productId');

                    const currentImageUrl = currentProduct.recordset[0]?.ImageURL;
                    const currentThumbnailUrls = currentProduct.recordset[0]?.ThumbnailURLs;
                    const currentModel3DURL = currentProduct.recordset[0]?.Model3DURL;

                    // Handle main image
                    if (req.files.image) {
                        // Delete old main image
                        await deleteOldImageFile(currentImageUrl);

                        const imageFile = req.files.image[0];
                        const imageUrl = publicUrlFromMulterProductFile(imageFile);
                        await transaction.request()
                            .input('productId', sql.Int, productid)
                            .input('imageUrl', sql.NVarChar, imageUrl)
                            .query('UPDATE Products SET ImageURL = @imageUrl WHERE ProductID = @productId');
                    }

                    // Handle thumbnails
                    const thumbnails = [];

                    // Check for individual thumbnail fields (thumbnail1, thumbnail2, etc.)
                    for (let i = 1; i <= 4; i++) {
                        if (req.files[`thumbnail${i}`]) {
                            const thumbnailFile = req.files[`thumbnail${i}`][0];
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                        }
                    }

                    // Also check for thumbnails field (multiple files)
                    if (req.files.thumbnails && req.files.thumbnails.length > 0) {
                        for (const thumbnailFile of req.files.thumbnails) {
                            thumbnails.push(publicUrlFromMulterProductFile(thumbnailFile));
                        }
                    }

                    if (thumbnails.length > 0) {
                        // Delete old thumbnails
                        await deleteOldThumbnailFiles(currentThumbnailUrls);

                        console.log(`[PRODUCT EDIT - THUMBNAILS] Found ${thumbnails.length} new/updated thumbnails. Saving to database...`);
                        console.log(`[PRODUCT EDIT - THUMBNAILS] Thumbnail URLs:`, thumbnails);
                        await transaction.request()
                            .input('productId', sql.Int, productid)
                            .input('thumbnails', sql.NVarChar, JSON.stringify(thumbnails))
                            .query('UPDATE Products SET ThumbnailURLs = @thumbnails WHERE ProductID = @productId');
                        console.log(`[PRODUCT EDIT - THUMBNAILS] ✅ Successfully saved ${thumbnails.length} thumbnails to database for ProductID ${productid}`);
                    } else {
                        console.log(`[PRODUCT EDIT - THUMBNAILS] No new thumbnails to update for ProductID ${productid}`);
                    }

                    // Handle 3D model
                    if (req.files.model3d) {
                        // Delete old 3D model file
                        if (currentModel3DURL) {
                            await deleteOldImageFile(currentModel3DURL);
                        }

                        const model3dFile = req.files.model3d[0];
                        const model3dUrl = publicUrlFromMulterProductFile(model3dFile);
                        await transaction.request()
                            .input('productId', sql.Int, productid)
                            .input('model3dUrl', sql.NVarChar, model3dUrl)
                            .input('has3dModel', sql.Bit, 1)
                            .query('UPDATE Products SET Model3DURL = @model3dUrl, Has3DModel = @has3dModel WHERE ProductID = @productId');
                    }
                }

                // Raw material recipes are managed on Product Inventory only

                await transaction.commit();

                // Capture changes for logging
                const newProductData = { Name: name, Description: description, Price: price, StockQuantity: stockquantity, Category: category };
                const changes = captureChanges(oldProduct, newProductData, ['Name', 'Description', 'Price', 'StockQuantity', 'Category']);

                // Log the activity
                await logActivity(
                    req.session.user.id,
                    'UPDATE',
                    'Products',
                    productid.toString(),
                    `Admin updated product: "${name}" (ID: ${productid})`,
                    changes
                );

                res.json({
                    success: true,
                    message: 'Product updated successfully!'
                });
            } catch (err) {
                await transaction.rollback();
                throw err;
            }
        } catch (err) {
            console.error('Error updating product:', err);
            res.json({
                success: false,
                message: 'Failed to update product: ' + err.message
            });
        }
    });

