    // Add new variation
    router.post('/Employee/Admin/Variations/Add', isAuthenticated, variationUpload.single('variationImage'), async (req, res) => {
        try {
            await pool.connect();
            const { variationName, color, quantity, productID, price, isActive, inventoryVariationId } = req.body;

            const parsedProductID = parseInt(productID);
            const parsedInventoryVariationId = inventoryVariationId ? parseInt(inventoryVariationId) : null;

            console.log(`[VARIATION ADD] ====== STARTING VARIATION ADD PROCESS ======`);
            console.log(`[VARIATION ADD] ProductID: ${parsedProductID}`);
            console.log(`[VARIATION ADD] InventoryVariationID: ${parsedInventoryVariationId}`);
            console.log(`[VARIATION ADD] VariationName: ${variationName}`);
            console.log(`[VARIATION ADD] Quantity: ${quantity}`);

            // Validate that inventory variation is selected (required)
            if (!inventoryVariationId || inventoryVariationId.toString().trim() === '' || isNaN(parseInt(inventoryVariationId)) || !parsedInventoryVariationId) {
                return res.json({
                    success: false,
                    message: 'Please select a variation from inventory. A variation from inventory is required to create a CMS variation.'
                });
            }

            // Verify product exists and get stock quantity
            const productResult = await pool.request()
                .input('productID', sql.Int, parsedProductID)
                .query('SELECT ProductID, StockQuantity FROM Products WHERE ProductID = @productID');

            if (productResult.recordset.length === 0) {
                return res.json({
                    success: false,
                    message: 'Product not found.'
                });
            }

            const productStock = productResult.recordset[0].StockQuantity || 0;
            const variationQuantity = parseInt(quantity) || 0;

            if (variationQuantity <= 0) {
                return res.json({
                    success: false,
                    message: 'Variation quantity must be greater than 0.'
                });
            }

            // Handle image upload
            let imageUrl = null;
            if (req.file) {
                imageUrl = publicUrlFromMulterVariationFile(req.file);
            }

            let variationID;

            // Linking to inventory variation is required - use the same VariationID
            if (parsedInventoryVariationId) {
                console.log(`[VARIATION ADD] Linking to Inventory Variation ID: ${parsedInventoryVariationId}`);

                // Check if inventory variation exists
                const inventoryVariationCheck = await pool.request()
                    .input('variationID', sql.Int, parsedInventoryVariationId)
                    .query(`
                        SELECT VariationID, ProductID as InventoryProductID, AvailableQuantity, Quantity
                        FROM InventoryProductVariations
                        WHERE VariationID = @variationID AND IsActive = 1
                    `);

                if (inventoryVariationCheck.recordset.length === 0) {
                    return res.json({
                        success: false,
                        message: 'Inventory variation not found or inactive.'
                    });
                }

                const inventoryVariation = inventoryVariationCheck.recordset[0];
                const inventoryQuantity = inventoryVariation.AvailableQuantity !== null && inventoryVariation.AvailableQuantity !== undefined
                    ? inventoryVariation.AvailableQuantity
                    : (inventoryVariation.Quantity || 0);

                console.log(`[VARIATION ADD] Found Inventory Variation with Quantity: ${inventoryQuantity}`);

                // Check if ProductVariation with this VariationID already exists
                const existingProductVariation = await pool.request()
                    .input('variationID', sql.Int, parsedInventoryVariationId)
                    .query(`
                        SELECT VariationID, ProductID, VariationName
                        FROM ProductVariations
                        WHERE VariationID = @variationID
                    `);

                if (existingProductVariation.recordset.length > 0) {
                    // Prevent duplicate - variation is already linked
                    const existing = existingProductVariation.recordset[0];
                    if (existing.ProductID === parsedProductID) {
                        return res.json({
                            success: false,
                            message: `This variation "${existing.VariationName || 'Variation ID: ' + parsedInventoryVariationId}" is already linked to this product (Product ID: ${parsedProductID}). You cannot create a duplicate variation. Please edit the existing variation instead.`
                        });
                    } else {
                        // Variation is linked to a different product - prevent duplicate linking
                        return res.json({
                            success: false,
                            message: `This variation "${existing.VariationName || 'Variation ID: ' + parsedInventoryVariationId}" is already linked to another product (Product ID: ${existing.ProductID}). You cannot link the same inventory variation to multiple CMS products. Please select a different variation.`
                        });
                    }
                } else {
                    // Insert new ProductVariation using the same VariationID from InventoryProductVariations
                    // Need to enable IDENTITY_INSERT to insert explicit VariationID value
                    // Use a single request to ensure IDENTITY_INSERT is in the same session
                    const insertRequest = pool.request();
                    try {
                        // Enable IDENTITY_INSERT, then insert, then disable - all in one batch
                        await insertRequest
                            .input('variationID', sql.Int, parsedInventoryVariationId)
                            .input('productID', sql.Int, parsedProductID)
                            .input('variationName', sql.NVarChar, variationName)
                            .input('color', sql.NVarChar, color || null)
                            .input('quantity', sql.Int, inventoryQuantity) // Use inventory quantity
                            .input('price', sql.Decimal(10, 2), price ? parseFloat(price) : null)
                            .input('imageUrl', sql.NVarChar, imageUrl)
                            .input('isActive', sql.Bit, isActive === '1' ? 1 : 0)
                            .query(`
                                SET IDENTITY_INSERT ProductVariations ON;
                                INSERT INTO ProductVariations (VariationID, ProductID, VariationName, Color, Quantity, Price, VariationImageURL, IsActive)
                                VALUES (@variationID, @productID, @variationName, @color, @quantity, @price, @imageUrl, @isActive);
                                SET IDENTITY_INSERT ProductVariations OFF;
                            `);

                        variationID = parsedInventoryVariationId;

                        console.log(`[VARIATION ADD] ✅ Created new ProductVariation with VariationID ${variationID} linked to InventoryProductVariation`);
                    } catch (insertErr) {
                        // Make sure to disable IDENTITY_INSERT even if insert fails
                        try {
                            await pool.request().query(`SET IDENTITY_INSERT ProductVariations OFF`);
                        } catch (disableErr) {
                            console.error('[VARIATION ADD] Error disabling IDENTITY_INSERT:', disableErr);
                        }
                        throw insertErr; // Re-throw the original error
                    }
                }

                // Sync variation stock to ensure ProductVariations.Quantity matches InventoryProductVariations
                await syncInventoryVariationToProductsVariation(variationID, null);
                console.log(`[VARIATION ADD] ✅ Synced variation stock for VariationID ${variationID}`);

                if (variationID && imageUrl) {
                    await pool.request()
                        .input('variationID', sql.Int, variationID)
                        .input('imageUrl', sql.NVarChar, imageUrl)
                        .query(`
                            UPDATE InventoryProductVariations
                            SET VariationImageURL = @imageUrl
                            WHERE VariationID = @variationID
                        `);
                    console.log(`[VARIATION ADD] Synced VariationImageURL to InventoryProductVariations for VariationID ${variationID}`);
                }
            } else {
                // This should never happen due to validation above, but keeping as fallback
                return res.json({
                    success: false,
                    message: 'Inventory variation linking is required. Please select a variation from inventory.'
                });
            }

            // Log the activity
            await logActivity(
                req.session.user.id,
                'INSERT',
                'ProductVariations',
                variationID.toString(),
                `Admin added product variation: "${variationName}" (Color: ${color || 'N/A'}, Quantity: ${variationQuantity}, Price: ${price || 'N/A'}) for Product ID: ${productID}${parsedInventoryVariationId ? ` - Linked to Inventory Variation ID: ${parsedInventoryVariationId}` : ' - Standalone variation'}.`
            );

            res.json({
                success: true,
                message: parsedInventoryVariationId
                    ? `Variation linked to inventory successfully. Stock synced automatically.`
                    : `Variation added successfully.`
            });
        } catch (err) {
            console.error('Error adding variation:', err);
            res.json({
                success: false,
                message: 'Failed to add variation: ' + err.message
            });
        }
    });
    // Edit variation
    router.post('/Employee/Admin/Variations/Edit', isAuthenticated, variationUpload.single('variationImage'), async (req, res) => {
        try {
            await pool.connect();
            const { variationID, variationName, color, quantity, price, isActive } = req.body;

            // Get current variation data including ProductID and old Quantity before updating
            const oldVariationResult = await pool.request()
                .input('variationID', sql.Int, parseInt(variationID))
                .query('SELECT ProductID, Quantity FROM ProductVariations WHERE VariationID = @variationID');

            if (oldVariationResult.recordset.length === 0) {
                return res.json({
                    success: false,
                    message: 'Variation not found.'
                });
            }

            const oldVariation = oldVariationResult.recordset[0];
            const productID = oldVariation.ProductID;
            const newQuantity = parseInt(quantity);

            // Validate quantity
            if (newQuantity <= 0) {
                return res.json({
                    success: false,
                    message: 'Variation quantity must be greater than 0.'
                });
            }

            // Get product stock
            const productResult = await pool.request()
                .input('productID', sql.Int, productID)
                .query('SELECT StockQuantity FROM Products WHERE ProductID = @productID');

            if (productResult.recordset.length === 0) {
                return res.json({
                    success: false,
                    message: 'Product not found.'
                });
            }

            const productStock = productResult.recordset[0].StockQuantity || 0;

            // Validation removed: variation quantity can exceed product stock
            // (User requested removal of this validation)

            // Handle image upload - get current image URL before updating (if new image provided)
            let imageUrl = null;
            if (req.file) {
                // Get current variation image URL before updating
                const currentVariation = await pool.request()
                    .input('variationID', sql.Int, parseInt(variationID))
                    .query('SELECT VariationImageURL FROM ProductVariations WHERE VariationID = @variationID');

                const currentImageUrl = currentVariation.recordset[0]?.VariationImageURL;

                // Delete old variation image
                await deleteOldImageFile(currentImageUrl);

                imageUrl = publicUrlFromMulterVariationFile(req.file);
            }

            // Build update query for variation
            let updateQuery = `
                    UPDATE ProductVariations 
                    SET VariationName = @variationName,
                        Color = @color,
                        Quantity = @quantity,
                        Price = @price,
                        IsActive = @isActive
                `;

            const updateRequest = pool.request()
                .input('variationID', sql.Int, parseInt(variationID))
                .input('variationName', sql.NVarChar, variationName)
                .input('color', sql.NVarChar, color || null)
                .input('quantity', sql.Int, newQuantity)
                .input('price', sql.Decimal(10, 2), price ? parseFloat(price) : null)
                .input('isActive', sql.Bit, isActive === '1' ? 1 : 0);

            if (req.file && imageUrl) {
                updateQuery += `, VariationImageURL = @imageUrl`;
                updateRequest.input('imageUrl', sql.NVarChar, imageUrl);
            }

            updateQuery += ` WHERE VariationID = @variationID`;

            // Update variation without affecting product stock
            await updateRequest.query(updateQuery);

            // Keep inventory row image in sync when CMS uploads a new file (same VariationID)
            if (req.file && imageUrl) {
                await pool.request()
                    .input('variationID', sql.Int, parseInt(variationID))
                    .input('imageUrl', sql.NVarChar, imageUrl)
                    .query(`
                        UPDATE InventoryProductVariations
                        SET VariationImageURL = @imageUrl
                        WHERE VariationID = @variationID
                    `);
                console.log(`[VARIATION EDIT] Synced VariationImageURL to InventoryProductVariations for VariationID ${variationID}`);
            }

            // Get old quantity for logging
            const oldQuantity = parseInt(oldVariationResult.recordset[0].Quantity);

            // Log the activity
            await logActivity(
                req.session.user.id,
                'UPDATE',
                'ProductVariations',
                variationID.toString(),
                `Admin updated product variation ID ${variationID}: "${variationName}" (Color: ${color || 'N/A'}, Quantity: ${oldQuantity} → ${newQuantity}). Product stock remains unchanged.`
            );

            res.json({
                success: true,
                message: 'Variation updated successfully.'
            });
        } catch (err) {
            console.error('Error updating variation:', err);
            res.json({
                success: false,
                message: 'Failed to update variation.'
            });
        }
    });

