    // Get variations for a specific product (Transaction Manager)
    router.get('/Employee/TransactionManager/TransactionVariations/Get/:productId', isAuthenticated, async (req, res) => {
        try {
            await pool.connect();
            const productId = parseInt(req.params.productId);

            const result = await pool.request()
                .input('productId', sql.Int, productId)
                .query(`
                    SELECT 
                        v.VariationID,
                        v.ProductID,
                        v.VariationName,
                        v.Color,
                        v.Quantity,
                        v.VariationImageURL,
                        v.IsActive,
                        v.CreatedAt,
                        p.Name as ProductName,
                        p.StockQuantity as ProductStock
                    FROM ProductVariations v
                    JOIN Products p ON v.ProductID = p.ProductID
                    WHERE v.ProductID = @productId
                    ORDER BY v.CreatedAt DESC
                `);

            // Get total variation quantity used
            const totalVariationQuantity = result.recordset
                .filter(v => v.IsActive === 1)
                .reduce((sum, v) => sum + (v.Quantity || 0), 0);

            const productStock = result.recordset.length > 0 ? result.recordset[0].ProductStock : 0;

            res.json({
                success: true,
                variations: result.recordset,
                productStock: productStock,
                totalVariationQuantity: totalVariationQuantity,
                availableStock: productStock - totalVariationQuantity
            });
        } catch (err) {
            console.error('Error fetching variations:', err);
            res.status(500).json({
                success: false,
                message: 'Failed to fetch variations',
                error: err.message
            });
        }
    });
